// Keep router top-k in the one-SIMD greedy path; this avoids the old
// full-row bitonic-sort barriers for the fixed 64-expert/top-6 decode shape.
#define UOCR_METAL_MOE_ROUTER_TOPK_THREADS 16u
#define UOCR_METAL_MOE_ROUTER_FUSED_THREADS 1024u
#define UOCR_METAL_MOE_SHARED_GATE_UP_TILE_COLUMNS 4u
#define UOCR_METAL_MOE_SHARED_GATE_UP_TILED_THREADS 1024u
#define UOCR_METAL_MOE_ROUTED_GATE_UP_TILE_COLUMNS 4u
#define UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS 256u
#define UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_TILE_COLUMNS 8u

/* Select the down-combine kernel name based on tile columns.
 * Tile8: 160 threadgroups (1280/8), better mid reuse but higher register pressure.
 * Tile4: 320 threadgroups (1280/4), lower register pressure.
 */
#if UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_TILE_COLUMNS == 8u
#define UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_KERNEL \
    "uocr_moe_decode_interleaved_down_sum_combine_tile8_f16_to_f16"
#else
#define UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_KERNEL \
    "uocr_moe_decode_interleaved_down_sum_combine_tile4_f16_to_f16"
#endif

#ifndef UOCR_METAL_DECODE_MOE_TOP_K
#define UOCR_METAL_DECODE_MOE_TOP_K UOCR_MOE_TOP_K
#endif

#if UOCR_METAL_DECODE_MOE_TOP_K < 1u || UOCR_METAL_DECODE_MOE_TOP_K > UOCR_MOE_TOP_K
#error "UOCR_METAL_DECODE_MOE_TOP_K must be in [1, UOCR_MOE_TOP_K]"
#endif
#define UOCR_METAL_FLASH_Q_PER_TG 4u
#define UOCR_METAL_FLASH_MAX_LANE_VALUES 4u
#define UOCR_METAL_HALF4_WIDTH 4u
#define UOCR_METAL_FC_HIDDEN_SIZE 0u
#define UOCR_METAL_FC_ATTENTION_HEADS 1u
#define UOCR_METAL_FC_HEAD_DIM 2u
#define UOCR_METAL_FC_RING_WINDOW 3u
#define UOCR_METAL_FC_MOE_EXPERTS 4u
#define UOCR_METAL_FC_MOE_TOP_K 5u
#define UOCR_METAL_FC_RMS_EPS 6u
#define UOCR_METAL_FC_ROPE_FREQ_SCALE 7u
#define UOCR_METAL_FC_ATTENTION_SCALE 8u
#define UOCR_METAL_FC_ATTENTION_PROJECTION_COUNT 9u
#define UOCR_METAL_FC_VOCAB_SIZE 10u
#define UOCR_METAL_FC_LM_HEAD_TILE_TOKENS 11u
#define UOCR_METAL_FC_LM_HEAD_LANES_PER_TOKEN 12u
#define UOCR_METAL_FC_MOE_EXPERT_INTERMEDIATE 13u
#define UOCR_METAL_FC_MOE_SHARED_INTERMEDIATE 14u
@interface NSObject (UOCRMetalMPSDynamic)
+ (id)descriptorWithDataType:(uint32_t)dataType shape:(NSArray<NSNumber *> *)shape;
- (void)setPreferPackedRows:(BOOL)preferPackedRows;
- (void)transposeDimension:(NSUInteger)dimension withDimension:(NSUInteger)otherDimension;
- (id)initWithBuffer:(id<MTLBuffer>)buffer offset:(NSUInteger)offset descriptor:(id)descriptor;
