static int metal_context_layernorm_f16_slices_with_parameter_buffers(
    uocr_metal_context *ctx,
    uocr_metal_buffer_slice input_slice,
    id<MTLBuffer> weight_buffer,
    NSUInteger weight_offset,
    id<MTLBuffer> bias_buffer,
    NSUInteger bias_offset,
    uint32_t n_rows,
    uint32_t hidden_size,
    float eps,
    uocr_metal_layernorm_output_type output_type,
    uocr_metal_buffer_slice output_slice,
    const char *op_name,
    char *error,
    size_t error_size);
static int metal_sam_transformer_activation_bytes(uint32_t grid_w,
                                                  uint32_t grid_h,
                                                  uint64_t *row_count,
                                                  uint64_t *hidden_bytes,
                                                  char *error,
                                                  size_t error_size);

static int metal_vision_require_workspace_slice_f16(uocr_metal_vision_workspace_slice slice,
                                                    uint64_t byte_length,
                                                    const char *label,
                                                    char *error,
                                                    size_t error_size) {
    if (slice.buffer == nil || slice.f16 == NULL || byte_length == 0u || byte_length > slice.bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){slice.buffer, slice.offset}, byte_length)) {
        return metal_fail(error, error_size, "invalid Metal vision %s slice", label != NULL ? label : "workspace");
    }
    return 1;
}

static int metal_vision_require_workspace_slice(uocr_metal_vision_workspace_slice slice,
                                                uint64_t byte_length,
                                                const char *label,
                                                char *error,
                                                size_t error_size) {
    if (slice.buffer == nil || byte_length == 0u || byte_length > slice.bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){slice.buffer, slice.offset}, byte_length)) {
        return metal_fail(error, error_size, "invalid Metal vision %s slice", label != NULL ? label : "workspace");
    }
    return 1;
}

static int metal_vision_require_tensor_slice_f16(uocr_metal_vision_tensor_f16 tensor,
                                                 uint64_t byte_length,
                                                 const char *label,
                                                 char *error,
                                                 size_t error_size) {
    if (tensor.qtype != UOCR_TENSOR_F16 || tensor.slice.buffer == nil || tensor.host_f16 == NULL ||
        byte_length == 0u || byte_length > tensor.byte_length || !metal_slice_valid(tensor.slice, byte_length)) {
        return metal_fail(error, error_size, "invalid Metal vision %s tensor slice", label != NULL ? label : "weight");
    }
    return 1;
}

static int metal_vision_require_weight_q8(uocr_metal_vision_tensor_f16 tensor,
                                          uint32_t rows,
                                          uint32_t cols,
                                          const char *label,
                                          char *error,
                                          size_t error_size) {
    const uint64_t qweight_bytes = (uint64_t)rows * (uint64_t)cols;
    const uint64_t qscale_bytes = uocr_q8_0_qscale_bytes(rows, cols, UOCR_Q8_GROUP_SIZE_DEFAULT);
    if (tensor.qtype != UOCR_TENSOR_Q8_0 || rows == 0u || cols == 0u || qscale_bytes == 0u ||
        tensor.rows != rows || tensor.cols != cols ||
        tensor.group_size != UOCR_Q8_GROUP_SIZE_DEFAULT ||
        tensor.groups_per_row != cols / UOCR_Q8_GROUP_SIZE_DEFAULT ||
        tensor.slice.buffer == nil || tensor.byte_length != qweight_bytes ||
        !metal_slice_valid(tensor.slice, qweight_bytes) ||
        tensor.scale_slice.buffer == nil || tensor.scale_byte_length != qscale_bytes ||
        !metal_slice_valid(tensor.scale_slice, qscale_bytes)) {
        return metal_fail(error, error_size, "invalid Metal vision %s q8_0 tensor slice", label != NULL ? label : "weight");
    }
    return 1;
}

static int metal_vision_f16_bytes(uint64_t value_count, uint64_t *out_bytes) {
    return checked_mul_u64(value_count, 2u, out_bytes) && *out_bytes <= (uint64_t)SIZE_MAX;
}

static int metal_vision_square_grid_values(uint32_t grid_w,
                                           uint32_t grid_h,
                                           uint32_t channels,
                                           uint64_t *out_values) {
    uint64_t spatial = 0u;
    return checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &spatial) &&
           checked_mul_u64(spatial, (uint64_t)channels, out_values);
}

static uint32_t metal_sam_abs_pos_source_grid_for_tensor(uocr_metal_vision_tensor_f16 pos_embed) {
    uint64_t local_values = 0u;
    uint64_t local_bytes = 0u;
    uint64_t global_values = 0u;
    uint64_t global_bytes = 0u;
    if (metal_vision_square_grid_values(UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                        UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                        UOCR_SAM_HIDDEN_SIZE,
                                        &local_values) &&
        metal_vision_f16_bytes(local_values, &local_bytes) && pos_embed.byte_length == local_bytes) {
        return UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    }
    if (metal_vision_square_grid_values(UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                        UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                        UOCR_SAM_HIDDEN_SIZE,
                                        &global_values) &&
        metal_vision_f16_bytes(global_values, &global_bytes) && pos_embed.byte_length == global_bytes) {
        return UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    }
    return 0u;
}

static uocr_metal_vision_tensor_f16 metal_sam_abs_pos_table_for_grid(const uocr_metal_vision_weights_f16 *weights,
                                                                     uint32_t grid_w,
                                                                     uint32_t grid_h) {
    if (weights == NULL || grid_w != grid_h) {
        uocr_metal_vision_tensor_f16 empty;
        memset(&empty, 0, sizeof(empty));
        return empty;
    }
    const uint32_t local_grid = UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    const uint32_t global_grid = UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    if (grid_w == local_grid && weights->sam_pos_embed_local.slice.buffer != nil) {
        return weights->sam_pos_embed_local;
    }
    if (grid_w == global_grid && weights->sam_pos_embed_global.slice.buffer != nil) {
        return weights->sam_pos_embed_global;
    }
    return weights->sam_pos_embed;
}

static int metal_precompute_sam_abs_pos_tables(uocr_metal_context *ctx,
                                               uocr_metal_vision_weights_f16 *weights,
                                               char *error,
                                               size_t error_size) {
    if (ctx == NULL || weights == NULL || weights->sam_pos_embed.slice.buffer == nil || weights->sam_pos_embed.host_f16 == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM absolute-position precompute request");
    }
    metal_release_precomputed_vision_tables(ctx);
    weights->sam_pos_embed_global = weights->sam_pos_embed;

    const uint32_t source_grid = UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    const uint32_t target_grid = UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    uint64_t source_values = 0u;
    uint64_t source_bytes = 0u;
    uint64_t target_values = 0u;
    uint64_t target_bytes = 0u;
    if (!metal_vision_square_grid_values(source_grid, source_grid, UOCR_SAM_HIDDEN_SIZE, &source_values) ||
        !metal_vision_f16_bytes(source_values, &source_bytes) ||
        !metal_vision_square_grid_values(target_grid, target_grid, UOCR_SAM_HIDDEN_SIZE, &target_values) ||
        !metal_vision_f16_bytes(target_values, &target_bytes) || target_values > (uint64_t)UINT32_MAX ||
        !metal_vision_require_tensor_slice_f16(weights->sam_pos_embed,
                                               source_bytes,
                                               "SAM absolute-position source table",
                                               error,
                                               error_size)) {
        return 0;
    }
    if (target_bytes > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal SAM absolute-position precompute byte-size overflow");
    }

    @autoreleasepool {
        id<MTLBuffer> local_buffer = metal_new_buffer_with_length(ctx, (NSUInteger)target_bytes, MTLResourceStorageModeShared);
        if (local_buffer == nil || [local_buffer contents] == NULL) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM local absolute-position table");
        }
        local_buffer.label = @"uocr_sam_abs_pos_local_40x40";
        memset([local_buffer contents], 0, (size_t)target_bytes);

        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_add_abs_pos_f16", error, error_size);
        if (pipeline == nil) {
            [local_buffer release];
            return 0;
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal SAM absolute-position precompute command buffer");
        }
        cb.label = @"uocr_sam_abs_pos_precompute_command_buffer";
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal SAM absolute-position precompute encoder");
        }

        uocr_metal_sam_abs_pos_params params;
        params.source_grid = source_grid;
        params.target_width = target_grid;
        params.target_height = target_grid;
        params.channels = UOCR_SAM_HIDDEN_SIZE;
        params.batch_size = 1u;

        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:local_buffer offset:0u atIndex:0u];
        [enc setBuffer:weights->sam_pos_embed.slice.buffer offset:weights->sam_pos_embed.slice.offset atIndex:1u];
        [enc setBuffer:local_buffer offset:0u atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)target_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        if (!metal_wait_for_command_buffer_profiled(ctx, cb, "Metal SAM absolute-position precompute", error, error_size)) {
            [local_buffer release];
            return 0;
        }

        ctx->sam_abs_pos_local_buffer = local_buffer;
        weights->sam_pos_embed_local.slice.buffer = local_buffer;
        weights->sam_pos_embed_local.slice.offset = 0u;
        weights->sam_pos_embed_local.byte_length = target_bytes;
        weights->sam_pos_embed_local.host_f16 = (const uint16_t *)[local_buffer contents];
        weights->sam_pos_embed_local.qtype = UOCR_TENSOR_F16;
        metal_profile_add_event_ms(ctx, "metal.vision.sam_abs_pos_precompute.local", 0.0);
    }
    return 1;
}

typedef struct uocr_metal_sam_rel_pos_table_pair_f16 {
    uocr_metal_vision_tensor_f16 h;
    uocr_metal_vision_tensor_f16 w;
    uint32_t h_length;
    uint32_t w_length;
} uocr_metal_sam_rel_pos_table_pair_f16;

static int metal_sam_rel_pos_target_length_for_grid(uint32_t grid, uint32_t *out_length) {
    if (grid == 0u || out_length == NULL || grid > (UINT32_MAX - 1u) / 2u) {
        return 0;
    }
    *out_length = 2u * grid - 1u;
    return 1;
}

static int metal_sam_rel_pos_table_values(uint32_t rel_pos_length, uint64_t *out_values) {
    if (out_values == NULL || rel_pos_length == 0u) {
        return 0;
    }
    return checked_mul_u64((uint64_t)rel_pos_length, (uint64_t)UOCR_SAM_HEAD_DIM, out_values);
}

static uocr_metal_sam_rel_pos_table_pair_f16 metal_sam_rel_pos_table_for_grid(
    const uocr_metal_sam_transformer_block_slices_f16 *block,
    uint32_t grid_w,
    uint32_t grid_h) {
    uocr_metal_sam_rel_pos_table_pair_f16 table;
    memset(&table, 0, sizeof(table));
    if (block == NULL || grid_w != grid_h) {
        return table;
    }
    uint32_t target_length = 0u;
    if (!metal_sam_rel_pos_target_length_for_grid(grid_w, &target_length)) {
        return table;
    }
    if (target_length == block->rel_pos_h_local_length && target_length == block->rel_pos_w_local_length &&
        block->rel_pos_h_local.slice.buffer != nil && block->rel_pos_w_local.slice.buffer != nil) {
        table.h = block->rel_pos_h_local;
        table.w = block->rel_pos_w_local;
        table.h_length = block->rel_pos_h_local_length;
        table.w_length = block->rel_pos_w_local_length;
        return table;
    }
    table.h = block->rel_pos_h;
    table.w = block->rel_pos_w;
    table.h_length = block->rel_pos_h_length;
    table.w_length = block->rel_pos_w_length;
    return table;
}

static int metal_precompute_sam_rel_pos_tables(uocr_metal_context *ctx,
                                               uocr_metal_vision_weights_f16 *weights,
                                               char *error,
                                               size_t error_size) {
    if (ctx == NULL || weights == NULL || !weights->valid) {
        return metal_fail(error, error_size, "invalid Metal SAM relative-position precompute request");
    }
    @autoreleasepool {
        [ctx->sam_rel_pos_local_buffer release];
        ctx->sam_rel_pos_local_buffer = nil;
    }
    for (uint32_t layer = 0u; layer < UOCR_SAM_BLOCKS; ++layer) {
        memset(&weights->sam_block_slices[layer].rel_pos_h_local, 0, sizeof(weights->sam_block_slices[layer].rel_pos_h_local));
        memset(&weights->sam_block_slices[layer].rel_pos_w_local, 0, sizeof(weights->sam_block_slices[layer].rel_pos_w_local));
        weights->sam_block_slices[layer].rel_pos_h_local_length = 0u;
        weights->sam_block_slices[layer].rel_pos_w_local_length = 0u;
    }

    const uint32_t local_grid = UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
    uint32_t target_length = 0u;
    if (!metal_sam_rel_pos_target_length_for_grid(local_grid, &target_length)) {
        return metal_fail(error, error_size, "invalid Metal SAM local relative-position target grid");
    }
    if (target_length == UOCR_SAM_MAX_REL_POS_SIZE) {
        return 1;
    }

    uint32_t global_attention_blocks = 0u;
    for (uint32_t layer = 0u; layer < UOCR_SAM_BLOCKS; ++layer) {
        if (uocr_sam_block_uses_global_attention(layer)) {
            ++global_attention_blocks;
        }
    }
    if (global_attention_blocks == 0u) {
        return 1;
    }

    uint64_t source_values = 0u;
    uint64_t source_bytes = 0u;
    uint64_t table_values = 0u;
    uint64_t table_bytes = 0u;
    uint64_t total_bytes_u64 = 0u;
    if (!metal_sam_rel_pos_table_values(UOCR_SAM_MAX_REL_POS_SIZE, &source_values) ||
        !metal_vision_f16_bytes(source_values, &source_bytes) ||
        !metal_sam_rel_pos_table_values(target_length, &table_values) ||
        !metal_vision_f16_bytes(table_values, &table_bytes) || table_values > (uint64_t)UINT32_MAX ||
        !checked_mul_u64(table_bytes, 2u * (uint64_t)global_attention_blocks, &total_bytes_u64)) {
        return metal_fail(error, error_size, "Metal SAM relative-position precompute byte-size overflow");
    }
    if (total_bytes_u64 > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal SAM relative-position precompute buffer-size overflow");
    }

    NSUInteger rel_h_offsets[UOCR_SAM_BLOCKS];
    NSUInteger rel_w_offsets[UOCR_SAM_BLOCKS];
    memset(rel_h_offsets, 0, sizeof(rel_h_offsets));
    memset(rel_w_offsets, 0, sizeof(rel_w_offsets));

    @autoreleasepool {
        id<MTLBuffer> local_buffer = metal_new_buffer_with_length(ctx, (NSUInteger)total_bytes_u64, MTLResourceStorageModeShared);
        if (local_buffer == nil || [local_buffer contents] == NULL) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM local relative-position tables");
        }
        local_buffer.label = @"uocr_sam_rel_pos_local_40x40";
        memset([local_buffer contents], 0, (size_t)total_bytes_u64);

        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_interpolate_rel_pos_f16", error, error_size);
        if (pipeline == nil) {
            [local_buffer release];
            return 0;
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal SAM relative-position precompute command buffer");
        }
        cb.label = @"uocr_sam_rel_pos_precompute_command_buffer";
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal SAM relative-position precompute encoder");
        }

        uocr_metal_sam_rel_pos_interpolate_params params;
        params.source_length = UOCR_SAM_MAX_REL_POS_SIZE;
        params.target_length = target_length;
        params.head_dim = UOCR_SAM_HEAD_DIM;
        params.reserved = 0u;
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        NSUInteger dst_offset = 0u;
        for (uint32_t layer = 0u; layer < UOCR_SAM_BLOCKS; ++layer) {
            if (!uocr_sam_block_uses_global_attention(layer)) {
                continue;
            }
            uocr_metal_sam_transformer_block_slices_f16 *block = &weights->sam_block_slices[layer];
            if (block->rel_pos_h_length != UOCR_SAM_MAX_REL_POS_SIZE ||
                block->rel_pos_w_length != UOCR_SAM_MAX_REL_POS_SIZE ||
                !metal_vision_require_tensor_slice_f16(block->rel_pos_h,
                                                       source_bytes,
                                                       "SAM global relative-position H source table",
                                                       error,
                                                       error_size) ||
                !metal_vision_require_tensor_slice_f16(block->rel_pos_w,
                                                       source_bytes,
                                                       "SAM global relative-position W source table",
                                                       error,
                                                       error_size)) {
                [enc endEncoding];
                [local_buffer release];
                return 0;
            }

            rel_h_offsets[layer] = dst_offset;
            [enc setComputePipelineState:pipeline];
            [enc setBuffer:block->rel_pos_h.slice.buffer offset:block->rel_pos_h.slice.offset atIndex:0u];
            [enc setBuffer:local_buffer offset:dst_offset atIndex:1u];
            [enc setBytes:&params length:sizeof(params) atIndex:2u];
            [enc dispatchThreads:MTLSizeMake((NSUInteger)table_values, 1u, 1u)
           threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
            dst_offset += (NSUInteger)table_bytes;

            rel_w_offsets[layer] = dst_offset;
            [enc setComputePipelineState:pipeline];
            [enc setBuffer:block->rel_pos_w.slice.buffer offset:block->rel_pos_w.slice.offset atIndex:0u];
            [enc setBuffer:local_buffer offset:dst_offset atIndex:1u];
            [enc setBytes:&params length:sizeof(params) atIndex:2u];
            [enc dispatchThreads:MTLSizeMake((NSUInteger)table_values, 1u, 1u)
           threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
            dst_offset += (NSUInteger)table_bytes;
        }
        [enc endEncoding];
        if (!metal_wait_for_command_buffer_profiled(ctx, cb, "Metal SAM relative-position precompute", error, error_size)) {
            [local_buffer release];
            return 0;
        }

        ctx->sam_rel_pos_local_buffer = local_buffer;
        const uint8_t *contents = (const uint8_t *)[local_buffer contents];
        for (uint32_t layer = 0u; layer < UOCR_SAM_BLOCKS; ++layer) {
            if (!uocr_sam_block_uses_global_attention(layer)) {
                continue;
            }
            uocr_metal_sam_transformer_block_slices_f16 *block = &weights->sam_block_slices[layer];
            block->rel_pos_h_local.slice.buffer = local_buffer;
            block->rel_pos_h_local.slice.offset = rel_h_offsets[layer];
            block->rel_pos_h_local.byte_length = table_bytes;
            block->rel_pos_h_local.host_f16 = (const uint16_t *)(const void *)(contents + rel_h_offsets[layer]);
            block->rel_pos_h_local.qtype = UOCR_TENSOR_F16;
            block->rel_pos_h_local_length = target_length;
            block->rel_pos_w_local.slice.buffer = local_buffer;
            block->rel_pos_w_local.slice.offset = rel_w_offsets[layer];
            block->rel_pos_w_local.byte_length = table_bytes;
            block->rel_pos_w_local.host_f16 = (const uint16_t *)(const void *)(contents + rel_w_offsets[layer]);
            block->rel_pos_w_local.qtype = UOCR_TENSOR_F16;
            block->rel_pos_w_local_length = target_length;
        }
        metal_profile_add_event_ms(ctx, "metal.vision.sam_rel_pos_precompute.local", 0.0);
    }
    return 1;
}

static int metal_clip_abs_pos_table_values(uint32_t grid, uint64_t *out_values) {
    if (out_values == NULL) {
        return 0;
    }
    uint64_t spatial = 0u;
    uint64_t tokens = 0u;
    return checked_mul_u64((uint64_t)grid, (uint64_t)grid, &spatial) &&
           checked_add_u64(spatial, (uint64_t)UOCR_CLIP_CLASS_TOKENS, &tokens) &&
           checked_mul_u64(tokens, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, out_values);
}

static uint32_t metal_clip_abs_pos_source_grid_for_tensor(uocr_metal_vision_tensor_f16 pos_embed) {
    uint64_t local_values = 0u;
    uint64_t local_bytes = 0u;
    uint64_t global_values = 0u;
    uint64_t global_bytes = 0u;
    if (metal_clip_abs_pos_table_values(UOCR_LOCAL_GRID_QUERIES, &local_values) &&
        metal_vision_f16_bytes(local_values, &local_bytes) && pos_embed.byte_length == local_bytes) {
        return UOCR_LOCAL_GRID_QUERIES;
    }
    if (metal_clip_abs_pos_table_values(UOCR_CLIP_POSITION_GRID, &global_values) &&
        metal_vision_f16_bytes(global_values, &global_bytes) && pos_embed.byte_length == global_bytes) {
        return UOCR_CLIP_POSITION_GRID;
    }
    return 0u;
}

static uocr_metal_vision_tensor_f16 metal_clip_abs_pos_table_for_grid(const uocr_metal_vision_weights_f16 *weights,
                                                                      uint32_t grid_w,
                                                                      uint32_t grid_h) {
    if (weights == NULL || grid_w != grid_h) {
        uocr_metal_vision_tensor_f16 empty;
        memset(&empty, 0, sizeof(empty));
        return empty;
    }
    if (grid_w == UOCR_LOCAL_GRID_QUERIES && weights->clip_pos_embed_local.slice.buffer != nil) {
        return weights->clip_pos_embed_local;
    }
    if (grid_w == UOCR_CLIP_POSITION_GRID && weights->clip_pos_embed_global.slice.buffer != nil) {
        return weights->clip_pos_embed_global;
    }
    return weights->clip_pos_embed;
}

static int metal_precompute_clip_abs_pos_tables(uocr_metal_context *ctx,
                                                uocr_metal_vision_weights_f16 *weights,
                                                char *error,
                                                size_t error_size) {
    if (ctx == NULL || weights == NULL || weights->clip_pos_embed.slice.buffer == nil || weights->clip_pos_embed.host_f16 == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP absolute-position precompute request");
    }
    @autoreleasepool {
        [ctx->clip_abs_pos_local_buffer release];
        ctx->clip_abs_pos_local_buffer = nil;
    }
    weights->clip_pos_embed_global = weights->clip_pos_embed;

    const uint32_t source_grid = UOCR_CLIP_POSITION_GRID;
    const uint32_t target_grid = UOCR_LOCAL_GRID_QUERIES;
    uint64_t source_values = 0u;
    uint64_t source_bytes = 0u;
    uint64_t target_values = 0u;
    uint64_t target_bytes = 0u;
    if (!metal_clip_abs_pos_table_values(source_grid, &source_values) ||
        !metal_vision_f16_bytes(source_values, &source_bytes) ||
        !metal_clip_abs_pos_table_values(target_grid, &target_values) ||
        !metal_vision_f16_bytes(target_values, &target_bytes) || target_values > (uint64_t)UINT32_MAX ||
        !metal_vision_require_tensor_slice_f16(weights->clip_pos_embed,
                                               source_bytes,
                                               "CLIP absolute-position source table",
                                               error,
                                               error_size)) {
        return 0;
    }
    if (target_bytes > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal CLIP absolute-position precompute byte-size overflow");
    }

    @autoreleasepool {
        id<MTLBuffer> local_buffer = metal_new_buffer_with_length(ctx, (NSUInteger)target_bytes, MTLResourceStorageModeShared);
        if (local_buffer == nil || [local_buffer contents] == NULL) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to allocate Metal CLIP local absolute-position table");
        }
        local_buffer.label = @"uocr_clip_abs_pos_local_10x10";
        memset([local_buffer contents], 0, (size_t)target_bytes);

        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_clip_add_abs_pos_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            [local_buffer release];
            return 0;
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal CLIP absolute-position precompute command buffer");
        }
        cb.label = @"uocr_clip_abs_pos_precompute_command_buffer";
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [local_buffer release];
            return metal_fail(error, error_size, "failed to create Metal CLIP absolute-position precompute encoder");
        }

        uocr_metal_clip_abs_pos_params params;
        params.source_grid = source_grid;
        params.target_width = target_grid;
        params.target_height = target_grid;
        params.hidden_size = UOCR_CLIP_HIDDEN_SIZE;
        params.batch_size = 1u;

        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:local_buffer offset:0u atIndex:0u];
        [enc setBuffer:weights->clip_pos_embed.slice.buffer offset:weights->clip_pos_embed.slice.offset atIndex:1u];
        [enc setBuffer:local_buffer offset:0u atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)target_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        if (!metal_wait_for_command_buffer_profiled(ctx, cb, "Metal CLIP absolute-position precompute", error, error_size)) {
            [local_buffer release];
            return 0;
        }

        ctx->clip_abs_pos_local_buffer = local_buffer;
        weights->clip_pos_embed_local.slice.buffer = local_buffer;
        weights->clip_pos_embed_local.slice.offset = 0u;
        weights->clip_pos_embed_local.byte_length = target_bytes;
        weights->clip_pos_embed_local.host_f16 = (const uint16_t *)[local_buffer contents];
        weights->clip_pos_embed_local.qtype = UOCR_TENSOR_F16;
        metal_profile_add_event_ms(ctx, "metal.vision.clip_abs_pos_precompute.local", 0.0);
    }
    return 1;
}
static int metal_context_sam_add_abs_pos_batch_f16_to_slice(uocr_metal_context *ctx,
                                                             uocr_metal_vision_workspace_slice patch_bhwc,
                                                             uocr_metal_vision_tensor_f16 pos_embed,
                                                             uint32_t grid_w,
                                                             uint32_t grid_h,
                                                             uint32_t view_count,
                                                             uocr_metal_vision_workspace_slice out_bhwc,
                                                             char *error,
                                                             size_t error_size) {
    uint64_t values_per_view = 0u;
    uint64_t values = 0u;
    uint64_t target_bytes = 0u;
    uint64_t pos_values = 0u;
    uint64_t pos_bytes = 0u;
    const uint32_t source_grid = metal_sam_abs_pos_source_grid_for_tensor(pos_embed);
    if (source_grid == 0u) {
        return metal_fail(error, error_size, "Metal SAM abs-pos table has unsupported cached shape");
    }
    if (view_count == 0u ||
        !metal_vision_square_grid_values(grid_w, grid_h, UOCR_SAM_HIDDEN_SIZE, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)view_count, &values) ||
        !metal_vision_f16_bytes(values, &target_bytes) ||
        !metal_vision_square_grid_values(source_grid, source_grid, UOCR_SAM_HIDDEN_SIZE, &pos_values) ||
        !metal_vision_f16_bytes(pos_values, &pos_bytes) ||
        !metal_vision_require_workspace_slice(patch_bhwc, target_bytes, "SAM abs-pos batch input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_bhwc, target_bytes, "SAM abs-pos batch output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(pos_embed, pos_bytes, "SAM abs-pos table", error, error_size)) {
        return 0;
    }
    if (values > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "Metal SAM abs-pos batch value-count overflow");
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_add_abs_pos_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal SAM abs-pos batch", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM abs-pos batch command encoder");
        }

        uocr_metal_sam_abs_pos_params params;
        params.source_grid = source_grid;
        params.target_width = grid_w;
        params.target_height = grid_h;
        params.channels = UOCR_SAM_HIDDEN_SIZE;
        params.batch_size = view_count;

        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) {
            threads = 1u;
        }
        if (threads > 256u) {
            threads = 256u;
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:patch_bhwc.buffer offset:patch_bhwc.offset atIndex:0u];
        [enc setBuffer:pos_embed.slice.buffer offset:pos_embed.slice.offset atIndex:1u];
        [enc setBuffer:out_bhwc.buffer offset:out_bhwc.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal SAM abs-pos batch", error, error_size);
    }
}
/*
 * BHWC → NCHW transpose helper for fp16 vision tensors.
 * input[batch][spatial][channels]  →  output[batch][channels][spatial]
 *
 * Takes raw buffer slices (no f16 pointer required) since this is a pure GPU
 * operation called from the MPS conv1x1 path where the intermediate buffer
 * may be private or temporary.
 */
static int metal_context_bhwc_to_nchw_f16(uocr_metal_context *ctx,
                                           uocr_metal_buffer_slice input_bhwc,
                                           uint32_t batch_size,
                                           uint32_t spatial,
                                           uint32_t channels,
                                           uocr_metal_buffer_slice out_nchw,
                                           char *error,
                                           size_t error_size) {
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    if (!checked_mul_u64((uint64_t)batch_size, (uint64_t)spatial, &input_values) ||
        !checked_mul_u64(input_values, (uint64_t)channels, &input_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !checked_mul_u64((uint64_t)batch_size, (uint64_t)channels, &output_values) ||
        !checked_mul_u64(output_values, (uint64_t)spatial, &output_values) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_slice_valid(input_bhwc, input_bytes) ||
        !metal_slice_valid(out_nchw, output_bytes)) {
        return metal_fail(error, error_size, "invalid Metal BHWC→NCHW transpose request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_bhwc_to_nchw_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal BHWC→NCHW transpose", error, error_size);
        if (cb == nil) {
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_bhwc_to_nchw_transpose_command_buffer";
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal BHWC→NCHW transpose encoder");
        }
        struct { uint32_t batch_size; uint32_t spatial; uint32_t channels; } dims;
        dims.batch_size = batch_size;
        dims.spatial = spatial;
        dims.channels = channels;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input_bhwc.buffer offset:input_bhwc.offset atIndex:0u];
        [enc setBuffer:out_nchw.buffer offset:out_nchw.offset atIndex:1u];
        [enc setBytes:&dims length:sizeof(dims) atIndex:2u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)spatial, (NSUInteger)channels, (NSUInteger)batch_size)
       threadsPerThreadgroup:MTLSizeMake(1u, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal BHWC→NCHW transpose", error, error_size);
    }
}

/*
 * BHWC variant of SAM LayerNorm2d.  Normalizes over channels at each spatial
 * position; channels are contiguous in BHWC for better cache behavior.
 */
static int metal_context_sam_layernorm2d_bhwc_batch_f16_to_slice(uocr_metal_context *ctx,
                                                                 uocr_metal_vision_workspace_slice input_bhwc,
                                                                 uocr_metal_vision_tensor_f16 weight,
                                                                 uocr_metal_vision_tensor_f16 bias,
                                                                 uint32_t grid_w,
                                                                 uint32_t grid_h,
                                                                 uint32_t view_count,
                                                                 uocr_metal_vision_workspace_slice out_bhwc,
                                                                 char *error,
                                                                 size_t error_size) {
    uint64_t values_per_view = 0u;
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    const uint64_t parameter_bytes = (uint64_t)UOCR_SAM_NECK_CHANNELS * 2u;
    if (view_count == 0u || !metal_vision_square_grid_values(grid_w, grid_h, UOCR_SAM_NECK_CHANNELS, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)view_count, &values) ||
        !metal_vision_f16_bytes(values, &bytes) ||
        !metal_vision_require_workspace_slice(input_bhwc, bytes, "SAM LayerNorm2d BHWC input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_bhwc, bytes, "SAM LayerNorm2d BHWC output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(weight, parameter_bytes, "SAM LayerNorm2d weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(bias, parameter_bytes, "SAM LayerNorm2d bias", error, error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_layernorm2d_bhwc_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads_per_group = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        if (threads_per_group < (NSUInteger)UOCR_SAM_NECK_CHANNELS) {
            return metal_fail(error, error_size, "Metal SAM LayerNorm2d BHWC needs at least %u threads", UOCR_SAM_NECK_CHANNELS);
        }
        const uint64_t threadgroup_bytes = 2u * (uint64_t)threads_per_group * (uint64_t)sizeof(float);
        if (threadgroup_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "Metal SAM LayerNorm2d BHWC threadgroup memory exceeds device limit");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal SAM LayerNorm2d BHWC batch", error, error_size);
        if (cb == nil) {
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_sam_layernorm2d_bhwc_batch_command_buffer";
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM LayerNorm2d BHWC command encoder");
        }
        uocr_metal_sam_layernorm2d_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.channels = UOCR_SAM_NECK_CHANNELS;
        params.eps = 1.0e-6f;
        params.batch_size = view_count;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input_bhwc.buffer offset:input_bhwc.offset atIndex:0u];
        [enc setBuffer:weight.slice.buffer offset:weight.slice.offset atIndex:1u];
        [enc setBuffer:bias.slice.buffer offset:bias.slice.offset atIndex:2u];
        [enc setBuffer:out_bhwc.buffer offset:out_bhwc.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:(NSUInteger)threadgroup_bytes atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)(grid_w * grid_h), 1u, (NSUInteger)view_count)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal SAM LayerNorm2d BHWC batch", error, error_size);
    }
}

/*
 * Generic 3x3 convolution via im2col + MPS matmul + BHWC→NCHW transpose.
 *
 * input_nchw  — NCHW fp16 [batch, in_channels, input_h, input_w]
 * weight      — [out_channels, in_channels, 3, 3] in row-major
 *               (weight[oc][ic][ky][kx] → weight_nk[oc][ic * 9 + ky * 3 + kx])
 * out_nchw    — NCHW fp16 [batch, out_channels, output_h, output_w]
 *
 * stride must be 1 or 2.  Padding is always SAME (zero outside).
 */
/*
 * BHWC variant of the im2col conv — reads BHWC input, uses the vectorized
 * BHWC im2col kernel, MPS matmul with repacked weights, outputs BHWC.
 * No BHWC→NCHW transpose needed.
 */
static int metal_context_sam_conv3x3_im2col_mps_bhwc_batch_f16_to_slice(uocr_metal_context *ctx,
                                                                        uocr_metal_vision_workspace_slice input_bhwc,
                                                                        uocr_metal_vision_tensor_f16 weight,
                                                                        uint32_t input_w,
                                                                        uint32_t input_h,
                                                                        uint32_t channels,
                                                                        uint32_t out_channels,
                                                                        uint32_t stride,
                                                                        uint32_t view_count,
                                                                        uocr_metal_vision_workspace_slice out_bhwc,
                                                                        const char *op_name,
                                                                        uocr_metal_vision_workspace *scratch,
                                                                        char *error,
                                                                        size_t error_size) {
    if (ctx == NULL || view_count == 0u || stride == 0u || stride > 2u || input_w == 0u || input_h == 0u ||
        channels == 0u || out_channels == 0u) {
        return metal_fail(error, error_size, "invalid Metal SAM BHWC im2col conv request");
    }
    const uint32_t output_w = (input_w + stride - 1u) / stride;
    const uint32_t output_h = (input_h + stride - 1u) / stride;
    const uint32_t output_spatial = output_w * output_h;
    const uint32_t rows = output_spatial * view_count;
    const uint32_t k_features = channels * 9u;

    uint64_t col_values = 0u;
    uint64_t col_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t weight_values = 0u;
    uint64_t weight_bytes = 0u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)k_features, &col_values) ||
        !metal_vision_f16_bytes(col_values, &col_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)out_channels, &output_values) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !checked_mul_u64((uint64_t)out_channels, (uint64_t)k_features, &weight_values) ||
        !metal_vision_f16_bytes(weight_values, &weight_bytes) ||
        col_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "invalid Metal SAM BHWC im2col conv sizes");
    }
    if (!metal_slice_valid((uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset}, input_bhwc.bytes) ||
        !metal_vision_require_tensor_slice_f16(weight, weight_bytes, "SAM BHWC im2col weight", error, error_size) ||
        !metal_slice_valid((uocr_metal_buffer_slice){out_bhwc.buffer, out_bhwc.offset}, output_bytes)) {
        return metal_fail(error, error_size, "invalid Metal SAM BHWC im2col conv buffer");
    }

    /* Use preallocated workspace slices for im2col buffer. */
    uocr_metal_vision_workspace_slice col_slice = scratch != NULL ? scratch->conv_im2col : (uocr_metal_vision_workspace_slice){0};
    int allocated = 0;
    NSUInteger col_offset = 0u;

    @autoreleasepool {
        id<MTLBuffer> col_buffer = nil;
        if (col_slice.buffer != nil && col_slice.bytes >= col_bytes) {
            col_buffer = col_slice.buffer;
            col_offset = col_slice.offset;
        } else {
            col_buffer = metal_new_buffer_with_length(ctx, (NSUInteger)col_bytes, MTLResourceStorageModePrivate);
            if (col_buffer == nil) return metal_fail(error, error_size, "failed to allocate SAM BHWC im2col buffer");
            col_buffer.label = @"uocr_sam_conv3x3_im2col_bhwc";
            col_offset = 0u;
            allocated = 1;
        }

        /* Step 1: BHWC im2col */
        {
            id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_conv3x3_im2col_bhwc_f16", error, error_size);
            if (pipeline == nil) { if (allocated) [col_buffer release]; return 0; }
            int owned = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned, "Metal SAM BHWC im2col", error, error_size);
            if (cb == nil) { if (allocated) [col_buffer release]; return 0; }
            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) { if (allocated) [col_buffer release]; return metal_fail(error, error_size, "failed to create BHWC im2col encoder"); }
            uocr_metal_conv3x3_bhwc_im2col_params p;
            memset(&p, 0, sizeof(p));
            p.input_width = input_w;
            p.input_height = input_h;
            p.output_width = output_w;
            p.output_height = output_h;
            p.channels = channels;
            p.stride = stride;
            p.batch_size = view_count;
            const NSUInteger c4_count = ((NSUInteger)channels + 3u) / 4u;
            [enc setComputePipelineState:pipeline];
            [enc setBuffer:input_bhwc.buffer offset:input_bhwc.offset atIndex:0u];
            [enc setBuffer:col_buffer offset:col_offset atIndex:1u];
            [enc setBytes:&p length:sizeof(p) atIndex:2u];
            [enc dispatchThreads:MTLSizeMake(9u * c4_count, (NSUInteger)rows, 1u)
           threadsPerThreadgroup:MTLSizeMake(32u, 8u, 1u)];
            [enc endEncoding];
            if (!metal_finish_command_buffer_for_op(ctx, cb, owned, "Metal SAM BHWC im2col", error, error_size)) {
                if (allocated) [col_buffer release]; return 0;
            }
        }

        /* Step 2: MPS matmul  cols @ weight^T  →  out_bhwc (already BHWC) */
        {
            uocr_metal_buffer_slice cs = { col_buffer, col_offset };
            uocr_metal_buffer_slice ws = { weight.slice.buffer, weight.slice.offset };
            uocr_metal_buffer_slice os = { out_bhwc.buffer, out_bhwc.offset };
            if (!metal_run_mps_matmul_nt_f16(ctx, cs, ws, os, rows, k_features, out_channels,
                                             op_name, error, error_size)) {
                if (allocated) [col_buffer release]; return 0;
            }
        }

        if (allocated) [col_buffer release];
        return 1;
    }
}

static int metal_context_sam_neck_batch_f16_to_slice(uocr_metal_vision_project_context *project,
                                                      uocr_metal_vision_workspace_slice input_bhwc,
                                                      uint32_t grid_w,
                                                      uint32_t grid_h,
                                                      uint32_t view_count,
                                                      uocr_metal_vision_workspace_slice out_sam_nchw,
                                                      uint32_t *out_grid_w,
                                                      uint32_t *out_grid_h,
                                                      char *error,
                                                      size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->weights == NULL || project->scratch == NULL ||
        view_count == 0u || out_grid_w == NULL || out_grid_h == NULL) {
        return metal_fail(error, error_size, "invalid Metal batched SAM neck request");
    }
    const uocr_metal_vision_weights_f16 *weights = project->weights;
    uocr_metal_vision_workspace *scratch = project->scratch;
    uocr_metal_context *ctx = project->ctx;
    const uint32_t net2_grid_w = (grid_w + 1u) / 2u;
    const uint32_t net2_grid_h = (grid_h + 1u) / 2u;
    const uint32_t sam_grid_w = (net2_grid_w + 1u) / 2u;
    const uint32_t sam_grid_h = (net2_grid_h + 1u) / 2u;

#if UOCR_ENABLE_PROFILING
#define RUN_BATCHED_SAM_NECK_STEP(step_name, call_expr)                                             \
    do {                                                                                             \
        const uint64_t vision_step_start_ns__ = uocr_profile_now_ns();                                \
        if (!(call_expr)) {                                                                          \
            char detail[512];                                                                        \
            metal_copy_error_detail(detail, sizeof(detail), error);                                   \
            return metal_fail(error, error_size, "failed to compute Metal vision %s: %s", step_name, detail); \
        }                                                                                            \
        metal_profile_add_event_now_f(ctx, vision_step_start_ns__, "metal.vision.%s", step_name);    \
        if (metal_vision_profile_detail_level() >= 3) {                                              \
            char checkpoint_name[128];                                                               \
            (void)snprintf(checkpoint_name, sizeof(checkpoint_name), "sam_neck.%s", step_name);      \
            checkpoint_name[sizeof(checkpoint_name) - 1u] = '\0';                                    \
            if (!metal_vision_profile_checkpoint(ctx, checkpoint_name, 1, error, error_size)) {       \
                return 0;                                                                            \
            }                                                                                        \
        }                                                                                            \
    } while (0)
#else
#define RUN_BATCHED_SAM_NECK_STEP(step_name, call_expr)                                             \
    do {                                                                                             \
        if (!(call_expr)) {                                                                          \
            char detail[512];                                                                        \
            metal_copy_error_detail(detail, sizeof(detail), error);                                   \
            return metal_fail(error, error_size, "failed to compute Metal vision %s: %s", step_name, detail); \
        }                                                                                            \
    } while (0)
#endif

#if UOCR_ENABLE_PROFILING
    const uint64_t sam_neck_start_ns = uocr_profile_now_ns();
#endif
    /*
     * Conv1x1: BHWC [B*S, 768] @ weight [256, 768]^T  →  BHWC.
     * Output stays BHWC throughout the neck pipeline — no transpose.
     */
    const uint32_t conv1x1_spatial = grid_w * grid_h;
    const uint32_t conv1x1_rows = conv1x1_spatial * view_count;
    uocr_metal_buffer_slice input_slice = { input_bhwc.buffer, input_bhwc.offset };
    uocr_metal_buffer_slice weight_slice = { weights->sam_neck_conv1x1_weight.slice.buffer,
                                              weights->sam_neck_conv1x1_weight.slice.offset };
    uocr_metal_buffer_slice out_slice = { scratch->sam_neck_a_nchw.buffer, scratch->sam_neck_a_nchw.offset };
#if UOCR_ENABLE_PROFILING
    const uint64_t conv1x1_start_ns = uocr_profile_now_ns();
#else
    const uint64_t conv1x1_start_ns = 0;
    (void)conv1x1_start_ns;
#endif
    if (!metal_run_mps_matmul_nt_f16(ctx, input_slice, weight_slice, out_slice,
                                     conv1x1_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_NECK_CHANNELS,
                                     "Metal SAM neck 1x1 MPS matmul", error, error_size)) {
        return 0;
    }
#if UOCR_ENABLE_PROFILING
    metal_profile_add_event_now(ctx, "metal.vision.SAM neck 1x1 convolution (BHWC)", conv1x1_start_ns);
    if (metal_vision_profile_detail_level() >= 3 &&
        !metal_vision_profile_checkpoint(ctx, "sam_neck.SAM neck 1x1 convolution (BHWC)", 1, error, error_size)) {
        return 0;
    }
#endif
    RUN_BATCHED_SAM_NECK_STEP("SAM neck LayerNorm2d-1 (BHWC)",
                              metal_context_sam_layernorm2d_bhwc_batch_f16_to_slice(ctx,
                                                                                   scratch->sam_neck_a_nchw,
                                                                                   weights->sam_neck_norm1_weight,
                                                                                   weights->sam_neck_norm1_bias,
                                                                                   grid_w,
                                                                                   grid_h,
                                                                                   view_count,
                                                                                   scratch->sam_neck_b_nchw,
                                                                                   error,
                                                                                   error_size));
    RUN_BATCHED_SAM_NECK_STEP("SAM neck 3x3 convolution (BHWC)",
                              metal_context_sam_conv3x3_im2col_mps_bhwc_batch_f16_to_slice(ctx,
                                                                                           scratch->sam_neck_b_nchw,
                                                                                           weights->sam_neck_conv3x3_weight_ohwi,
                                                                                           grid_w,
                                                                                           grid_h,
                                                                                           UOCR_SAM_NECK_CHANNELS,
                                                                                           UOCR_SAM_NECK_CHANNELS,
                                                                                           1u,
                                                                                           view_count,
                                                                                           scratch->sam_neck_a_nchw,
                                                                                           "Metal SAM neck 3x3 BHWC MPS",
                                                                                           scratch,
                                                                                           error,
                                                                                           error_size));
    RUN_BATCHED_SAM_NECK_STEP("SAM neck LayerNorm2d-2 (BHWC)",
                              metal_context_sam_layernorm2d_bhwc_batch_f16_to_slice(ctx,
                                                                                   scratch->sam_neck_a_nchw,
                                                                                   weights->sam_neck_norm2_weight,
                                                                                   weights->sam_neck_norm2_bias,
                                                                                   grid_w,
                                                                                   grid_h,
                                                                                   view_count,
                                                                                   scratch->sam_neck_b_nchw,
                                                                                   error,
                                                                                   error_size));
    RUN_BATCHED_SAM_NECK_STEP("SAM net_2 convolution (BHWC)",
                              metal_context_sam_conv3x3_im2col_mps_bhwc_batch_f16_to_slice(ctx,
                                                                                           scratch->sam_neck_b_nchw,
                                                                                           weights->sam_net2_weight_ohwi,
                                                                                           grid_w,
                                                                                           grid_h,
                                                                                           UOCR_SAM_NECK_CHANNELS,
                                                                                           UOCR_SAM_NET2_CHANNELS,
                                                                                           UOCR_SAM_NET_STRIDE,
                                                                                           view_count,
                                                                                           scratch->sam_net2_nchw,
                                                                                           "Metal SAM net_2 BHWC MPS",
                                                                                           scratch,
                                                                                           error,
                                                                                           error_size));
    RUN_BATCHED_SAM_NECK_STEP("SAM net_3 convolution (BHWC)",
                              metal_context_sam_conv3x3_im2col_mps_bhwc_batch_f16_to_slice(ctx,
                                                                                           scratch->sam_net2_nchw,
                                                                                           weights->sam_net3_weight_ohwi,
                                                                                           net2_grid_w,
                                                                                           net2_grid_h,
                                                                                           UOCR_SAM_NET2_CHANNELS,
                                                                                           UOCR_SAM_NET3_CHANNELS,
                                                                                           UOCR_SAM_NET_STRIDE,
                                                                                           view_count,
                                                                                           out_sam_nchw,
                                                                                           "Metal SAM net_3 BHWC MPS",
                                                                                           scratch,
                                                                                           error,
                                                                                           error_size));
#if UOCR_ENABLE_PROFILING
    metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.sam_neck_batch" : "metal.vision.sam_neck", sam_neck_start_ns);
#endif
    *out_grid_w = sam_grid_w;
    *out_grid_h = sam_grid_h;

#undef RUN_BATCHED_SAM_NECK_STEP

    return 1;
}

static int metal_context_clip_embed_sam_batch_f16_to_slice(uocr_metal_context *ctx,
                                                           uocr_metal_vision_workspace_slice sam_nchw,
                                                           uocr_metal_vision_tensor_f16 class_embedding,
                                                           uint32_t grid_w,
                                                           uint32_t grid_h,
                                                           uint32_t view_count,
                                                           uocr_metal_vision_workspace_slice out_tokens,
                                                           char *error,
                                                           size_t error_size) {
    uint64_t spatial = 0u;
    uint64_t input_values_per_view = 0u;
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_tokens = 0u;
    uint64_t output_values_per_view = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t class_bytes = (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    if (view_count == 0u || !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &spatial) ||
        !checked_mul_u64(spatial, (uint64_t)UOCR_SAM_FEATURE_CHANNELS, &input_values_per_view) ||
        !checked_mul_u64(input_values_per_view, (uint64_t)view_count, &input_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !checked_add_u64(spatial, (uint64_t)UOCR_CLIP_CLASS_TOKENS, &output_tokens) ||
        !checked_mul_u64(output_tokens, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &output_values_per_view) ||
        !checked_mul_u64(output_values_per_view, (uint64_t)view_count, &output_values) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_vision_require_workspace_slice(sam_nchw, input_bytes, "CLIP SAM embedding input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_tokens, output_bytes, "CLIP SAM embedding output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(class_embedding, class_bytes, "CLIP class embedding", error, error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_clip_embed_sam_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx,
                                                              &owned_command_buffer,
                                                              "Metal CLIP SAM embedding batch",
                                                              error,
                                                              error_size);
        if (cb == nil) {
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_clip_embed_sam_command_buffer";
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal CLIP SAM embedding command encoder");
        }
        uocr_metal_clip_embed_sam_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.hidden_size = UOCR_CLIP_HIDDEN_SIZE;
        params.token_count = (uint32_t)output_tokens;
        params.batch_size = view_count;
        NSUInteger threads_x = pipeline.threadExecutionWidth;
        if (threads_x == 0u) {
            threads_x = 1u;
        }
        if (threads_x > (NSUInteger)UOCR_CLIP_HIDDEN_SIZE) {
            threads_x = (NSUInteger)UOCR_CLIP_HIDDEN_SIZE;
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:sam_nchw.buffer offset:sam_nchw.offset atIndex:0u];
        [enc setBuffer:class_embedding.slice.buffer offset:class_embedding.slice.offset atIndex:1u];
        [enc setBuffer:out_tokens.buffer offset:out_tokens.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)UOCR_CLIP_HIDDEN_SIZE, (NSUInteger)output_tokens, (NSUInteger)view_count)
       threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx,
                                                  cb,
                                                  owned_command_buffer,
                                                  "Metal CLIP SAM embedding batch",
                                                  error,
