/*
 * Fused Q8_0 vision GEMM: dst = act(src @ qweightᵀ + bias).
 * Tiled simdgroup-MMA kernel; each Q8 weight tile is dequantized once per
 * 64-row block into threadgroup memory (no dequantized global buffers).
 * split_size == 0 writes a single [m, n] output; otherwise columns are routed
 * into dst0/dst1/dst2 with per-projection width split_size (fused QKV).
 */
static int metal_run_vision_gemm_q8_0(uocr_metal_context *ctx,
                                      uocr_metal_buffer_slice input,
                                      uocr_metal_vision_tensor_f16 weight,
                                      uocr_metal_vision_tensor_f16 bias,
                                      uint32_t n_rows,
                                      uint32_t input_size,
                                      uint32_t output_size,
                                      uint32_t activation,
                                      uint32_t split_size,
                                      uocr_metal_buffer_slice dst0,
                                      uocr_metal_buffer_slice dst1,
                                      uocr_metal_buffer_slice dst2,
                                      const char *op_name,
                                      char *error,
                                      size_t error_size) {
    const uint64_t bias_bytes = (uint64_t)output_size * 2u;
    if (ctx == NULL || n_rows == 0u || (input_size % 32u) != 0u ||
        (split_size != 0u && (output_size != split_size * 3u)) ||
        !metal_vision_require_weight_q8(weight, output_size, input_size, op_name, error, error_size) ||
        !metal_vision_require_tensor_slice_f16(bias, bias_bytes, op_name, error, error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_vision_gemm_q8_0_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        if (pipeline.maxTotalThreadsPerThreadgroup < UOCR_METAL_GEMM_Q8_THREADS) {
            return metal_fail(error, error_size, "%s pipeline does not support 128-thread groups", op_name);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s encoder", op_name);
        }
        uocr_metal_vision_gemm_q8_params params;
        memset(&params, 0, sizeof(params));
        params.m = n_rows;
        params.k = input_size;
        params.n = output_size;
        params.groups_per_row = input_size / UOCR_Q8_GROUP_SIZE_DEFAULT;
        params.activation = activation;
        params.split_size = split_size;
        if (split_size == 0u) {
            dst1 = dst0;
            dst2 = dst0;
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:weight.slice.buffer offset:weight.slice.offset atIndex:1u];
        [enc setBuffer:weight.scale_slice.buffer offset:weight.scale_slice.offset atIndex:2u];
        [enc setBuffer:bias.slice.buffer offset:bias.slice.offset atIndex:3u];
        [enc setBuffer:dst0.buffer offset:dst0.offset atIndex:4u];
        [enc setBuffer:dst1.buffer offset:dst1.offset atIndex:5u];
        [enc setBuffer:dst2.buffer offset:dst2.offset atIndex:6u];
        [enc setBytes:&params length:sizeof(params) atIndex:7u];
        const NSUInteger col_tiles = ((NSUInteger)output_size + UOCR_METAL_GEMM_Q8_BN - 1u) / UOCR_METAL_GEMM_Q8_BN;
        const NSUInteger row_tiles = ((NSUInteger)n_rows + UOCR_METAL_GEMM_Q8_BM - 1u) / UOCR_METAL_GEMM_Q8_BM;
        [enc dispatchThreadgroups:MTLSizeMake(col_tiles, row_tiles, 1u)
            threadsPerThreadgroup:MTLSizeMake(UOCR_METAL_GEMM_Q8_THREADS, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_run_visual_projector_q8_0_to_slice(uocr_metal_context *ctx,
                                                     uocr_metal_vision_workspace_slice input,
                                                     uocr_metal_vision_tensor_f16 weight,
                                                     uocr_metal_vision_tensor_f16 bias,
                                                     uint32_t n_rows,
                                                     uocr_metal_vision_workspace_slice out_rows,
                                                     char *error,
                                                     size_t error_size) {
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &input_values) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_HIDDEN_SIZE, &output_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_vision_require_workspace_slice(input, input_bytes, "visual projector input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_rows, output_bytes, "visual projector output", error, error_size)) {
        return metal_fail(error, error_size, "invalid Metal visual projector q8_0 inputs");
    }
    const uocr_metal_buffer_slice input_slice = { input.buffer, input.offset };
    const uocr_metal_buffer_slice out_slice = { out_rows.buffer, out_rows.offset };
    const uint64_t q8_start_ns = uocr_profile_now_ns();
    if (!metal_run_vision_gemm_q8_0(ctx,
                                    input_slice,
                                    weight,
                                    bias,
                                    n_rows,
                                    UOCR_PROJECTOR_IN_SIZE,
                                    UOCR_HIDDEN_SIZE,
                                    UOCR_METAL_VISION_Q8_ACT_NONE,
                                    0u,
                                    out_slice,
                                    out_slice,
                                    out_slice,
                                    "Metal visual projector Q8",
                                    error,
                                    error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.vision.projector_q8", q8_start_ns);
    return 1;
}

static int metal_context_visual_projector_f16_to_slice(uocr_metal_context *ctx,
                                                       uocr_metal_vision_workspace_slice input,
                                                       uocr_metal_vision_tensor_f16 weight,
                                                       uocr_metal_vision_tensor_f16 bias,
                                                       uint32_t n_rows,
                                                       uocr_metal_vision_workspace_slice out_rows,
                                                       char *error,
                                                       size_t error_size) {
    if (weight.qtype == UOCR_TENSOR_Q8_0) {
        return metal_run_visual_projector_q8_0_to_slice(ctx,
                                                        input,
                                                        weight,
                                                        bias,
                                                        n_rows,
                                                        out_rows,
                                                        error,
                                                        error_size);
    }
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_PROJECTOR_IN_SIZE * 2u;
    const uint64_t bias_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &input_values) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_HIDDEN_SIZE, &output_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_vision_require_workspace_slice(input, input_bytes, "visual projector input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_rows, output_bytes, "visual projector output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(weight, weight_bytes, "visual projector weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(bias, bias_bytes, "visual projector bias", error, error_size)) {
        return 0;
    }
    uocr_metal_buffer_slice input_slice = { input.buffer, input.offset };
    uocr_metal_buffer_slice weight_slice = { weight.slice.buffer, weight.slice.offset };
    uocr_metal_buffer_slice out_slice = { out_rows.buffer, out_rows.offset };
    if (!metal_run_mps_matmul_nt_f16(ctx, input_slice, weight_slice, out_slice,
                                     n_rows, UOCR_PROJECTOR_IN_SIZE, UOCR_HIDDEN_SIZE,
                                     "Metal visual projector MPS matmul", error, error_size)) {
        return 0;
    }
    uocr_metal_buffer_slice bias_slice = { bias.slice.buffer, bias.slice.offset };
    if (!metal_run_bias_add_f16_inplace(ctx, out_slice, bias_slice,
                                        n_rows, UOCR_HIDDEN_SIZE,
                                        "Metal visual projector bias add", error, error_size)) {
        return 0;
    }
    return 1;
}
static int metal_context_sam_patch_embed_batch_f16_to_slice(uocr_metal_vision_project_context *project,
                                                            const uocr_vision_chunk *chunk,
                                                            uocr_metal_vision_workspace_slice out_bhwc,
                                                            uint32_t *out_grid_w,
                                                            uint32_t *out_grid_h,
                                                            char *error,
                                                            size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->request == NULL || project->weights == NULL || chunk == NULL ||
        out_grid_w == NULL || out_grid_h == NULL || chunk->view_count == 0u || out_bhwc.buffer == nil) {
        return metal_fail(error, error_size, "invalid Metal batched SAM patch request");
    }
    if (project->scratch == NULL || chunk->view_count > project->scratch->sam_patch_view_capacity) {
        return metal_fail(error, error_size, "Metal batched SAM patch view count exceeds workspace capacity");
    }
    if (chunk->first_view > project->request->n_views || chunk->view_count > project->request->n_views - chunk->first_view) {
        return metal_fail(error, error_size, "Metal batched SAM patch view range is invalid");
    }

    const uocr_image_view *first = &project->request->views[chunk->first_view];
    if (first->kind != (chunk->kind == UOCR_VISION_CHUNK_LOCAL ? UOCR_VIEW_LOCAL : UOCR_VIEW_GLOBAL) ||
        (first->format != UOCR_PIXEL_F16_NCHW && first->format != UOCR_PIXEL_F32_NCHW) ||
        first->width == 0u || first->height == 0u ||
        (first->width % UOCR_VISION_PATCH_SIZE) != 0u || (first->height % UOCR_VISION_PATCH_SIZE) != 0u) {
        return metal_fail(error, error_size, "Metal batched SAM patch first view is invalid");
    }
    for (uint32_t view_index = 1u; view_index < chunk->view_count; ++view_index) {
        const uocr_image_view *view = &project->request->views[chunk->first_view + view_index];
        if (view->kind != first->kind || view->format != first->format || view->width != first->width || view->height != first->height) {
            return metal_fail(error,
                              error_size,
                              "Metal batched SAM patch requires same kind/format/shape within a shape group");
        }
    }

    const uint32_t grid_w = first->width / UOCR_VISION_PATCH_SIZE;
    const uint32_t grid_h = first->height / UOCR_VISION_PATCH_SIZE;
    const uint64_t element_size = first->format == UOCR_PIXEL_F16_NCHW ? 2u : 4u;
    uint64_t pixel_values = 0u;
    uint64_t pixel_bytes_per_view = 0u;
    uint64_t pixel_bytes = 0u;
    uint64_t output_patches = 0u;
    uint64_t output_values_per_view = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t weight_values = 0u;
    uint64_t weight_bytes = 0u;
    const uint64_t bias_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    if (!checked_mul_u64(3u, (uint64_t)first->width, &pixel_values) ||
        !checked_mul_u64(pixel_values, (uint64_t)first->height, &pixel_values) ||
        !checked_mul_u64(pixel_values, element_size, &pixel_bytes_per_view) ||
        !checked_mul_u64(pixel_bytes_per_view, (uint64_t)chunk->view_count, &pixel_bytes) ||
        !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &output_patches) ||
        !checked_mul_u64(output_patches, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &output_values_per_view) ||
        !checked_mul_u64(output_values_per_view, (uint64_t)chunk->view_count, &output_values) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !checked_mul_u64((uint64_t)UOCR_SAM_HIDDEN_SIZE,
                         3u * (uint64_t)UOCR_VISION_PATCH_SIZE * (uint64_t)UOCR_VISION_PATCH_SIZE,
                         &weight_values) ||
        !metal_vision_f16_bytes(weight_values, &weight_bytes) ||
        pixel_bytes > (uint64_t)SIZE_MAX ||
        !metal_vision_require_workspace_slice(out_bhwc, output_bytes, "batched SAM patch output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(project->weights->sam_patch_weight, weight_bytes, "SAM patch weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(project->weights->sam_patch_bias, bias_bytes, "SAM patch bias", error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLBuffer> pixel_buffer = metal_new_buffer_with_length(project->ctx, (NSUInteger)pixel_bytes, MTLResourceStorageModeShared);
        if (pixel_buffer == nil || [pixel_buffer contents] == NULL) {
            if (pixel_buffer != nil) [pixel_buffer release];
            return metal_fail(error, error_size, "failed to allocate Metal batched SAM patch pixel buffer");
        }
        pixel_buffer.label = @"uocr_sam_patch_pixels_batch";
        uint8_t *dst_pixels = (uint8_t *)[pixel_buffer contents];
        for (uint32_t view_index = 0u; view_index < chunk->view_count; ++view_index) {
            const uocr_image_view *view = &project->request->views[chunk->first_view + view_index];
            memcpy(dst_pixels + (size_t)view_index * (size_t)pixel_bytes_per_view,
                   view->pixels,
                   (size_t)pixel_bytes_per_view);
        }

        /*
         * Replace the direct-convolution patch embed with:
         *   1. Extract non-overlapping 16x16 patches from NCHW pixels
         *      into row-major [B*patches, 768].
         *   2. MPS matmul: patches @ weight^T  →  out_bhwc [B*patches, 768].
         *   3. Add bias in-place.
         *
         * The custom kernel (threadgroup reduction) was slower than MPS matmul
         * for these non-overlapping patches.
         */
        const uint32_t total_patches = (uint32_t)output_patches * chunk->view_count;
        const uint64_t temp_patch_bytes = (uint64_t)total_patches * 768u * 2u;
        id<MTLBuffer> patch_buffer = nil;
        @autoreleasepool {
            patch_buffer = metal_new_buffer_with_length(project->ctx, (NSUInteger)temp_patch_bytes, MTLResourceStorageModePrivate);
            if (patch_buffer == nil) {
                [pixel_buffer release];
                return metal_fail(error, error_size, "failed to allocate Metal SAM patch extraction temp buffer");
            }
            patch_buffer.label = @"uocr_sam_patch_extraction_temp";
        }

        /* Step 1: extract patches */
        {
            id<MTLComputePipelineState> extract_pipeline = metal_get_pipeline(project->ctx, "uocr_sam_extract_patches_f16", error, error_size);
            if (extract_pipeline == nil) {
                [patch_buffer release];
                [pixel_buffer release];
                return 0;
            }
            int owned = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(project->ctx, &owned, "Metal SAM patch extraction", error, error_size);
            if (cb == nil) {
                [patch_buffer release];
                [pixel_buffer release];
                return 0;
            }
            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(project->ctx, cb);
            if (enc == nil) {
                [patch_buffer release];
                [pixel_buffer release];
                return metal_fail(error, error_size, "failed to create Metal SAM patch extraction encoder");
            }
            struct { uint32_t height; uint32_t width; uint32_t grid_h; uint32_t grid_w; } dims;
            dims.height = first->height;
            dims.width = first->width;
            dims.grid_h = grid_h;
            dims.grid_w = grid_w;
            [enc setComputePipelineState:extract_pipeline];
            [enc setBuffer:pixel_buffer offset:0u atIndex:0u];
            [enc setBuffer:patch_buffer offset:0u atIndex:1u];
            [enc setBytes:&dims length:sizeof(dims) atIndex:2u];
            [enc dispatchThreads:MTLSizeMake(768u, (NSUInteger)total_patches, 1u)
           threadsPerThreadgroup:MTLSizeMake(32u, 1u, 1u)];
            [enc endEncoding];
            const int extract_ok = metal_finish_command_buffer_for_op(project->ctx, cb, owned, "Metal SAM patch extraction", error, error_size);
            if (!extract_ok) {
                [patch_buffer release];
                [pixel_buffer release];
                return 0;
            }
        }

        /* Step 2: MPS matmul  patches @ weight^T  →  out_bhwc */
        {
            uocr_metal_buffer_slice patch_slice = { patch_buffer, 0u };
            uocr_metal_buffer_slice weight_slice = { project->weights->sam_patch_weight.slice.buffer,
                                                     project->weights->sam_patch_weight.slice.offset };
            uocr_metal_buffer_slice out_slice = { out_bhwc.buffer, out_bhwc.offset };
            if (!metal_run_mps_matmul_nt_f16(project->ctx,
                                             patch_slice,
                                             weight_slice,
                                             out_slice,
                                             total_patches,
                                             768u,
                                             UOCR_SAM_HIDDEN_SIZE,
                                             "Metal SAM patch embed MPS matmul",
                                             error,
                                             error_size)) {
                [patch_buffer release];
                [pixel_buffer release];
                return 0;
            }
        }

        /* Step 3: bias add in-place */
        {
            uocr_metal_buffer_slice out_slice = { out_bhwc.buffer, out_bhwc.offset };
            uocr_metal_buffer_slice bias_slice = { project->weights->sam_patch_bias.slice.buffer,
                                                    project->weights->sam_patch_bias.slice.offset };
            if (!metal_run_bias_add_f16_inplace(project->ctx,
                                                out_slice,
                                                bias_slice,
                                                total_patches,
                                                UOCR_SAM_HIDDEN_SIZE,
                                                "Metal SAM patch embed bias",
                                                error,
                                                error_size)) {
                [patch_buffer release];
                [pixel_buffer release];
                return 0;
            }
        }

        [patch_buffer release];
        [pixel_buffer release];
        *out_grid_w = grid_w;
        *out_grid_h = grid_h;
        metal_clear_error(error, error_size);
        return 1;
    }
}
static int metal_dispatch_visual_format_kernel(uocr_metal_context *ctx,
                                               const char *function_name,
                                               const char *op_name,
                                               id<MTLBuffer> buffer0,
                                               NSUInteger offset0,
                                               id<MTLBuffer> buffer1,
                                               NSUInteger offset1,
                                               id<MTLBuffer> buffer2,
                                               NSUInteger offset2,
                                               id<MTLBuffer> buffer3,
                                               NSUInteger offset3,
                                               const void *params,
                                               NSUInteger params_size,
                                               uint32_t hidden_size,
                                               uint32_t rows,
                                               char *error,
                                               size_t error_size) {
    if (ctx == NULL || function_name == NULL || op_name == NULL || buffer0 == nil || buffer1 == nil ||
        params == NULL || params_size == 0u || hidden_size == 0u || rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal visual formatter request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = [NSString stringWithFormat:@"%s_command_buffer", op_name];
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s encoder", op_name);
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:buffer0 offset:offset0 atIndex:0u];
        [enc setBuffer:buffer1 offset:offset1 atIndex:1u];
        if (buffer2 != nil) {
            [enc setBuffer:buffer2 offset:offset2 atIndex:2u];
        }
        if (buffer3 != nil) {
            [enc setBuffer:buffer3 offset:offset3 atIndex:3u];
            [enc setBytes:params length:params_size atIndex:4u];
        } else {
            [enc setBytes:params length:params_size atIndex:2u];
        }
        const NSUInteger dispatch_width = (NSUInteger)(((uint64_t)hidden_size + UOCR_METAL_HALF4_WIDTH - 1u) /
                                                       UOCR_METAL_HALF4_WIDTH);
        NSUInteger threads_x = pipeline.threadExecutionWidth;
        if (threads_x == 0u || threads_x > dispatch_width) {
            threads_x = 32u;
        }
        if (threads_x > dispatch_width) {
            threads_x = dispatch_width;
        }
        if (threads_x > pipeline.maxTotalThreadsPerThreadgroup) {
            threads_x = pipeline.maxTotalThreadsPerThreadgroup;
        }
        if (threads_x == 0u) {
            threads_x = 1u;
        }
        [enc dispatchThreads:MTLSizeMake(dispatch_width, (NSUInteger)rows, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_format_global_visual_rows_f16(uocr_metal_context *ctx,
                                               uocr_metal_vision_workspace_slice projected_rows,
                                               uocr_metal_vision_tensor_f16 image_newline,
                                               uocr_metal_vision_tensor_f16 view_separator,
                                               uocr_metal_vision_workspace_slice dst_rows,
                                               uint32_t grid_size,
                                               uint32_t view_count,
                                               uint32_t dst_token_base,
                                               char *error,
                                               size_t error_size) {
    if (view_count == 0u || grid_size == 0u) {
        return metal_fail(error, error_size, "invalid Metal global visual formatter shape");
    }
    const uint32_t projected_tokens_per_view = grid_size * grid_size;
    const uint32_t visual_tokens_per_view = grid_size * (grid_size + 1u) + 1u;
    const uint64_t projected_bytes = (uint64_t)view_count * (uint64_t)projected_tokens_per_view * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t dst_end_bytes = ((uint64_t)dst_token_base + (uint64_t)view_count * (uint64_t)visual_tokens_per_view) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes) ||
        !metal_slice_valid(image_newline.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(view_separator.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal global visual formatter slices");
    }
    uocr_metal_visual_format_global_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = grid_size;
    params.visual_tokens_per_view = visual_tokens_per_view;
    params.view_count = view_count;
    params.dst_token_base = dst_token_base;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_format_global_visual_rows_f16",
                                               "Metal global visual formatter",
                                               projected_rows.buffer,
                                               projected_rows.offset,
                                               image_newline.slice.buffer,
                                               image_newline.slice.offset,
                                               view_separator.slice.buffer,
                                               view_separator.slice.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               view_count * visual_tokens_per_view,
                                               error,
                                               error_size);
}

static int metal_fill_local_visual_newlines_f16(uocr_metal_context *ctx,
                                                uocr_metal_vision_tensor_f16 image_newline,
                                                uocr_metal_vision_workspace_slice dst_rows,
                                                uint32_t crop_grid_w,
                                                uint32_t crop_grid_h,
                                                uint32_t dst_token_base,
                                                char *error,
                                                size_t error_size) {
    if (crop_grid_w == 0u || crop_grid_h == 0u) {
        return metal_fail(error, error_size, "invalid Metal local newline formatter grid");
    }
    const uint32_t local_rows = crop_grid_h * UOCR_LOCAL_GRID_QUERIES;
    const uint32_t local_visual_tokens = uocr_local_visual_token_count(crop_grid_w, crop_grid_h);
    const uint64_t dst_end_bytes = ((uint64_t)dst_token_base + (uint64_t)local_visual_tokens) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid(image_newline.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal local newline formatter slices");
    }
    uocr_metal_visual_format_local_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = UOCR_LOCAL_GRID_QUERIES;
    params.crop_grid_w = crop_grid_w;
    params.chunk_view_count = crop_grid_h;
    params.dst_token_base = dst_token_base;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_fill_local_visual_newlines_f16",
                                               "Metal local newline formatter",
                                               image_newline.slice.buffer,
                                               image_newline.slice.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               nil,
                                               0u,
                                               nil,
                                               0u,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               local_rows,
                                               error,
                                               error_size);
}

static int metal_format_local_visual_rows_f16(uocr_metal_context *ctx,
                                              const uocr_vision_chunk *chunk,
                                              uocr_metal_vision_workspace_slice projected_rows,
                                              uocr_metal_vision_workspace_slice dst_rows,
                                              uint32_t crop_grid_w,
                                              char *error,
                                              size_t error_size) {
    if (chunk == NULL || chunk->kind != UOCR_VISION_CHUNK_LOCAL || crop_grid_w == 0u || chunk->view_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal local visual formatter request");
    }
    const uint32_t projected_rows_count = chunk->view_count * UOCR_LOCAL_GRID_QUERIES * UOCR_LOCAL_GRID_QUERIES;
    const uint64_t projected_bytes = (uint64_t)projected_rows_count * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint32_t last_local_view = chunk->first_view + chunk->view_count - 1u;
    const uint64_t dst_min_rows = (uint64_t)uocr_local_visual_token_count(crop_grid_w, 1u + last_local_view / crop_grid_w);
    if ((uint64_t)chunk->final_token_count < dst_min_rows) {
        return metal_fail(error, error_size, "Metal local visual formatter final range is too small");
    }
    const uint64_t dst_end_bytes = ((uint64_t)chunk->final_token_start + (uint64_t)chunk->final_token_count) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal local visual formatter slices");
    }
    uocr_metal_visual_format_local_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = UOCR_LOCAL_GRID_QUERIES;
    params.crop_grid_w = crop_grid_w;
    params.chunk_first_view = chunk->first_view;
    params.chunk_view_count = chunk->view_count;
    params.dst_token_base = chunk->final_token_start;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_format_local_visual_rows_f16",
                                               "Metal local visual formatter",
                                               projected_rows.buffer,
                                               projected_rows.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               nil,
                                               0u,
                                               nil,
                                               0u,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               projected_rows_count,
                                               error,
                                               error_size);
}

static int metal_project_vision_chunk_f16(const uocr_vision_chunk *chunk,
                                          uocr_metal_vision_workspace_slice projected_rows,
                                          uint32_t projected_scratch_rows,
                                          void *user_data,
                                          char *error,
                                          size_t error_size) {
    if (chunk == NULL || projected_rows.buffer == nil || user_data == NULL) {
        (void)metal_fail(error, error_size, "invalid Metal vision chunk projection request");
        return UOCR_ERROR_INVALID_ARGUMENT;
    }
    if (projected_scratch_rows < chunk->projected_token_count) {
        (void)metal_fail(error,
                         error_size,
                         "Metal vision projected scratch has %u rows, need %u",
                         projected_scratch_rows,
                         chunk->projected_token_count);
        return UOCR_ERROR_OUT_OF_MEMORY;
    }
    const uint64_t projected_bytes = (uint64_t)chunk->projected_token_count * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (projected_rows.bytes < projected_bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes)) {
        (void)metal_fail(error, error_size, "Metal vision projected-row slice is too small for chunk");
        return UOCR_ERROR_OUT_OF_MEMORY;
    }

    uocr_metal_vision_project_context *project = (uocr_metal_vision_project_context *)user_data;
    if (project->request == NULL || chunk->first_view > project->request->n_views ||
        chunk->view_count > project->request->n_views - chunk->first_view) {
        (void)metal_fail(error, error_size, "Metal vision chunk view range is invalid");
        return UOCR_ERROR_INVALID_ARGUMENT;
    }

#if UOCR_ENABLE_PROFILING
    const uint64_t chunk_encode_start_ns = uocr_profile_now_ns();
    const int vision_profile_detail = metal_vision_profile_detail_level();
#define METAL_VISION_STAGE_CHECKPOINT(stage_name__)                                                    \
    do {                                                                                                \
        if (vision_profile_detail >= 1 &&                                                               \
            !metal_vision_profile_checkpoint(project->ctx, (stage_name__), 1, error, error_size)) {     \
            return UOCR_ERROR_INTERNAL;                                                                \
        }                                                                                               \
    } while (0)
#else
    const uint64_t chunk_encode_start_ns = 0;
    const int vision_profile_detail = 0;
    (void)vision_profile_detail;
#define METAL_VISION_STAGE_CHECKPOINT(stage_name__) ((void)(stage_name__))
#endif
    uint32_t batched_patch_grid_w = 0u;
    uint32_t batched_patch_grid_h = 0u;
#if UOCR_ENABLE_PROFILING
    const uint64_t sam_patch_batch_start_ns = uocr_profile_now_ns();
#else
    const uint64_t sam_patch_batch_start_ns = 0;
#endif
    if (!metal_context_sam_patch_embed_batch_f16_to_slice(project,
                                                         chunk,
                                                         project->scratch->sam_patch_bhwc,
                                                         &batched_patch_grid_w,
                                                         &batched_patch_grid_h,
                                                         error,
                                                         error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.sam_patch_batch", sam_patch_batch_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("sam_patch_batch");

    const uint32_t projected_tokens_per_view = chunk->projected_tokens_per_view;
    const uint32_t clip_tokens_per_view = projected_tokens_per_view + UOCR_CLIP_CLASS_TOKENS;
    if (clip_tokens_per_view == 0u || chunk->view_count > UINT32_MAX / clip_tokens_per_view) {
        (void)metal_fail(error, error_size, "Metal batched CLIP token count overflow");
        return UOCR_ERROR_INTERNAL;
    }
    const uint32_t batch_clip_tokens = clip_tokens_per_view * chunk->view_count;
    const uint32_t patch_grid_w = batched_patch_grid_w;
    const uint32_t patch_grid_h = batched_patch_grid_h;
    const uocr_metal_vision_tensor_f16 sam_pos_embed = metal_sam_abs_pos_table_for_grid(project->weights,
                                                                                        patch_grid_w,
                                                                                        patch_grid_h);
    const uint64_t sam_abs_pos_batch_start_ns = uocr_profile_now_ns();
    if (!metal_context_sam_add_abs_pos_batch_f16_to_slice(project->ctx,
                                                         project->scratch->sam_patch_bhwc,
                                                         sam_pos_embed,
                                                         patch_grid_w,
                                                         patch_grid_h,
                                                         chunk->view_count,
                                                         project->scratch->sam_pos_bhwc,
                                                         error,
                                                         error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.sam_abs_pos_batch", sam_abs_pos_batch_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("sam_abs_pos_batch");

    const uint64_t sam_transformer_batch_start_ns = uocr_profile_now_ns();
    if (!metal_context_sam_transformer_batch_workspace_f16_to_slice(project->ctx,
                                                                    project->scratch->sam_pos_bhwc,
                                                                    project->weights->sam_block_slices,
                                                                    UOCR_SAM_BLOCKS,
                                                                    patch_grid_w,
                                                                    patch_grid_h,
                                                                    chunk->view_count,
                                                                    project->scratch->sam_transformer_batch_bhwc,
                                                                    project->scratch,
                                                                    error,
                                                                    error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.sam_transformer_batch", sam_transformer_batch_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("sam_transformer_batch");
    uint32_t sam_grid_w = 0u;
    uint32_t sam_grid_h = 0u;
    if (!metal_context_sam_neck_batch_f16_to_slice(project,
                                                   project->scratch->sam_transformer_batch_bhwc,
                                                   patch_grid_w,
                                                   patch_grid_h,
                                                   chunk->view_count,
                                                   project->scratch->sam_net3_nchw,
                                                   &sam_grid_w,
                                                   &sam_grid_h,
                                                   error,
                                                   error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    METAL_VISION_STAGE_CHECKPOINT("sam_neck_batch");
    if (sam_grid_w * sam_grid_h != projected_tokens_per_view) {
        (void)metal_fail(error, error_size, "Metal batched SAM neck grid does not match projected token count");
        return UOCR_ERROR_INTERNAL;
    }

    /* Transpose neck BHWC output → NCHW into stable sam_neck_b_nchw buffer.
     * This NCHW copy is used by both CLIP embedding and concat. */
    {
        uocr_metal_buffer_slice bhwc_slice = { project->scratch->sam_net3_nchw.buffer, project->scratch->sam_net3_nchw.offset };
        uocr_metal_buffer_slice nchw_slice = { project->scratch->sam_neck_b_nchw.buffer, project->scratch->sam_neck_b_nchw.offset };
        const uint64_t transpose_start_ns = uocr_profile_now_ns();
        if (!metal_context_bhwc_to_nchw_f16(project->ctx,
                                            bhwc_slice,
                                            chunk->view_count,
                                            sam_grid_w * sam_grid_h,
                                            UOCR_SAM_NET3_CHANNELS,
                                            nchw_slice,
                                            error,
                                            error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.sam_neck_bhwc_to_nchw_batch", transpose_start_ns);
        METAL_VISION_STAGE_CHECKPOINT("sam_neck_bhwc_to_nchw_batch");
    }

    const uint64_t clip_frontend_start_ns = uocr_profile_now_ns();
    if (!metal_context_clip_embed_sam_batch_f16_to_slice(project->ctx,
                                                        project->scratch->sam_neck_b_nchw,
                                                        project->weights->clip_class_embedding,
                                                        sam_grid_w,
                                                        sam_grid_h,
                                                        chunk->view_count,
                                                        project->scratch->clip_a,
                                                        error,
                                                        error_size) ||
        !metal_context_clip_add_abs_pos_batch_f16_to_slice(project->ctx,
                                                          project->scratch->clip_a,
                                                          metal_clip_abs_pos_table_for_grid(project->weights, sam_grid_w, sam_grid_h),
                                                          sam_grid_w,
                                                          sam_grid_h,
                                                          chunk->view_count,
                                                          project->scratch->clip_b,
                                                          error,
                                                          error_size) ||
        !metal_context_clip_pre_layernorm_f16_to_slice(project->ctx,
                                                       project->scratch->clip_b,
                                                       project->weights->clip_pre_ln_weight,
                                                       project->weights->clip_pre_ln_bias,
                                                       batch_clip_tokens,
                                                       project->scratch->clip_a,
                                                       error,
                                                       error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.clip_frontend_batch", clip_frontend_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("clip_frontend_batch");
    const uint64_t clip_transformer_start_ns = uocr_profile_now_ns();
    if (!metal_context_clip_transformer_batch_workspace_f16_to_slice(project->ctx,
                                                                     project->scratch->clip_a,
                                                                     project->weights->clip_block_slices,
                                                                     UOCR_CLIP_BLOCKS,
                                                                     clip_tokens_per_view,
                                                                     chunk->view_count,
                                                                     project->scratch->clip_final,
                                                                     project->scratch,
                                                                     error,
                                                                     error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.clip_transformer_batch", clip_transformer_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("clip_transformer_batch");
    const uint64_t concat_start_ns = uocr_profile_now_ns();
    if (!metal_context_clip_sam_concat_batch_f16_to_slice(project->ctx,
                                                         project->scratch->clip_final,
                                                         project->scratch->sam_neck_b_nchw,
                                                         sam_grid_w,
                                                         sam_grid_h,
                                                         chunk->view_count,
                                                         project->scratch->concat,
                                                         error,
                                                         error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.concat_batch", concat_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("concat_batch");
    const uint64_t projector_start_ns = uocr_profile_now_ns();
    if (!metal_context_visual_projector_f16_to_slice(project->ctx,
                                                    project->scratch->concat,
                                                    project->weights->projector_weight,
                                                    project->weights->projector_bias,
                                                    chunk->projected_token_count,
                                                    projected_rows,
                                                    error,
                                                    error_size)) {
        return UOCR_ERROR_INTERNAL;
    }
    metal_profile_add_event_now(project->ctx, "metal.vision.projector_batch", projector_start_ns);
    METAL_VISION_STAGE_CHECKPOINT("projector_batch");
    const uint64_t chunk_encode_end_ns = uocr_profile_now_ns();
    project->chunk_encode_ms += uocr_profile_elapsed_ms(chunk_encode_start_ns, chunk_encode_end_ns);
    metal_profile_add_event_now(project->ctx, "metal.vision.chunk_encode", chunk_encode_start_ns);

#undef METAL_VISION_STAGE_CHECKPOINT

    return UOCR_OK;
}

static int metal_vision_workspace_init_for_chunk_kind(uocr_metal_context *ctx,
                                                       uocr_metal_vision_workspace *workspace,
                                                       uocr_vision_chunk_kind kind,
                                                       uint32_t view_capacity,
                                                       uint32_t projected_row_capacity,
                                                       uocr_metal_vision_workspace_slice final_visual_rows,
                                                       uint32_t final_visual_row_capacity,
                                                       int cpu_visible_workspace,
                                                       char *error,
                                                       size_t error_size) {
    const uint32_t max_view_size = kind == UOCR_VISION_CHUNK_LOCAL ? UOCR_LOCAL_VIEW_SIZE : UOCR_GLOBAL_VIEW_SIZE;
    if (!metal_vision_workspace_init(ctx,
                                     workspace,
                                     max_view_size,
                                     view_capacity,
                                     projected_row_capacity,
                                     0u,
                                     cpu_visible_workspace,
                                     error,
                                     error_size)) {
        return 0;
    }
    workspace->final_visual_rows = final_visual_rows;
    workspace->final_visual_row_capacity = final_visual_row_capacity;
    uint64_t projected_row_values = 0u;
    uint64_t projected_row_bytes = 0u;
    uint64_t final_visual_row_values = 0u;
    uint64_t final_visual_row_bytes = 0u;
    if (!checked_mul_u64((uint64_t)projected_row_capacity, (uint64_t)UOCR_HIDDEN_SIZE, &projected_row_values) ||
        !metal_vision_f16_bytes(projected_row_values, &projected_row_bytes) ||
        !checked_mul_u64((uint64_t)final_visual_row_capacity, (uint64_t)UOCR_HIDDEN_SIZE, &final_visual_row_values) ||
        !metal_vision_f16_bytes(final_visual_row_values, &final_visual_row_bytes)) {
        metal_vision_workspace_reset(workspace);
        return metal_fail(error, error_size, "Metal vision projected/final workspace byte-size overflow");
    }
    if (workspace->projected_row_capacity < projected_row_capacity ||
        workspace->final_visual_row_capacity < final_visual_row_capacity) {
        metal_vision_workspace_reset(workspace);
        return metal_fail(error, error_size, "Metal vision workspace projected/final row capacity is insufficient");
    }
    if (!metal_vision_require_workspace_slice(workspace->projected_rows,
                                              projected_row_bytes,
                                              "projected visual rows",
                                              error,
                                              error_size) ||
        !metal_vision_require_workspace_slice(workspace->final_visual_rows,
                                              final_visual_row_bytes,
                                              "final visual rows",
                                              error,
                                              error_size)) {
        metal_vision_workspace_reset(workspace);
        return 0;
    }
    const uint32_t local_view_count = kind == UOCR_VISION_CHUNK_LOCAL ? view_capacity : 0u;
    const uint32_t global_view_count = kind == UOCR_VISION_CHUNK_GLOBAL ? view_capacity : 0u;
    if (!metal_prebuild_mps_vision_workspace_ndarrays(ctx,
                                                       workspace,
                                                       local_view_count,
                                                       global_view_count,
                                                       error,
                                                       error_size)) {
        metal_vision_workspace_reset(workspace);
        return 0;
    }
    return 1;
}

static int metal_context_encode_visual_features_to_workspace_f16(uocr_metal_context *ctx,
                                                                 const uocr_prepared_request *request,
                                                                 uint32_t max_views_per_chunk,
                                                                 const uocr_vision_schedule *schedule,
                                                                 uocr_metal_vision_workspace *scratch,
                                                                 int cpu_visible_workspace,
                                                                 char *error,
                                                                 size_t error_size) {
    if (ctx == NULL || request == NULL || schedule == NULL || scratch == NULL || schedule->final_visual_tokens == 0u) {
        return metal_fail(error, error_size, "invalid Metal vision workspace encoding request");
    }

    const uocr_metal_vision_weights_f16 *weights = metal_require_vision_weights_f16(ctx, error, error_size);
    if (weights == NULL) {
        return 0;
    }

    uocr_vision_chunk *chunks = (uocr_vision_chunk *)calloc(schedule->chunk_count, sizeof(chunks[0]));
    if (chunks == NULL) {
        metal_vision_workspace_reset(scratch);
        return metal_fail(error, error_size, "failed to allocate Metal vision chunk schedule");
    }
    uocr_vision_schedule planned;
    memset(&planned, 0, sizeof(planned));
    const int schedule_status = uocr_plan_vision_schedule(request,
                                                          max_views_per_chunk,
                                                          chunks,
                                                          schedule->chunk_count,
                                                          &planned,
                                                          error,
                                                          error_size);
    if (schedule_status != UOCR_OK || planned.chunk_count != schedule->chunk_count ||
        planned.final_visual_tokens != schedule->final_visual_tokens ||
        planned.max_chunk_projected_tokens != schedule->max_chunk_projected_tokens ||
        planned.max_local_chunk_projected_tokens != schedule->max_local_chunk_projected_tokens ||
        planned.max_global_chunk_projected_tokens != schedule->max_global_chunk_projected_tokens) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        free(chunks);
        metal_vision_workspace_reset(scratch);
        return metal_fail(error, error_size, "Metal vision schedule changed before encoding: %s", detail);
    }

    uocr_metal_vision_workspace_slice final_visual_rows;
    if (!metal_vision_final_rows_init(ctx,
                                      &final_visual_rows,
                                      schedule->final_visual_tokens,
                                      cpu_visible_workspace,
                                      error,
                                      error_size)) {
        free(chunks);
        metal_vision_workspace_reset(scratch);
        return 0;
    }
    scratch->final_visual_rows = final_visual_rows;
    scratch->final_visual_row_capacity = schedule->final_visual_tokens;

    uocr_metal_vision_project_context project;
    memset(&project, 0, sizeof(project));
    project.ctx = ctx;
    project.request = request;
    project.weights = weights;
    project.scratch = scratch;

#if UOCR_ENABLE_PROFILING
    const uint64_t chunk_processing_start_ns = uocr_profile_now_ns();
#else
    const uint64_t chunk_processing_start_ns = 0;
#endif
    uint64_t formatter_ns = 0u;
    int process_status = UOCR_OK;
    uint32_t local_newlines_encoded = 0u;
    int active_chunk_kind = -1;
    for (uint32_t chunk_index = 0u; process_status == UOCR_OK && chunk_index < schedule->chunk_count; ++chunk_index) {
        const uocr_vision_chunk *chunk = &chunks[chunk_index];
        if (active_chunk_kind != (int)chunk->kind) {
            const uocr_metal_vision_workspace_slice final_rows = scratch->final_visual_rows;
            const uint32_t final_row_capacity = scratch->final_visual_row_capacity;
            if (active_chunk_kind >= 0 || ctx->scratch[UOCR_METAL_SCRATCH_VISION].buffer != nil) {
                if (metal_command_batch_active(ctx)) {
                    process_status = UOCR_ERROR_INTERNAL;
                    (void)metal_fail(error, error_size, "Metal vision workspace shape changed inside an active command batch");
                    break;
                }
                uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
            }
            const uint32_t kind_view_capacity = chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                                   schedule->max_local_chunk_views :
                                                   schedule->max_global_chunk_views;
            const uint32_t kind_projected_capacity = chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                                        schedule->max_local_chunk_projected_tokens :
                                                        schedule->max_global_chunk_projected_tokens;
            if (!metal_vision_workspace_init_for_chunk_kind(ctx,
                                                            scratch,
                                                            chunk->kind,
                                                            kind_view_capacity,
                                                            kind_projected_capacity,
                                                            final_rows,
                                                            final_row_capacity,
                                                            cpu_visible_workspace,
                                                            error,
                                                            error_size)) {
                process_status = UOCR_ERROR_INTERNAL;
                break;
            }
            project.scratch = scratch;
            active_chunk_kind = (int)chunk->kind;
        }
        const int had_active_batch = metal_command_batch_active(ctx);
        const char *shape_group_op = chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                         "Metal local vision shape-group graph" :
                                         "Metal global vision shape-group graph";
        if (!had_active_batch && !metal_command_batch_begin(ctx, error, error_size)) {
            process_status = UOCR_ERROR_INTERNAL;
            break;
        }

        if (chunk->kind == UOCR_VISION_CHUNK_LOCAL && !local_newlines_encoded) {
#if UOCR_ENABLE_PROFILING
            const uint64_t formatter_start_ns = uocr_profile_now_ns();
#endif
            if (!metal_fill_local_visual_newlines_f16(ctx,
                                                      weights->image_newline,
                                                      scratch->final_visual_rows,
                                                      request->crop_grid_w,
                                                      request->crop_grid_h,
                                                      chunk->final_token_start,
                                                      error,
                                                      error_size)) {
                process_status = UOCR_ERROR_INTERNAL;
            } else {
                local_newlines_encoded = 1u;
            }
#if UOCR_ENABLE_PROFILING
            formatter_ns += uocr_profile_now_ns() - formatter_start_ns;
#endif
        }

        if (process_status == UOCR_OK) {
            process_status = metal_project_vision_chunk_f16(chunk,
                                                            scratch->projected_rows,
                                                            scratch->projected_row_capacity,
                                                            &project,
                                                            error,
                                                            error_size);
        }

        if (process_status == UOCR_OK) {
#if UOCR_ENABLE_PROFILING
            const uint64_t formatter_start_ns = uocr_profile_now_ns();
#endif
            if (chunk->kind == UOCR_VISION_CHUNK_LOCAL) {
                if (!metal_format_local_visual_rows_f16(ctx,
                                                        chunk,
                                                        scratch->projected_rows,
                                                        scratch->final_visual_rows,
                                                        request->crop_grid_w,
                                                        error,
                                                        error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                }
            } else {
                if (chunk->final_token_count != chunk->view_count * UOCR_GLOBAL_VISUAL_TOKENS) {
                    process_status = UOCR_ERROR_INTERNAL;
                    (void)metal_fail(error, error_size, "Metal global visual formatter final range is invalid");
                } else if (!metal_format_global_visual_rows_f16(ctx,
                                                                 scratch->projected_rows,
                                                                 weights->image_newline,
                                                                 weights->view_separator,
                                                                 scratch->final_visual_rows,
                                                                 chunk->projected_grid_w,
                                                                 chunk->view_count,
                                                                 chunk->final_token_start,
                                                                 error,
                                                                 error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                }
            }
#if UOCR_ENABLE_PROFILING
            formatter_ns += uocr_profile_now_ns() - formatter_start_ns;
            if (process_status == UOCR_OK && metal_vision_profile_detail_level() >= 1) {
                const char *formatter_checkpoint = chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                                       "local_formatter" :
                                                       "global_formatter";
                if (!metal_vision_profile_checkpoint(ctx, formatter_checkpoint, 0, error, error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                }
            }
#endif
        }

        if (!had_active_batch) {
            if (process_status == UOCR_OK) {
#if UOCR_ENABLE_PROFILING
                const uint64_t shape_group_wait_start_ns = uocr_profile_now_ns();
#endif
                if (!metal_command_batch_commit_and_wait(ctx, shape_group_op, error, error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                } else {
#if UOCR_ENABLE_PROFILING
                    metal_profile_add_event_now(ctx,
                                                chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                                    "metal.vision.local_shape_group_command_wait" :
                                                    "metal.vision.global_shape_group_command_wait",
                                                shape_group_wait_start_ns);
#endif
                }
            } else {
                metal_command_batch_abort(ctx);
            }
        }
    }
    free(chunks);

    const double chunk_processing_ms = uocr_profile_elapsed_ms(chunk_processing_start_ns, uocr_profile_now_ns());
    if (process_status == UOCR_OK) {
        metal_profile_add_event_ms(ctx, "metal.vision.chunk_processing", chunk_processing_ms);
        metal_profile_add_event_ms(ctx, "metal.vision.formatter", (double)formatter_ns / 1000000.0);
        return 1;
    }

    char detail[512];
    metal_copy_error_detail(detail, sizeof(detail), error);
    metal_vision_workspace_reset(scratch);
    return metal_fail(error, error_size, "Metal vision encoding failed: %s", detail);
}

/* Diagnostic host-output vision helpers. Public OCR dispatch must use
 * uocr_metal_context_generate_image_f16(), which keeps the final visual rows in
 * a reusable Metal final-feature buffer and binds that slice directly into prompt
 * assembly. These helpers deliberately copy results back to caller-owned host
 * buffers for parity probes only; profile markers make accidental production
 * use visible.
 */
static int scratch_slot_valid(uocr_metal_scratch_slot slot) {
    return slot >= UOCR_METAL_SCRATCH_VISION && slot < UOCR_METAL_SCRATCH_COUNT;
}

static const char *scratch_slot_name(uocr_metal_scratch_slot slot) {
    switch (slot) {
        case UOCR_METAL_SCRATCH_VISION:
            return "vision";
        case UOCR_METAL_SCRATCH_DECODER:
            return "decoder";
        case UOCR_METAL_SCRATCH_MOE:
            return "moe";
        case UOCR_METAL_SCRATCH_LOGITS:
            return "logits";
        case UOCR_METAL_SCRATCH_TRANSIENT:
            return "transient";
        case UOCR_METAL_SCRATCH_VISION_FINAL:
            return "vision-final";
        case UOCR_METAL_SCRATCH_LM_HEAD_LOGITS:
            return "lm-head-logits";
        default:
            return "unknown";
    }
}

static uocr_memory_category scratch_slot_memory_category(uocr_metal_scratch_slot slot) {
    switch (slot) {
        case UOCR_METAL_SCRATCH_VISION:
            return UOCR_MEMORY_VISION_GPU_WORKSPACE;
        case UOCR_METAL_SCRATCH_DECODER:
            return UOCR_MEMORY_DECODER_SCRATCH;
        case UOCR_METAL_SCRATCH_MOE:
            return UOCR_MEMORY_MOE_SCRATCH;
        case UOCR_METAL_SCRATCH_LOGITS:
            return UOCR_MEMORY_DECODER_SCRATCH;
        case UOCR_METAL_SCRATCH_TRANSIENT:
            return UOCR_MEMORY_TRANSIENT_BUFFERS;
        case UOCR_METAL_SCRATCH_VISION_FINAL:
            return UOCR_MEMORY_VISION_FINAL_FEATURES;
        case UOCR_METAL_SCRATCH_LM_HEAD_LOGITS:
            return UOCR_MEMORY_DECODER_SCRATCH;
        default:
            return UOCR_MEMORY_TRANSIENT_BUFFERS;
    }
}

static int scratch_capacity_for_request(uocr_metal_scratch_slot slot,
                                        uint64_t current_capacity,
                                        uint64_t min_length,
                                        uint64_t *out_capacity) {
    const uint64_t min_allocation = 4096u;
    uint64_t requested = 0u;
    if (!align_up_u64_checked(min_length, 256u, &requested)) {
        return 0;
    }
    if (requested < min_allocation) {
        requested = min_allocation;
    }

    /* Vision scratch is the public request-shaped workspace reported in memory
     * estimates.  Allocate it to the exact aligned request size on first use so
     * a fresh base request does not inherit the generic power-of-two slack used
     * for small transient/decoder scratch buffers.
     */
    if (slot == UOCR_METAL_SCRATCH_VISION || slot == UOCR_METAL_SCRATCH_VISION_FINAL) {
        *out_capacity = requested;
        return 1;
    }

    uint64_t capacity = current_capacity;
    if (capacity < min_allocation) {
        capacity = min_allocation;
    }
    while (capacity < requested) {
        if (capacity > UINT64_MAX / 2u) {
            capacity = requested;
            break;
        }
        capacity *= 2u;
    }
    *out_capacity = capacity;
    return 1;
}

static void metal_scratch_release_accounting(uocr_metal_context *ctx, uocr_metal_scratch_buffer *scratch) {
    if (ctx == NULL || scratch == NULL) {
        return;
    }
    metal_memory_release(ctx, scratch->primary_accounted_category, scratch->primary_accounted_bytes);
    metal_memory_release(ctx, scratch->secondary_accounted_category, scratch->secondary_accounted_bytes);
    scratch->primary_accounted_bytes = 0u;
    scratch->secondary_accounted_bytes = 0u;
    scratch->primary_accounted_category = UOCR_MEMORY_TRANSIENT_BUFFERS;
    scratch->secondary_accounted_category = UOCR_MEMORY_TRANSIENT_BUFFERS;
}

static int metal_scratch_reserve_accounting(uocr_metal_context *ctx,
                                            uocr_memory_category primary_category,
                                            uint64_t primary_bytes,
                                            uocr_memory_category secondary_category,
                                            uint64_t secondary_bytes,
                                            const char *label,
                                            char *error,
                                            size_t error_size) {
    if (!metal_memory_reserve(ctx, primary_category, primary_bytes, label, error, error_size)) {
        return 0;
    }
    if (!metal_memory_reserve(ctx, secondary_category, secondary_bytes, label, error, error_size)) {
        metal_memory_release(ctx, primary_category, primary_bytes);
        return 0;
    }
    return 1;
}

static int metal_scratch_rebalance_accounting(uocr_metal_context *ctx,
                                              uocr_metal_scratch_buffer *scratch,
                                              uocr_memory_category primary_category,
                                              uint64_t primary_bytes,
                                              uocr_memory_category secondary_category,
                                              uint64_t secondary_bytes,
                                              const char *label,
                                              char *error,
                                              size_t error_size) {
    if (scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal scratch accounting request");
    }
    if (scratch->primary_accounted_category == primary_category && scratch->primary_accounted_bytes == primary_bytes &&
        scratch->secondary_accounted_category == secondary_category && scratch->secondary_accounted_bytes == secondary_bytes) {
        return 1;
    }
    metal_scratch_release_accounting(ctx, scratch);
    if (!metal_scratch_reserve_accounting(ctx,
                                          primary_category,
                                          primary_bytes,
                                          secondary_category,
                                          secondary_bytes,
                                          label,
                                          error,
                                          error_size)) {
        return 0;
    }
    scratch->primary_accounted_category = primary_category;
    scratch->primary_accounted_bytes = primary_bytes;
    scratch->secondary_accounted_category = secondary_category;
    scratch->secondary_accounted_bytes = secondary_bytes;
    return 1;
}

static int metal_context_ensure_scratch_accounted(uocr_metal_context *ctx,
                                                  uocr_metal_scratch_slot slot,
                                                  uint64_t min_length,
                                                  int cpu_visible,
                                                  uocr_memory_category secondary_category,
                                                  uint64_t secondary_bytes,
                                                  char *error,
                                                  size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return metal_fail(error, error_size, "invalid Metal scratch buffer request");
    }
    if (min_length == 0u) {
        return 1;
    }
    if (min_length > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch request for %s is too large: %llu bytes",
                          scratch_slot_name(slot),
                          (unsigned long long)min_length);
    }

    uocr_metal_scratch_buffer *scratch = &ctx->scratch[slot];
    const int wants_cpu_visible = cpu_visible ? 1 : 0;
    const uocr_memory_category primary_category = scratch_slot_memory_category(slot);
    if (scratch->buffer != nil && scratch->capacity >= min_length && scratch->cpu_visible == wants_cpu_visible) {
        if (secondary_bytes > scratch->capacity) {
            return metal_fail(error,
                              error_size,
                              "Metal scratch accounting split for %s exceeds retained capacity",
                              scratch_slot_name(slot));
        }
        const uint64_t primary_bytes = scratch->capacity - secondary_bytes;
        if (!metal_scratch_rebalance_accounting(ctx,
                                                scratch,
                                                primary_category,
                                                primary_bytes,
                                                secondary_category,
                                                secondary_bytes,
                                                scratch_slot_name(slot),
                                                error,
                                                error_size)) {
            return 0;
        }
        if (scratch->high_watermark < min_length) {
            scratch->high_watermark = min_length;
        }
        return 1;
    }

    uint64_t new_capacity = 0u;
    if (!scratch_capacity_for_request(slot, scratch->capacity, min_length, &new_capacity) ||
        new_capacity > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch capacity overflow for %s request of %llu bytes",
                          scratch_slot_name(slot),
                          (unsigned long long)min_length);
    }
    if (secondary_bytes > new_capacity) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch accounting split for %s exceeds new capacity",
                          scratch_slot_name(slot));
    }
    const uint64_t primary_bytes = new_capacity - secondary_bytes;

    @autoreleasepool {
        const MTLResourceOptions storage_mode = wants_cpu_visible ? MTLResourceStorageModeShared : MTLResourceStorageModePrivate;
        id<MTLBuffer> buffer = metal_new_buffer_with_length(ctx, (NSUInteger)new_capacity, storage_mode);
        if (buffer == nil) {
            return metal_fail(error,
                              error_size,
                              "failed to allocate %s Metal scratch buffer with %llu bytes",
                              scratch_slot_name(slot),
                              (unsigned long long)new_capacity);
        }
        if (!metal_scratch_reserve_accounting(ctx,
                                              primary_category,
                                              primary_bytes,
                                              secondary_category,
                                              secondary_bytes,
                                              scratch_slot_name(slot),
                                              error,
                                              error_size)) {
            [buffer release];
            return 0;
        }
        buffer.label = [NSString stringWithFormat:@"uocr_scratch_%s", scratch_slot_name(slot)];
        if (slot != UOCR_METAL_SCRATCH_VISION_FINAL) {
            metal_clear_mps_workspace_ndarray_cache(ctx);
        }
        [scratch->buffer release];
        metal_scratch_release_accounting(ctx, scratch);
        scratch->buffer = buffer;
        scratch->capacity = new_capacity;
        scratch->cpu_visible = wants_cpu_visible;
        scratch->primary_accounted_category = primary_category;
        scratch->primary_accounted_bytes = primary_bytes;
        scratch->secondary_accounted_category = secondary_category;
        scratch->secondary_accounted_bytes = secondary_bytes;
        if (scratch->high_watermark < min_length) {
            scratch->high_watermark = min_length;
        }
    }
    return 1;
}

int uocr_metal_context_ensure_scratch(uocr_metal_context *ctx,
                                      uocr_metal_scratch_slot slot,
                                      uint64_t min_length,
                                      int cpu_visible,
                                      char *error,
                                      size_t error_size) {
    return metal_context_ensure_scratch_accounted(ctx,
                                                  slot,
                                                  min_length,
                                                  cpu_visible,
                                                  UOCR_MEMORY_TRANSIENT_BUFFERS,
                                                  0u,
                                                  error,
                                                  error_size);
}

void uocr_metal_context_release_scratch(uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return;
    }
    @autoreleasepool {
        uocr_metal_scratch_buffer *scratch = &ctx->scratch[slot];
        if (scratch->buffer != nil && slot != UOCR_METAL_SCRATCH_VISION_FINAL) {
            metal_clear_mps_workspace_ndarray_cache(ctx);
        }
        [scratch->buffer release];
        scratch->buffer = nil;
        scratch->capacity = 0u;
        scratch->cpu_visible = 0;
        metal_scratch_release_accounting(ctx, scratch);
    }
}

uint64_t uocr_metal_context_scratch_capacity(const uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return 0u;
    }
    return ctx->scratch[slot].capacity;
}

uint64_t uocr_metal_context_scratch_high_watermark(const uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return 0u;
    }
    return ctx->scratch[slot].high_watermark;
}

uint64_t uocr_metal_context_total_scratch_capacity(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->scratch[i].capacity, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

uint64_t uocr_metal_context_total_scratch_high_watermark(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->scratch[i].high_watermark, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

static void release_all_scratch(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        uocr_metal_context_release_scratch(ctx, (uocr_metal_scratch_slot)i);
    }
}

int uocr_metal_context_warmup_model_views(uocr_metal_context *ctx,
                                          uint64_t max_bytes_per_view,
                                          char *error,
                                          size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL) {
        return metal_fail(error, error_size, "Metal model-view warmup requires a context");
    }
    if (ctx->model_views == NULL || ctx->model_view_count == 0u) {
        return metal_fail(error, error_size, "Metal model-view warmup requires mapped model views");
    }

    long page_size_long = sysconf(_SC_PAGESIZE);
    if (page_size_long <= 0) {
        page_size_long = (long)UOCR_TENSOR_DATA_ALIGNMENT;
    }
    uint64_t stride_words_u64 = (uint64_t)page_size_long / sizeof(uint32_t);
    if (stride_words_u64 == 0u) {
        stride_words_u64 = 1u;
    }
    if (stride_words_u64 > UINT32_MAX) {
        return metal_fail(error, error_size, "Metal warmup page stride is too large");
    }
    const uint32_t stride_words = (uint32_t)stride_words_u64;

    uint64_t total_probe_count = 0u;
    uint64_t total_warmup_bytes = 0u;
    for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
        uint64_t bytes = ctx->model_views[i].length;
        if (max_bytes_per_view != 0u && bytes > max_bytes_per_view) {
            bytes = max_bytes_per_view;
        }
        const uint64_t words = bytes / sizeof(uint32_t);
        if (words == 0u) {
            continue;
        }
        if (words > UINT32_MAX) {
            return metal_fail(error, error_size, "Metal model-view warmup view %u is too large for u32 probe indexing", i);
        }
        const uint64_t probes = (words + (uint64_t)stride_words - 1u) / (uint64_t)stride_words;
        if (probes > UINT32_MAX || total_probe_count > (uint64_t)UINT32_MAX - probes) {
            return metal_fail(error, error_size, "Metal model-view warmup would need too many probe outputs");
        }
        if (!checked_add_u64(total_warmup_bytes, words * sizeof(uint32_t), &total_warmup_bytes)) {
            return metal_fail(error, error_size, "Metal model-view warmup byte count overflow");
        }
        total_probe_count += probes;
    }

    if (total_probe_count == 0u) {
        ctx->last_model_warmup_bytes = 0u;
        return 1;
    }
    const uint64_t output_bytes = total_probe_count * sizeof(uint32_t);
    if (!uocr_metal_context_ensure_scratch(ctx, UOCR_METAL_SCRATCH_TRANSIENT, output_bytes, 1, error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_touch_u32", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        id<MTLBuffer> dst = ctx->scratch[UOCR_METAL_SCRATCH_TRANSIENT].buffer;
        if (dst == nil || [dst contents] == NULL) {
            return metal_fail(error, error_size, "Metal model-view warmup has no CPU-visible scratch output");
        }
        memset([dst contents], 0, (size_t)output_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            return metal_fail(error, error_size, "failed to create Metal warmup command buffer");
        }
        cb.label = @"uocr_model_view_warmup_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal warmup command encoder");
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:dst offset:0u atIndex:1u];

        uint32_t dst_base = 0u;
        for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
            uint64_t bytes = ctx->model_views[i].length;
            if (max_bytes_per_view != 0u && bytes > max_bytes_per_view) {
                bytes = max_bytes_per_view;
            }
            const uint64_t words = bytes / sizeof(uint32_t);
            if (words == 0u) {
                continue;
            }
            const uint32_t probes = (uint32_t)((words + (uint64_t)stride_words - 1u) / (uint64_t)stride_words);
            uocr_metal_touch_params params;
            params.n_words = (uint32_t)words;
            params.stride_words = stride_words;
            params.dst_base = dst_base;
            params.reserved = 0u;

            [enc setBuffer:ctx->model_views[i].buffer offset:0u atIndex:0u];
            [enc setBytes:&params length:sizeof(params) atIndex:2u];

            NSUInteger threads_per_group = pipeline.threadExecutionWidth;
            if (threads_per_group == 0u) {
                threads_per_group = 1u;
            }
            if (threads_per_group > (NSUInteger)probes) {
                threads_per_group = (NSUInteger)probes;
            }
            [enc dispatchThreads:MTLSizeMake((NSUInteger)probes, 1u, 1u)
           threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
            dst_base += probes;
        }
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            return metal_fail(error, error_size, "Metal model-view warmup failed: %s", [description UTF8String]);
        }
    }

    ctx->last_model_warmup_bytes = total_warmup_bytes;
    metal_clear_error(error, error_size);
    return 1;
}

uint64_t uocr_metal_context_last_warmup_bytes(const uocr_metal_context *ctx) {
    return ctx != NULL ? ctx->last_model_warmup_bytes : 0u;
}

static int runtime_arena_slot_valid(uocr_metal_runtime_arena_slot slot) {
    return slot >= UOCR_METAL_ARENA_KV_CACHE && slot < UOCR_METAL_ARENA_COUNT;
}

static const char *runtime_arena_slot_name(uocr_metal_runtime_arena_slot slot) {
    switch (slot) {
        case UOCR_METAL_ARENA_KV_CACHE:
            return "kv-cache";
        case UOCR_METAL_ARENA_PROMPT_EMBEDDINGS:
            return "prompt-embeddings";
        case UOCR_METAL_ARENA_HIDDEN_PINGPONG:
            return "hidden-pingpong";
        case UOCR_METAL_ARENA_ROUTER_TOPK:
            return "router-topk";
        case UOCR_METAL_ARENA_MOE_INTERMEDIATE:
            return "moe-intermediate";
        case UOCR_METAL_ARENA_VISION_SCRATCH:
            return "vision-scratch";
        case UOCR_METAL_ARENA_LOGITS_READBACK:
            return "logits-readback";
        default:
            return "unknown";
    }
}

static int runtime_arena_is_cpu_visible(uocr_metal_runtime_arena_slot slot) {
    return slot == UOCR_METAL_ARENA_LOGITS_READBACK;
}

static int metal_init_kv_cache_layout(uint32_t batch_slots,
                                      uint32_t prompt_token_capacity,
                                      uocr_metal_kv_cache_layout *out_layout) {
    if (out_layout == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return 0;
    }

    uint64_t cache_token_capacity = 0u;
    uint64_t token_stride = 0u;
    uint64_t slot_stride = 0u;
    uint64_t layer_stride = 0u;
    uint64_t tensor_bytes = 0u;
    uint64_t total_bytes = 0u;
    if (!checked_add_u64((uint64_t)prompt_token_capacity,
                         (uint64_t)UOCR_GENERATED_RING_WINDOW,
                         &cache_token_capacity) ||
        cache_token_capacity > (uint64_t)UINT32_MAX ||
        !checked_mul_u64((uint64_t)UOCR_KV_HEADS, (uint64_t)UOCR_HEAD_DIM, &token_stride) ||
        !checked_mul_u64(token_stride, 2u, &token_stride) ||
        !checked_mul_u64(cache_token_capacity, token_stride, &slot_stride) ||
        !checked_mul_u64((uint64_t)batch_slots, slot_stride, &layer_stride) ||
        !checked_mul_u64((uint64_t)UOCR_DECODER_LAYERS, layer_stride, &tensor_bytes) ||
        !checked_mul_u64(tensor_bytes, 2u, &total_bytes)) {
        return 0;
    }

    memset(out_layout, 0, sizeof(*out_layout));
    out_layout->decoder_layers = UOCR_DECODER_LAYERS;
    out_layout->batch_slots = batch_slots;
    out_layout->prompt_token_capacity = prompt_token_capacity;
    out_layout->cache_token_capacity = (uint32_t)cache_token_capacity;
    out_layout->kv_heads = UOCR_KV_HEADS;
    out_layout->head_dim = UOCR_HEAD_DIM;
    out_layout->generated_ring_window = UOCR_GENERATED_RING_WINDOW;
    out_layout->token_stride_bytes = token_stride;
    out_layout->slot_stride_bytes = slot_stride;
    out_layout->layer_stride_bytes = layer_stride;
    out_layout->tensor_bytes = tensor_bytes;
    out_layout->k_offset_bytes = 0u;
    out_layout->v_offset_bytes = tensor_bytes;
    out_layout->total_bytes = total_bytes;
    return 1;
}

static int runtime_arena_capacities(uint32_t batch_slots,
                                    uint32_t prompt_token_capacity,
                                    uint64_t capacities[UOCR_METAL_ARENA_COUNT]) {
    if (capacities == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return UOCR_ERROR_INVALID_ARGUMENT;
    }
    memset(capacities, 0, (size_t)UOCR_METAL_ARENA_COUNT * sizeof(capacities[0]));

    int status = uocr_estimate_kv_cache_bytes(batch_slots, prompt_token_capacity, &capacities[UOCR_METAL_ARENA_KV_CACHE]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_prompt_embedding_bytes(batch_slots,
                                                  prompt_token_capacity,
                                                  &capacities[UOCR_METAL_ARENA_PROMPT_EMBEDDINGS]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_decoder_scratch_bytes(batch_slots,
                                                 prompt_token_capacity,
                                                 &capacities[UOCR_METAL_ARENA_HIDDEN_PINGPONG]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_moe_router_topk_bytes(batch_slots,
                                                 prompt_token_capacity,
                                                 &capacities[UOCR_METAL_ARENA_ROUTER_TOPK]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_moe_intermediate_bytes(batch_slots,
                                                  prompt_token_capacity,
                                                  &capacities[UOCR_METAL_ARENA_MOE_INTERMEDIATE]);
    if (status != UOCR_OK) {
        return status;
    }
    /* Vision workspace is request-shaped and grow-on-demand via
     * UOCR_METAL_SCRATCH_VISION.  Do not reserve a stale prompt-sized
     * runtime arena at engine open.
     */
    capacities[UOCR_METAL_ARENA_VISION_SCRATCH] = 0u;
    status = uocr_estimate_logits_readback_bytes(batch_slots, &capacities[UOCR_METAL_ARENA_LOGITS_READBACK]);
    if (status != UOCR_OK) {
        return status;
    }
    return UOCR_OK;
}

void uocr_metal_context_release_runtime_arenas(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    @autoreleasepool {
        int changed = ctx->prompt_token_ids_buffer != nil || ctx->has_kv_cache_layout != 0;
        metal_clear_mps_workspace_ndarray_cache(ctx);
        for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
            uocr_metal_runtime_arena *arena = &ctx->runtime_arenas[i];
            if (arena->buffer != nil || arena->capacity != 0u) {
                changed = 1;
            }
            [arena->buffer release];
            arena->buffer = nil;
            arena->capacity = 0u;
            arena->cpu_visible = 0;
        }
        [ctx->prompt_token_ids_buffer release];
        ctx->prompt_token_ids_buffer = nil;
        ctx->prompt_token_ids_capacity = 0u;
        ctx->prompt_token_ids_batch_slots = 0u;
        ctx->prompt_token_ids_prompt_capacity = 0u;
        memset(&ctx->kv_cache_layout, 0, sizeof(ctx->kv_cache_layout));
        ctx->has_kv_cache_layout = 0;
        ctx->has_integrated_prefill = 0;
        ctx->integrated_prefill_slot = 0u;
        ctx->integrated_prefill_tokens = 0u;
        ctx->integrated_prefill_final_segment = 0u;
        if (changed) {
            ++ctx->runtime_arena_generation;
        }
    }
}

int uocr_metal_context_allocate_runtime_arenas(uocr_metal_context *ctx,
                                               uint32_t batch_slots,
                                               uint32_t prompt_token_capacity,
                                               char *error,
                                               size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return metal_fail(error, error_size, "invalid Metal runtime arena allocation request");
    }
    if (ctx->active_command_buffer != nil) {
        return metal_fail(error,
                          error_size,
                          "Metal runtime arenas must be grown before command encoding; active command batch is in progress");
    }

    uint64_t capacities[UOCR_METAL_ARENA_COUNT];
    const int estimate_status = runtime_arena_capacities(batch_slots, prompt_token_capacity, capacities);
    if (estimate_status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "failed to estimate Metal runtime arena sizes: %s",
                          uocr_status_string(estimate_status));
    }

    uocr_metal_kv_cache_layout kv_layout;
    if (!metal_init_kv_cache_layout(batch_slots, prompt_token_capacity, &kv_layout) ||
        kv_layout.total_bytes != capacities[UOCR_METAL_ARENA_KV_CACHE]) {
        return metal_fail(error, error_size, "failed to build Metal KV cache layout");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (max_buffer_length == 0u) {
        return metal_fail(error, error_size, "Metal device reported maxBufferLength=0");
    }

    uocr_metal_context_release_runtime_arenas(ctx);
    @autoreleasepool {
        for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
            const uocr_metal_runtime_arena_slot slot = (uocr_metal_runtime_arena_slot)i;
            const uint64_t bytes = capacities[i];
            if (bytes == 0u) {
                continue;
            }
            if (bytes > max_buffer_length || bytes > (uint64_t)SIZE_MAX) {
                uocr_metal_context_release_runtime_arenas(ctx);
                return metal_fail(error,
                                  error_size,
                                  "Metal runtime arena %s needs %llu bytes, exceeding maxBufferLength %llu",
                                  runtime_arena_slot_name(slot),
                                  (unsigned long long)bytes,
                                  (unsigned long long)max_buffer_length);
            }
            const int cpu_visible = runtime_arena_is_cpu_visible(slot);
            const MTLResourceOptions storage_mode = cpu_visible ? MTLResourceStorageModeShared : MTLResourceStorageModePrivate;
            id<MTLBuffer> buffer = metal_new_buffer_with_length(ctx, (NSUInteger)bytes, storage_mode);
            if (buffer == nil) {
                uocr_metal_context_release_runtime_arenas(ctx);
                return metal_fail(error,
                                  error_size,
                                  "failed to allocate Metal runtime arena %s with %llu bytes",
                                  runtime_arena_slot_name(slot),
                                  (unsigned long long)bytes);
            }
            buffer.label = [NSString stringWithFormat:@"uocr_arena_%s", runtime_arena_slot_name(slot)];
            ctx->runtime_arenas[i].buffer = buffer;
            ctx->runtime_arenas[i].capacity = bytes;
            ctx->runtime_arenas[i].cpu_visible = cpu_visible;
        }
        uint64_t prompt_token_id_bytes = 0u;
        if (!checked_mul_u64((uint64_t)batch_slots, (uint64_t)prompt_token_capacity, &prompt_token_id_bytes) ||
            !checked_mul_u64(prompt_token_id_bytes, (uint64_t)sizeof(int32_t), &prompt_token_id_bytes) ||
            prompt_token_id_bytes > max_buffer_length || prompt_token_id_bytes > (uint64_t)SIZE_MAX) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error, error_size, "Metal prompt token-id arena byte-size overflow");
        }
        id<MTLBuffer> prompt_tokens = metal_new_buffer_with_length(ctx,
                                                                   (NSUInteger)prompt_token_id_bytes,
                                                                   MTLResourceStorageModeShared);
        if (prompt_tokens == nil) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error,
                              error_size,
                              "failed to allocate persistent Metal prompt token-id buffer with %llu bytes",
                              (unsigned long long)prompt_token_id_bytes);
        }
        prompt_tokens.label = @"uocr_persistent_prompt_token_ids";
        ctx->prompt_token_ids_buffer = prompt_tokens;
        ctx->prompt_token_ids_capacity = prompt_token_id_bytes;
        ctx->prompt_token_ids_batch_slots = batch_slots;
        ctx->prompt_token_ids_prompt_capacity = prompt_token_capacity;

        ctx->kv_cache_layout = kv_layout;
        ctx->has_kv_cache_layout = 1;
        ++ctx->runtime_arena_generation;
        if (!metal_prebuild_mps_runtime_workspace_ndarrays(ctx, prompt_token_capacity, error, error_size)) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return 0;
        }
    }
    return 1;
}

uint64_t uocr_metal_context_runtime_arena_capacity(const uocr_metal_context *ctx,
                                                   uocr_metal_runtime_arena_slot slot) {
    if (ctx == NULL || !runtime_arena_slot_valid(slot)) {
        return 0u;
    }
    return ctx->runtime_arenas[slot].capacity;
}

uint64_t uocr_metal_context_total_runtime_arena_capacity(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->runtime_arenas[i].capacity, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

uint32_t uocr_metal_context_runtime_arena_batch_slots(const uocr_metal_context *ctx) {
    return (ctx != NULL && ctx->has_kv_cache_layout) ? ctx->kv_cache_layout.batch_slots : 0u;
}

uint32_t uocr_metal_context_runtime_arena_prompt_token_capacity(const uocr_metal_context *ctx) {
    return (ctx != NULL && ctx->has_kv_cache_layout) ? ctx->kv_cache_layout.prompt_token_capacity : 0u;
}

int uocr_metal_context_get_kv_cache_layout(const uocr_metal_context *ctx,
                                           uocr_metal_kv_cache_layout *out_layout) {
    if (ctx == NULL || out_layout == NULL || !ctx->has_kv_cache_layout) {
        return 0;
    }
    *out_layout = ctx->kv_cache_layout;
    return 1;
}

int uocr_metal_kv_cache_offset(const uocr_metal_kv_cache_layout *layout,
                               int value_cache,
                               uint32_t layer,
                               uint32_t slot,
                               uint32_t cache_token,
                               uint32_t head,
                               uint32_t dim,
                               uint64_t *out_offset_bytes) {
    if (layout == NULL || out_offset_bytes == NULL || (value_cache != 0 && value_cache != 1) ||
        layout->total_bytes < 2u || layer >= layout->decoder_layers || slot >= layout->batch_slots ||
        cache_token >= layout->cache_token_capacity || head >= layout->kv_heads || dim >= layout->head_dim) {
        return 0;
    }

    uint64_t offset = value_cache ? layout->v_offset_bytes : layout->k_offset_bytes;
    uint64_t term = 0u;
    if (!checked_mul_u64((uint64_t)layer, layout->layer_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)slot, layout->slot_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)cache_token, layout->token_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)head, (uint64_t)layout->head_dim * 2u, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)dim, 2u, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        offset > layout->total_bytes - 2u) {
        return 0;
    }

    *out_offset_bytes = offset;
    return 1;
}

int uocr_metal_kv_cache_token_for_position(uint32_t prompt_length,
                                           uint32_t prompt_token_capacity,
                                           uint32_t position,
                                           uint32_t *out_cache_token) {
    if (out_cache_token == NULL || prompt_length == 0u || prompt_length > prompt_token_capacity ||
        position >= UOCR_MAX_POSITIONS) {
        return 0;
    }
    if (position < prompt_length) {
        *out_cache_token = position;
        return 1;
    }
    *out_cache_token = prompt_length + ((position - prompt_length) % UOCR_GENERATED_RING_WINDOW);
    return 1;
}

int uocr_metal_kv_cache_attention_length(uint32_t prompt_length,
                                         uint32_t generated_count,
                                         uint32_t *out_attention_length) {
    if (out_attention_length == NULL || prompt_length == 0u || prompt_length > UOCR_MAX_POSITIONS) {
        return 0;
    }
    const uint32_t live_generated = generated_count < UOCR_GENERATED_RING_WINDOW ? generated_count : UOCR_GENERATED_RING_WINDOW;
    if (prompt_length > UOCR_MAX_POSITIONS - live_generated) {
        return 0;
    }
    *out_attention_length = prompt_length + live_generated;
    return 1;
}

int uocr_metal_kv_cache_decode_attention_plan(uint32_t prompt_length,
                                             uint32_t prompt_token_capacity,
                                             uint32_t generated_count,
                                             uocr_metal_decode_attention_plan *out_plan) {
    if (out_plan == NULL || prompt_length == 0u || prompt_length > prompt_token_capacity ||
        prompt_length > UOCR_MAX_POSITIONS || generated_count > UOCR_MAX_POSITIONS - prompt_length) {
        return 0;
    }

    uint64_t cache_token_capacity = 0u;
    if (!checked_add_u64((uint64_t)prompt_token_capacity,
                         (uint64_t)UOCR_GENERATED_RING_WINDOW,
                         &cache_token_capacity) ||
        cache_token_capacity > (uint64_t)UINT32_MAX) {
        return 0;
    }

    uint32_t attention_length = 0u;
    if (!uocr_metal_kv_cache_attention_length(prompt_length, generated_count, &attention_length)) {
        return 0;
    }

    const uint32_t live_generated = generated_count < UOCR_GENERATED_RING_WINDOW ? generated_count : UOCR_GENERATED_RING_WINDOW;
    const uint32_t first_generated_index = generated_count - live_generated;
    const uint32_t first_generated_position = prompt_length + first_generated_index;
    const uint32_t query_position = generated_count == 0u ? prompt_length : prompt_length + generated_count - 1u;

    memset(out_plan, 0, sizeof(*out_plan));
    out_plan->prompt_length = prompt_length;
    out_plan->prompt_token_capacity = prompt_token_capacity;
    out_plan->cache_token_capacity = (uint32_t)cache_token_capacity;
    out_plan->generated_count = generated_count;
    out_plan->live_generated = live_generated;
    out_plan->first_generated_index = first_generated_index;
    out_plan->first_generated_position = first_generated_position;
    out_plan->query_position = query_position;
    out_plan->attention_length = attention_length;
    out_plan->generated_ring_window = UOCR_GENERATED_RING_WINDOW;
    return 1;
}

int uocr_metal_kv_cache_decode_position_allowed(const uocr_metal_decode_attention_plan *plan,
                                                uint32_t key_position) {
    if (plan == NULL || plan->prompt_length == 0u || plan->generated_ring_window != UOCR_GENERATED_RING_WINDOW ||
        key_position >= UOCR_MAX_POSITIONS) {
        return 0;
    }
    if (key_position < plan->prompt_length) {
        return 1;
    }
    if (plan->live_generated == 0u) {
        return 0;
    }
    return key_position >= plan->first_generated_position && key_position <= plan->query_position;
}

int uocr_metal_kv_cache_decode_attention_index_to_token(const uocr_metal_decode_attention_plan *plan,
                                                        uint32_t attention_index,
                                                        uint32_t *out_cache_token) {
    if (plan == NULL || out_cache_token == NULL || plan->prompt_length == 0u ||
        plan->generated_ring_window != UOCR_GENERATED_RING_WINDOW || attention_index >= plan->attention_length) {
        return 0;
    }
    if (attention_index < plan->prompt_length) {
        *out_cache_token = attention_index;
        return 1;
    }

    const uint32_t generated_offset = attention_index - plan->prompt_length;
    if (generated_offset >= plan->live_generated) {
        return 0;
    }
    const uint32_t logical_generated = plan->first_generated_index + generated_offset;
    const uint32_t cache_token = plan->prompt_length + (logical_generated % plan->generated_ring_window);
    if (cache_token >= plan->cache_token_capacity) {
        return 0;
    }
    *out_cache_token = cache_token;
    return 1;
}

int uocr_metal_kv_cache_token_for_attention_index(uint32_t prompt_length,
                                                  uint32_t prompt_token_capacity,
                                                  uint32_t generated_count,
                                                  uint32_t attention_index,
                                                  uint32_t *out_cache_token) {
    uocr_metal_decode_attention_plan plan;
    if (!uocr_metal_kv_cache_decode_attention_plan(prompt_length,
                                                   prompt_token_capacity,
                                                   generated_count,
                                                   &plan)) {
        return 0;
    }
    return uocr_metal_kv_cache_decode_attention_index_to_token(&plan, attention_index, out_cache_token);
}

static void metal_decoder_result_reset(uocr_metal_decoder_result_f16 *result) {
    if (result == NULL) {
        return;
    }
    result->generated_count = 0u;
    result->stopped_on_eos = 0u;
    result->last_token_id = UINT32_MAX;
    result->last_score_f32 = 0.0f;
    result->reserved0 = 0u;
}

static void metal_integrated_decoder_state_reset(uocr_metal_context *ctx, uint32_t slot) {
    if (ctx == NULL) {
        return;
    }
    ctx->has_integrated_prefill = 0;
    ctx->integrated_prefill_slot = slot;
    ctx->integrated_prefill_tokens = 0u;
    ctx->integrated_prefill_final_segment = 0u;
}

static int metal_decoder_runtime_arenas_ready(const uocr_metal_context *ctx) {
    if (ctx == NULL || !ctx->has_kv_cache_layout) {
        return 0;
    }
    return ctx->runtime_arenas[UOCR_METAL_ARENA_KV_CACHE].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_PROMPT_EMBEDDINGS].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_HIDDEN_PINGPONG].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_ROUTER_TOPK].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_MOE_INTERMEDIATE].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_LOGITS_READBACK].buffer != nil;
}

typedef struct uocr_metal_runtime_arena_guard {
    uint64_t generation;
    uint64_t capacity;
    uint32_t batch_slots;
    uint32_t prompt_token_capacity;
} uocr_metal_runtime_arena_guard;

typedef struct uocr_metal_hot_path_alloc_guard {
    uocr_alloc_guard core_alloc_guard;
    uint64_t scratch_capacity;
    uocr_metal_runtime_arena_guard runtime_arena;
} uocr_metal_hot_path_alloc_guard;

static uocr_metal_runtime_arena_guard metal_runtime_arena_guard_begin(const uocr_metal_context *ctx) {
    uocr_metal_runtime_arena_guard guard;
    guard.generation = ctx != NULL ? ctx->runtime_arena_generation : 0u;
    guard.capacity = uocr_metal_context_total_runtime_arena_capacity(ctx);
    guard.batch_slots = uocr_metal_context_runtime_arena_batch_slots(ctx);
    guard.prompt_token_capacity = uocr_metal_context_runtime_arena_prompt_token_capacity(ctx);
    return guard;
}

static int metal_runtime_arena_guard_end(const uocr_metal_context *ctx,
                                         const uocr_metal_runtime_arena_guard *guard,
                                         const char *label,
                                         char *error,
                                         size_t error_size) {
    if (ctx == NULL || guard == NULL) {
        return metal_fail(error, error_size, "invalid %s runtime-arena guard", label != NULL ? label : "Metal hot path");
    }
    const uint64_t generation = ctx->runtime_arena_generation;
    const uint64_t capacity = uocr_metal_context_total_runtime_arena_capacity(ctx);
    const uint32_t batch_slots = uocr_metal_context_runtime_arena_batch_slots(ctx);
    const uint32_t prompt_token_capacity = uocr_metal_context_runtime_arena_prompt_token_capacity(ctx);
    if (generation != guard->generation || capacity != guard->capacity || batch_slots != guard->batch_slots ||
        prompt_token_capacity != guard->prompt_token_capacity) {
        return metal_fail(error,
                          error_size,
                          "%s changed runtime arena state "
                          "(generation %llu->%llu, capacity %llu->%llu bytes, batch_slots %u->%u, prompt_capacity %u->%u)",
                          label != NULL ? label : "Metal hot path",
                          (unsigned long long)guard->generation,
                          (unsigned long long)generation,
                          (unsigned long long)guard->capacity,
                          (unsigned long long)capacity,
                          guard->batch_slots,
                          batch_slots,
                          guard->prompt_token_capacity,
                          prompt_token_capacity);
    }
    metal_profile_add_event_ms(ctx, "metal.runtime_arena_guard.no_growth", 0.0);
    return 1;
}

static uocr_metal_hot_path_alloc_guard metal_hot_path_alloc_guard_begin(const uocr_metal_context *ctx) {
    uocr_metal_hot_path_alloc_guard guard;
    guard.core_alloc_guard = uocr_alloc_guard_begin();
    guard.scratch_capacity = uocr_metal_context_total_scratch_capacity(ctx);
    guard.runtime_arena = metal_runtime_arena_guard_begin(ctx);
    return guard;
}

static int metal_hot_path_alloc_guard_end(const uocr_metal_context *ctx,
                                          const uocr_metal_hot_path_alloc_guard *guard,
                                          const char *label,
                                          char *error,
                                          size_t error_size) {
    if (ctx == NULL || guard == NULL) {
        return metal_fail(error, error_size, "invalid %s allocation guard", label != NULL ? label : "Metal hot path");
    }
    if (!uocr_alloc_guard_end_no_alloc(&guard->core_alloc_guard)) {
        return metal_fail(error,
                          error_size,
                          "%s allocated through the core allocator",
                          label != NULL ? label : "Metal hot path");
    }
    const uint64_t scratch_capacity = uocr_metal_context_total_scratch_capacity(ctx);
    if (scratch_capacity != guard->scratch_capacity) {
        return metal_fail(error,
                          error_size,
                          "%s grew Metal scratch capacity from %llu to %llu bytes",
                          label != NULL ? label : "Metal hot path",
                          (unsigned long long)guard->scratch_capacity,
                          (unsigned long long)scratch_capacity);
    }
    if (!metal_runtime_arena_guard_end(ctx, &guard->runtime_arena, label, error, error_size)) {
        return 0;
    }
    return 1;
}

