static int metal_run_packed_qkv_mps_f16(uocr_metal_context *ctx,
                                         uocr_metal_buffer_slice src,
                                         uocr_metal_buffer_slice packed_weight,
                                         uocr_metal_buffer_slice packed_bias,
                                         uocr_metal_buffer_slice q_dst,
                                         uocr_metal_buffer_slice k_dst,
                                         uocr_metal_buffer_slice v_dst,
                                         uint32_t rows,
                                         uint32_t hidden_size,
                                         const char *op_name,
                                         char *error,
                                         size_t error_size) {
    if (ctx == NULL || rows == 0u || hidden_size == 0u) {
        return metal_fail(error, error_size, "invalid %s MPS QKV request", op_name != NULL ? op_name : "Metal");
    }
    const uint32_t qkv_size = hidden_size * 3u;
    uint64_t qkv_values = 0u;
    uint64_t qkv_bytes = 0u;
    uint64_t weight_values = 0u;
    uint64_t weight_bytes = 0u;
    uint64_t bias_bytes = 0u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)qkv_size, &qkv_values) ||
        !metal_vision_f16_bytes(qkv_values, &qkv_bytes) ||
        !checked_mul_u64((uint64_t)qkv_size, (uint64_t)hidden_size, &weight_values) ||
        !metal_vision_f16_bytes(weight_values, &weight_bytes) ||
        !checked_mul_u64((uint64_t)qkv_size, 2u, &bias_bytes) ||
        qkv_bytes > (uint64_t)SIZE_MAX ||
        !metal_slice_valid(packed_weight, weight_bytes) ||
        !metal_slice_valid(packed_bias, bias_bytes)) {
        return metal_fail(error, error_size, "invalid %s fused MPS QKV sizes", op_name != NULL ? op_name : "Metal");
    }

    /*
     * Fused QKV: one MPS matmul  src @ Wqkv^T  →  temp [rows, 3*hidden],
     * then split into separate Q/K/V buffers.  This replaces 3 separate
     * MPS matmul calls (Q, K, V) with 1, cutting 2 dispatches per block.
     */
    @autoreleasepool {
        id<MTLBuffer> temp = metal_new_buffer_with_length(ctx, (NSUInteger)qkv_bytes, MTLResourceStorageModePrivate);
        if (temp == nil) {
            return metal_fail(error, error_size, "failed to allocate %s fused QKV temp buffer", op_name != NULL ? op_name : "Metal");
        }
        temp.label = @"uocr_qkv_fused_temp";

        uocr_metal_buffer_slice temp_slice = { temp, 0u };

        /* One fused MPS matmul:  src @ Wqkv^T  →  temp [rows, 3*hidden] */
        if (!metal_run_mps_matmul_nt_f16(ctx,
                                         src,
                                         packed_weight,
                                         temp_slice,
                                         rows,
                                         hidden_size,
                                         qkv_size,
                                         op_name,
                                         error,
                                         error_size)) {
            [temp release];
            return 0;
        }

        /* Bias add on the fused output */
        if (!metal_run_bias_add_f16_inplace(ctx,
                                            temp_slice,
                                            packed_bias,
                                            rows,
                                            qkv_size,
                                            op_name,
                                            error,
                                            error_size)) {
            [temp release];
            return 0;
        }

        /* Split kernel: temp → q_dst, k_dst, v_dst */
        {
            id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_split_qkv_f16", error, error_size);
            if (pipeline == nil) {
                [temp release];
                return 0;
            }
            int owned = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned, "Metal QKV split", error, error_size);
            if (cb == nil) {
                [temp release];
                return 0;
            }
            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                [temp release];
                return metal_fail(error, error_size, "failed to create %s QKV split encoder", op_name != NULL ? op_name : "Metal");
            }
            struct { uint32_t rows; uint32_t hidden_size; } split_params;
            split_params.rows = rows;
            split_params.hidden_size = hidden_size;
            [enc setComputePipelineState:pipeline];
            [enc setBuffer:temp offset:0u atIndex:0u];
            [enc setBuffer:q_dst.buffer offset:q_dst.offset atIndex:1u];
            [enc setBuffer:k_dst.buffer offset:k_dst.offset atIndex:2u];
            [enc setBuffer:v_dst.buffer offset:v_dst.offset atIndex:3u];
            [enc setBytes:&split_params length:sizeof(split_params) atIndex:4u];
            [enc dispatchThreads:MTLSizeMake((NSUInteger)hidden_size, (NSUInteger)rows, 1u)
           threadsPerThreadgroup:MTLSizeMake(32u, 1u, 1u)];
            [enc endEncoding];
            if (!metal_finish_command_buffer_for_op(ctx, cb, owned, "Metal QKV split", error, error_size)) {
                [temp release];
                return 0;
            }
        }

        [temp release];
    }
    return 1;
}

static const uocr_metal_decoder_binding *metal_require_decoder_binding_index(const uocr_metal_context *ctx,
                                                                             uint32_t binding_index,
                                                                             const char *label,
                                                                             char *error,
                                                                             size_t error_size) {
    const int profile_on = metal_profile_enabled(ctx);
    const uint64_t lookup_start_ns = profile_on ? uocr_profile_now_ns() : 0u;
    if (ctx == NULL || !ctx->decoder_bindings.valid || binding_index >= ctx->decoder_bindings.count) {
        (void)metal_fail(error, error_size, "missing cached decoder tensor for %s", label != NULL ? label : "binding");
        return NULL;
    }
    const uocr_metal_decoder_binding *binding = &ctx->decoder_bindings.tensors[binding_index];
    if (binding->buffer == nil) {
        (void)metal_fail(error,
                         error_size,
                         "cached decoder tensor for %s has no Metal buffer (id=%u)",
                         label != NULL ? label : "binding",
                         binding->tensor_id);
        return NULL;
    }
    if (profile_on) {
        metal_profile_add_event_now(ctx, "metal.decoder_binding_cache.direct_lookup", lookup_start_ns);
    }
    return binding;
}

static int metal_run_token_embedding_from_token_slot_f16(uocr_metal_context *ctx,
                                                         uocr_metal_buffer_slice token_id,
                                                         uocr_metal_buffer_slice dst,
                                                         char *error,
                                                         size_t error_size) {
    if (ctx == NULL || !metal_slice_valid(token_id, sizeof(int32_t)) ||
        !metal_slice_valid(dst, (uint64_t)UOCR_HIDDEN_SIZE * 2u)) {
        return metal_fail(error, error_size, "invalid integrated token-embedding request");
    }
    const uocr_metal_decoder_binding *embedding = metal_require_decoder_binding_index(ctx,
                                                                                      ctx->decoder_bindings.token_embedding,
                                                                                      "token embedding",
                                                                                      error,
                                                                                      error_size);
    if (embedding == NULL) {
        return 0;
    }
    const uint64_t table_f16_bytes = (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t table_qweight_bytes = uocr_q8_0_qweight_bytes(UOCR_VOCAB_SIZE, UOCR_HIDDEN_SIZE);
    const uint64_t table_qscale_bytes = uocr_q8_0_qscale_bytes(UOCR_VOCAB_SIZE,
                                                               UOCR_HIDDEN_SIZE,
                                                               UOCR_Q8_GROUP_SIZE_DEFAULT);
    if (embedding->qtype == UOCR_TENSOR_F16) {
        if (!metal_buffer_range_valid(embedding->buffer, embedding->offset, table_f16_bytes)) {
            return 0;
        }
    } else if (embedding->qtype == UOCR_TENSOR_Q8_0) {
        if (embedding->group_size != UOCR_Q8_GROUP_SIZE_DEFAULT || embedding->rows != UOCR_VOCAB_SIZE ||
            embedding->cols != UOCR_HIDDEN_SIZE || embedding->payload_size != table_qweight_bytes ||
            embedding->scale_size != table_qscale_bytes ||
            !metal_buffer_range_valid(embedding->buffer, embedding->offset, table_qweight_bytes) ||
            !metal_buffer_range_valid(embedding->scale_buffer, embedding->scale_offset, table_qscale_bytes)) {
            return metal_fail(error, error_size, "invalid integrated Q8 token-embedding binding");
        }
    } else {
        return metal_fail(error,
                          error_size,
                          "unsupported integrated token-embedding qtype %s",
                          uocr_tensor_qtype_name(embedding->qtype));
    }
    @autoreleasepool {
        const int use_q8 = embedding->qtype == UOCR_TENSOR_Q8_0;
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx,
                                                                  use_q8 ? "uocr_get_rows_q8_0_to_f16_h1280_g64"
                                                                         : "uocr_get_rows_f16_to_f16",
                                                                  error,
                                                                  error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated token embedding", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated token-embedding command encoder");
        }
        const NSUInteger dispatch_width = (NSUInteger)((UOCR_HIDDEN_SIZE + UOCR_METAL_HALF4_WIDTH - 1u) /
                                                       UOCR_METAL_HALF4_WIDTH);
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > dispatch_width) threads = dispatch_width;
        [enc setComputePipelineState:pipeline];
        if (use_q8) {
            uocr_metal_get_rows_q8_params params;
            memset(&params, 0, sizeof(params));
            params.table_rows = UOCR_VOCAB_SIZE;
            params.logical_width = UOCR_HIDDEN_SIZE;
            params.physical_width = UOCR_HIDDEN_SIZE;
            params.n_row_ids = 1u;
            params.row_size = UOCR_HIDDEN_SIZE;
            [enc setBuffer:embedding->buffer offset:embedding->offset atIndex:0u];
            [enc setBuffer:embedding->scale_buffer offset:embedding->scale_offset atIndex:1u];
            [enc setBuffer:token_id.buffer offset:token_id.offset atIndex:2u];
            [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
            [enc setBytes:&params length:sizeof(params) atIndex:4u];
        } else {
            uocr_metal_get_rows_params params;
            params.table_rows = UOCR_VOCAB_SIZE;
            params.row_width = UOCR_HIDDEN_SIZE;
            params.n_row_ids = 1u;
            params.reserved = 0u;
            [enc setBuffer:embedding->buffer offset:embedding->offset atIndex:0u];
            [enc setBuffer:token_id.buffer offset:token_id.offset atIndex:1u];
            [enc setBuffer:dst.buffer offset:dst.offset atIndex:2u];
            [enc setBytes:&params length:sizeof(params) atIndex:3u];
        }
        [enc dispatchThreads:MTLSizeMake(dispatch_width, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated token embedding", error, error_size);
    }
}

static int metal_run_lm_head_argmax_f16(uocr_metal_context *ctx,
                                        uocr_metal_buffer_slice input,
                                        uocr_metal_buffer_slice ban_flags,
                                        uint32_t banned_count,
                                        uocr_metal_buffer_slice partial_scores,
                                        uocr_metal_buffer_slice partial_ids,
                                        uint32_t partial_count,
                                        char *error,
                                        size_t error_size) {
    const uint64_t input_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t partial_bytes = 0u;
    const uint32_t expected_partials = (UOCR_VOCAB_SIZE + UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS - 1u) /
                                       UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS;
    if (ctx == NULL || partial_count != expected_partials ||
        !checked_mul_u64((uint64_t)partial_count, (uint64_t)sizeof(float), &partial_bytes) ||
        !metal_slice_valid(input, input_bytes) ||
        (banned_count != 0u && !metal_slice_valid(ban_flags, (uint64_t)UOCR_VOCAB_SIZE)) ||
        !metal_slice_valid(partial_scores, partial_bytes) || !metal_slice_valid(partial_ids, partial_bytes)) {
        return metal_fail(error, error_size, "invalid integrated fused LM-head argmax request");
    }
    const uocr_metal_decoder_binding *lm_head = metal_require_decoder_binding_index(ctx,
                                                                                    ctx->decoder_bindings.lm_head,
                                                                                    "LM head",
                                                                                    error,
                                                                                    error_size);
    if (lm_head == NULL || !metal_buffer_range_valid(lm_head->buffer, lm_head->offset, weight_bytes)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_decoder_shape_pipeline(ctx, "uocr_lm_head_argmax_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = (NSUInteger)UOCR_METAL_LM_HEAD_ARGMAX_THREADS;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads) {
            return metal_fail(error,
                              error_size,
                              "integrated fused LM-head argmax requires %u threads per threadgroup, device supports %llu",
                              UOCR_METAL_LM_HEAD_ARGMAX_THREADS,
                              (unsigned long long)pipeline.maxTotalThreadsPerThreadgroup);
        }
        const uint64_t sum_bytes = (uint64_t)threads * (uint64_t)sizeof(float);
        const uint64_t id_bytes = (uint64_t)threads * (uint64_t)sizeof(uint32_t);
        const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
        uint64_t tg_bytes = 0u;
        if (!checked_add_u64(sum_bytes, id_bytes, &tg_bytes) ||
            !checked_add_u64(tg_bytes, hidden_bytes, &tg_bytes) ||
            tg_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "integrated fused LM-head argmax threadgroup memory exceeds device limit");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated fused LM-head argmax", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated fused LM-head argmax encoder");
        }
        uocr_metal_lm_head_argmax_params params;
        params.vocab_size = UOCR_VOCAB_SIZE;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.tile_tokens = UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS;
        params.lanes_per_token = UOCR_METAL_LM_HEAD_ARGMAX_LANES_PER_TOKEN;
        params.banned_count = banned_count;
        params.partial_count = partial_count;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:lm_head->buffer offset:lm_head->offset atIndex:1u];
        [enc setBuffer:ban_flags.buffer offset:ban_flags.offset atIndex:2u];
        [enc setBuffer:partial_scores.buffer offset:partial_scores.offset atIndex:3u];
        [enc setBuffer:partial_ids.buffer offset:partial_ids.offset atIndex:4u];
        [enc setBytes:&params length:sizeof(params) atIndex:5u];
        [enc setThreadgroupMemoryLength:(NSUInteger)sum_bytes atIndex:0u];
        [enc setThreadgroupMemoryLength:(NSUInteger)id_bytes atIndex:1u];
        [enc setThreadgroupMemoryLength:(NSUInteger)hidden_bytes atIndex:2u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)partial_count, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated fused LM-head argmax", error, error_size);
    }
}

