                                        char *error,
                                        size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_rows * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (ctx == NULL || weight == NULL || n_rows == 0u || !metal_slice_valid(src, hidden_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) || !metal_buffer_range_valid(weight->buffer, weight->offset, UOCR_HIDDEN_SIZE * 2ull)) {
        return metal_fail(error, error_size, "invalid %s RMSNorm request", op_name);
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_decoder_shape_pipeline(ctx, "uocr_rmsnorm_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        if ((uint64_t)threads * sizeof(float) > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "%s RMSNorm threadgroup memory exceeds device limit", op_name);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s RMSNorm command encoder", op_name);
        }
        uocr_metal_rmsnorm_params params;
        params.n_rows = n_rows;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.eps = UOCR_RMS_NORM_EPS;
        params.reserved = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:src.buffer offset:src.offset atIndex:0u];
        [enc setBuffer:weight->buffer offset:weight->offset atIndex:1u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_rows, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

/* ──────────────────────────────────────────────────────────────────────────
 * Chunked decode: GPU-resident token generation
 *
 * Instead of commit/wait per token, we encode N decode steps into one
 * command batch and commit once.  The GPU chains token → next_token
 * internally without CPU readback until the chunk boundary.
 *
 * Each step in the chunk:
 *   1. selection: final_norm → lm_head → argmax
 *      writes token to chunk_token_slots[step]
 *   2. embed:     get_rows(chunk_token_slots[step]) → decode_input
 *   3. decode:    one decoder forward pass → new hidden state
 *
 * All operations use the active command batch; no commit/wait between steps.
 * ────────────────────────────────────────────────────────────────────────── */

#define UOCR_METAL_DECODE_CHUNK_SIZE 8u

/* Forward declarations needed by chunk decode (defined later in this file) */
static int metal_run_decoder_decode_one_f16(uocr_metal_context *ctx,
                                            uint32_t slot,
                                            uint32_t prompt_length,
                                            uint32_t generated_count_after_write,
                                            uint32_t generated_token_index,
                                            char *error,
                                            size_t error_size);

/**
 * Encode the selection kernel chain for one decode step into the active
 * command batch, writing the chosen token/score into chunk_token_slots[step]
 * and chunk_score_slots[step].  The hidden slice must point to the current
 * decoder hidden state (scratch segment 0).  This is the GPU-resident chunk
 * analogue that avoids the old per-token commit/wait/CPU-readback cycle.
 */
static int metal_encode_chunk_step_selection_f16(
    uocr_metal_context *ctx,
    uocr_metal_buffer_slice hidden,
    uocr_metal_buffer_slice norm_scratch,
    uocr_metal_buffer_slice selection_scratch,
    uocr_metal_buffer_slice chunk_token_out,   /* single int32 slot for this step */
    uocr_metal_buffer_slice chunk_score_out,   /* single float slot for this step */
    char *error,
    size_t error_size) {
    if (ctx == NULL ||
        !metal_slice_valid(hidden, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(norm_scratch, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(selection_scratch, metal_decode_selection_scratch_bytes_per_slot()) ||
        !metal_slice_valid(chunk_token_out, sizeof(int32_t)) ||
        !metal_slice_valid(chunk_score_out, sizeof(float))) {
        return metal_fail(error, error_size, "invalid chunk step selection request");
    }

    const uocr_metal_decoder_binding *final_norm =
        metal_require_decoder_binding_index(ctx, ctx->decoder_bindings.final_norm,
                                            "final norm", error, error_size);
    if (final_norm == NULL) return 0;

    uocr_metal_decode_selection_slices selection_slices;
    if (!metal_decode_selection_slices(selection_scratch, 0u, &selection_slices)) {
        return metal_fail(error, error_size, "chunk step selection scratch layout is invalid");
    }

    if (!metal_run_rmsnorm_buffer_f16(ctx, hidden, final_norm, 1u, norm_scratch,
                                      "chunk decode final RMSNorm", error, error_size)) {
        return 0;
    }

    const uocr_metal_decoder_binding *lm_head =
        metal_require_decoder_binding_index(ctx, ctx->decoder_bindings.lm_head,
                                            "LM head", error, error_size);
    if (lm_head == NULL) return 0;

    if (lm_head->qtype == UOCR_TENSOR_Q8_0) {
        if (metal_lm_head_backend_is_mps()) {
            metal_profile_add_event_now(ctx, "metal.lm_head.q8_forced_custom", uocr_profile_now_ns());
        }
        if (!metal_run_lm_head_argmax_q8_0(ctx, norm_scratch,
                                           selection_slices.partial_scores,
                                           selection_slices.partial_ids,
                                           selection_slices.partial_count,
                                           error, error_size)) {
            return 0;
        }
        if (!metal_run_argmax_pairs_to_token(ctx,
                                             selection_slices.partial_scores,
                                             selection_slices.partial_ids,
                                             selection_slices.partial_count,
                                             chunk_token_out,
                                             chunk_score_out,
                                             error, error_size)) {
            return 0;
        }
    } else if (metal_lm_head_backend_is_mps()) {
        uocr_metal_buffer_slice lm_head_logits;
        if (!metal_lm_head_logits_scratch_slice(ctx, 0u, &lm_head_logits)) {
            return metal_fail(error, error_size, "MPS chunk LM head: failed to get lm_head_logits slice");
        }
        uocr_metal_buffer_slice empty_ban_flags = { nil, 0u };
        if (!metal_run_lm_head_mps_path(ctx, norm_scratch, lm_head_logits, empty_ban_flags,
                                        chunk_token_out, chunk_score_out, error, error_size)) {
            return 0;
        }
    } else {
        /* Custom fused path */
        if (!metal_run_lm_head_argmax_f16(ctx, norm_scratch,
                                          selection_slices.ban_flags,
                                          0u,
                                          selection_slices.partial_scores,
                                          selection_slices.partial_ids,
                                          selection_slices.partial_count,
                                          error, error_size)) {
            return 0;
        }
        if (!metal_run_argmax_pairs_to_token(ctx,
                                             selection_slices.partial_scores,
                                             selection_slices.partial_ids,
                                             selection_slices.partial_count,
                                             chunk_token_out,
                                             chunk_score_out,
                                             error, error_size)) {
            return 0;
        }
    }
    return 1;
}

/**
 * Run a full chunk of decode steps GPU-resident.
 *
 * Encodes `chunk_size` sequential decode iterations into one command batch
 * with no CPU synchronization between steps.  After commit, reads back all
 * token/score results via the CPU-visible chunk buffer.
 *
 * Arguments:
 *   ctx                    – Metal context
 *   slot                   – batch slot
 *   prompt_length          – number of prompt tokens
 *   generated_before_chunk – tokens already generated before this chunk
 *   chunk_size             – number of decode steps in this chunk
 *   hidden                 – current hidden state (segment 0) before first step
 *   norm_scratch           – RMSNorm scratch segment
 *   selection_scratch      – logits/ban_flags scratch
 *   chunk_token_slots      – GPU buffer [chunk_size] int32, CPU-visible
 *   chunk_score_slots      – GPU buffer [chunk_size] float,  CPU-visible
 *   chunk_storage_bytes    – sizeof(chunk_token_slots + chunk_score_slots)
 *   error/error_size       – error output
 *
 * Returns 1 on success, 0 on error.
 */
static int metal_run_decoder_decode_chunk_f16(
    uocr_metal_context *ctx,
    uint32_t slot,
    uint32_t prompt_length,
    uint32_t generated_before_chunk,
    uint32_t chunk_size,
    uocr_metal_buffer_slice hidden,
    uocr_metal_buffer_slice norm_scratch,
    uocr_metal_buffer_slice selection_scratch,
    uocr_metal_buffer_slice chunk_token_slots,
    uocr_metal_buffer_slice chunk_score_slots,
    char *error,
    size_t error_size) {
    if (ctx == NULL || chunk_size == 0u || chunk_size > 128u ||
        !metal_slice_valid(hidden, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(norm_scratch, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(selection_scratch, metal_decode_selection_scratch_bytes_per_slot()) ||
        !metal_slice_valid(chunk_token_slots, (uint64_t)chunk_size * sizeof(int32_t)) ||
        !metal_slice_valid(chunk_score_slots, (uint64_t)chunk_size * sizeof(float))) {
        return metal_fail(error, error_size, "invalid chunk decode request");
    }

    /* Selection for step 0 reads the final prefill hidden.  Token embedding for
     * the selected token must be written to decoder segment 0, because
     * metal_run_decoder_decode_one_f16() always reads scratch[0].  After each
     * decode_one, its final-hidden copy also leaves the next selection hidden
     * in the same segment-0 slice. */
    uocr_metal_buffer_slice decode_input;
    uint64_t decode_input_bytes = 0u;
    if (!metal_hidden_arena_segment_slice(ctx, slot, 0u, 1u, &decode_input, &decode_input_bytes) ||
        decode_input_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
        return metal_fail(error, error_size, "chunk decode input segment is invalid");
    }
    uocr_metal_buffer_slice current_hidden = hidden;

    for (uint32_t step = 0u; step < chunk_size; ++step) {
        const uint64_t step_start_ns = uocr_profile_now_ns();

        /* 1. Selection: final_norm → lm_head → argmax
         *    Writes to chunk_token_slots[step], chunk_score_slots[step]. */
        {
            uocr_metal_buffer_slice token_out = chunk_token_slots;
            token_out.offset += (NSUInteger)((uint64_t)step * sizeof(int32_t));
            uocr_metal_buffer_slice score_out = chunk_score_slots;
            score_out.offset += (NSUInteger)((uint64_t)step * sizeof(float));

            if (!metal_encode_chunk_step_selection_f16(ctx,
                                                       current_hidden,
                                                       norm_scratch,
                                                       selection_scratch,
                                                       token_out,
                                                       score_out,
                                                       error, error_size)) {
                return 0;
            }
        }
        metal_profile_add_event_now(ctx, "metal.chunk.step.selection", step_start_ns);

        /* 2. Token embedding: get_rows from chunk_token_slots[step] → segment 0 */
        {
            uocr_metal_buffer_slice token_src = chunk_token_slots;
            token_src.offset += (NSUInteger)((uint64_t)step * sizeof(int32_t));
            if (!metal_run_token_embedding_from_token_slot_f16(ctx, token_src, decode_input,
                                                               error, error_size)) {
                return 0;
            }
        }
        metal_profile_add_event_now(ctx, "metal.chunk.step.embed", step_start_ns);

        /* 3. Decoder decode_one step.
         *    Reads from segment 0 (just filled by embedding), writes final
         *    output back to segment 0 via decode_one's internal final copy. */
        {
            const uint32_t generated_token_index = generated_before_chunk + step;
            const uint32_t generated_count_after = generated_token_index + 1u;
            if (!metal_run_decoder_decode_one_f16(ctx, slot, prompt_length,
                                                  generated_count_after,
                                                  generated_token_index,
                                                  error, error_size)) {
                return 0;
            }
        }
        metal_profile_add_event_now(ctx, "metal.chunk.step.decode", step_start_ns);
        metal_profile_add_event_now(ctx, "metal.chunk.step", step_start_ns);

        current_hidden = decode_input;
    }

    return 1;
}


static int metal_run_decode_rope_kv_write_one_f16(uocr_metal_context *ctx,
                                                   uocr_metal_buffer_slice q,
                                                   uocr_metal_buffer_slice k,
                                                   uocr_metal_buffer_slice v,
                                                   uint32_t layer,
                                                   uint32_t slot,
                                                   uint32_t prompt_length,
                                                   uint32_t position,
                                                   char *error,
                                                   size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (ctx == NULL || !ctx->has_kv_cache_layout || layer >= UOCR_DECODER_LAYERS ||
        slot >= ctx->kv_cache_layout.batch_slots || prompt_length == 0u ||
        prompt_length > ctx->kv_cache_layout.prompt_token_capacity ||
        !metal_slice_valid(q, hidden_bytes) || !metal_slice_valid(k, hidden_bytes) ||
        !metal_slice_valid(v, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid decode RoPE+KV-write request");
    }
    if (position > UOCR_MAX_POSITIONS) {
        return metal_fail(error, error_size, "decode RoPE+KV-write position exceeds max");
    }
    id<MTLBuffer> kv = ctx->runtime_arenas[UOCR_METAL_ARENA_KV_CACHE].buffer;
    if (!metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.k_offset_bytes, ctx->kv_cache_layout.tensor_bytes) ||
        !metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.v_offset_bytes, ctx->kv_cache_layout.tensor_bytes)) {
        return metal_fail(error, error_size, "decode RoPE+KV-write KV cache arena is invalid");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_decoder_shape_pipeline(ctx, "uocr_decode_rope_kv_write_one_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "decode RoPE+KV-write", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create decode RoPE+KV-write command encoder");
        }
        uocr_metal_decode_rope_kv_write_params params;
        params.heads = UOCR_ATTENTION_HEADS;
        params.head_dim = UOCR_HEAD_DIM;
        params.position = position;
        params.freq_scale = -2.0f * log2f((float)UOCR_ROPE_THETA) / (float)UOCR_HEAD_DIM;
        params.batch_slots = ctx->kv_cache_layout.batch_slots;
        params.cache_token_capacity = ctx->kv_cache_layout.cache_token_capacity;
        params.layer = layer;
        params.slot = slot;
        params.prompt_length = prompt_length;
        params.ring_window = UOCR_GENERATED_RING_WINDOW;
        params.reserved[0] = 0u;
        params.reserved[1] = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.k_offset_bytes atIndex:3u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.v_offset_bytes atIndex:4u];
        [enc setBytes:&params length:sizeof(params) atIndex:5u];
        const NSUInteger total_threads = (NSUInteger)UOCR_ATTENTION_HEADS * (NSUInteger)(UOCR_HEAD_DIM / 2u);
        [enc dispatchThreads:MTLSizeMake(total_threads, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "decode RoPE+KV-write", error, error_size);
    }
}

static int metal_run_attention_qkv_buffer_q8_0(uocr_metal_context *ctx,
                                              uocr_metal_buffer_slice src,
                                              const uocr_metal_decoder_binding *q_weight,
                                              const uocr_metal_decoder_binding *k_weight,
                                              const uocr_metal_decoder_binding *v_weight,
                                              uint32_t n_tokens,
                                              uocr_metal_buffer_slice q_dst,
                                              uocr_metal_buffer_slice k_dst,
                                              uocr_metal_buffer_slice v_dst,
                                              char *error,
                                              size_t error_size);

static int metal_run_attention_output_residual_q8_0(uocr_metal_context *ctx,
                                                     uocr_metal_buffer_slice context,
                                                     const uocr_metal_decoder_binding *o_weight,
                                                     uocr_metal_buffer_slice residual,
                                                     uint32_t n_tokens,
                                                     uocr_metal_buffer_slice dst,
                                                     const char *op_name,
                                                     char *error,
                                                     size_t error_size);

static int metal_run_decode_attention_qkv_one_f16(uocr_metal_context *ctx,
                                                   uocr_metal_buffer_slice src,
                                                   const uocr_metal_decoder_binding *q_weight,
                                                   const uocr_metal_decoder_binding *k_weight,
                                                   const uocr_metal_decoder_binding *v_weight,
                                                   uocr_metal_buffer_slice q_dst,
                                                   uocr_metal_buffer_slice k_dst,
                                                   uocr_metal_buffer_slice v_dst,
                                                   char *error,
                                                   size_t error_size) {
    if (ctx == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL) {
        return metal_fail(error, error_size, "invalid decode attention QKV request");
    }
    if (q_weight->qtype == UOCR_TENSOR_Q8_0 && k_weight->qtype == UOCR_TENSOR_Q8_0 &&
        v_weight->qtype == UOCR_TENSOR_Q8_0) {
        return metal_run_attention_qkv_buffer_q8_0(ctx,
                                                  src,
                                                  q_weight,
                                                  k_weight,
                                                  v_weight,
                                                  1u,
                                                  q_dst,
                                                  k_dst,
                                                  v_dst,
                                                  error,
                                                  error_size);
    }
    const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid(src, hidden_bytes) || !metal_slice_valid(q_dst, hidden_bytes) ||
        !metal_slice_valid(k_dst, hidden_bytes) || !metal_slice_valid(v_dst, hidden_bytes) ||
        !metal_buffer_range_valid(q_weight->buffer, q_weight->offset, weight_bytes) ||
        !metal_buffer_range_valid(k_weight->buffer, k_weight->offset, weight_bytes) ||
        !metal_buffer_range_valid(v_weight->buffer, v_weight->offset, weight_bytes)) {
        return metal_fail(error, error_size, "invalid decode attention QKV request");
    }
    uint64_t output_values = (uint64_t)UOCR_HIDDEN_SIZE * 3u;
    if (output_values > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "decode attention QKV dispatch size overflow");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_decoder_shape_pipeline(ctx, "uocr_attention_qkvo_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "decode attention QKV", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create decode attention QKV command encoder");
        }
        uocr_metal_attention_projection_params params;
        params.n_tokens = 1u;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.projection_count = 3u;
        params.reserved = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:src.buffer offset:src.offset atIndex:0u];
        [enc setBuffer:q_weight->buffer offset:q_weight->offset atIndex:1u];
        [enc setBuffer:k_weight->buffer offset:k_weight->offset atIndex:2u];
        [enc setBuffer:v_weight->buffer offset:v_weight->offset atIndex:3u];
        [enc setBuffer:q_weight->buffer offset:q_weight->offset atIndex:4u];
        [enc setBuffer:q_dst.buffer offset:q_dst.offset atIndex:5u];
        [enc setBuffer:k_dst.buffer offset:k_dst.offset atIndex:6u];
        [enc setBuffer:v_dst.buffer offset:v_dst.offset atIndex:7u];
        [enc setBuffer:q_dst.buffer offset:q_dst.offset atIndex:8u];
        [enc setBytes:&params length:sizeof(params) atIndex:9u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)output_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "decode attention QKV", error, error_size);
    }
}

static int metal_run_attention_output_residual_q8_0(uocr_metal_context *ctx,
                                                     uocr_metal_buffer_slice context,
                                                     const uocr_metal_decoder_binding *o_weight,
                                                     uocr_metal_buffer_slice residual,
                                                     uint32_t n_tokens,
                                                     uocr_metal_buffer_slice dst,
                                                     const char *op_name,
                                                     char *error,
                                                     size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal Q8 attention output";
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = uocr_q8_0_qweight_bytes(UOCR_HIDDEN_SIZE, UOCR_HIDDEN_SIZE);
    const uint64_t scale_bytes = uocr_q8_0_qscale_bytes(UOCR_HIDDEN_SIZE, UOCR_HIDDEN_SIZE, UOCR_Q8_GROUP_SIZE_DEFAULT);
    uint64_t output_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || o_weight == NULL || n_tokens == 0u ||
        o_weight->qtype != UOCR_TENSOR_Q8_0 || o_weight->rows != UOCR_HIDDEN_SIZE ||
        o_weight->cols != UOCR_HIDDEN_SIZE || o_weight->group_size != UOCR_Q8_GROUP_SIZE_DEFAULT ||
        o_weight->payload_size != weight_bytes || o_weight->scale_size != scale_bytes ||
        !metal_slice_valid(context, hidden_bytes) || !metal_slice_valid(residual, hidden_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) ||
        !metal_buffer_range_valid(o_weight->buffer, o_weight->offset, weight_bytes) ||
        !metal_buffer_range_valid(o_weight->scale_buffer, o_weight->scale_offset, scale_bytes) ||
        output_values > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }
    if (n_tokens > 1u) {
        /* Prefill: tiled GEMM with residual epilogue; the GEMV kernel below is
         * decode-only. */
        @autoreleasepool {
            id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_decoder_gemm_residual_q8_0_to_f16", error, error_size);
            if (pipeline == nil) {
                return 0;
            }
            int owned_command_buffer = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
            if (cb == nil) {
                return 0;
            }
            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create %s GEMM encoder", op);
            }
            uocr_metal_decoder_gemm_q8_params params;
            memset(&params, 0, sizeof(params));
            params.m = n_tokens;
            params.k = UOCR_HIDDEN_SIZE;
            params.n = UOCR_HIDDEN_SIZE;
            params.groups_per_row = UOCR_HIDDEN_SIZE / UOCR_Q8_GROUP_SIZE_DEFAULT;
            params.has_residual = 1u;
            [enc setComputePipelineState:pipeline];
            [enc setBuffer:context.buffer offset:context.offset atIndex:0u];
            [enc setBuffer:o_weight->buffer offset:o_weight->offset atIndex:1u];
            [enc setBuffer:o_weight->scale_buffer offset:o_weight->scale_offset atIndex:2u];
            [enc setBuffer:residual.buffer offset:residual.offset atIndex:3u];
            [enc setBuffer:dst.buffer offset:dst.offset atIndex:4u];
            [enc setBytes:&params length:sizeof(params) atIndex:5u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)(UOCR_HIDDEN_SIZE / UOCR_METAL_GEMM_Q8_BN),
                                                  ((NSUInteger)n_tokens + UOCR_METAL_GEMM_Q8_BM - 1u) / UOCR_METAL_GEMM_Q8_BM,
                                                  1u)
                threadsPerThreadgroup:MTLSizeMake(UOCR_METAL_GEMM_Q8_THREADS, 1u, 1u)];
            [enc endEncoding];
            return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size);
        }
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_attention_output_residual_q8_0_to_f16_h1280_g64", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s command encoder", op);
        }
        uocr_metal_attention_output_q8_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.group_size = UOCR_Q8_GROUP_SIZE_DEFAULT;
        params.groups_per_row = UOCR_HIDDEN_SIZE / UOCR_Q8_GROUP_SIZE_DEFAULT;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:context.buffer offset:context.offset atIndex:0u];
        [enc setBuffer:o_weight->buffer offset:o_weight->offset atIndex:1u];
        [enc setBuffer:o_weight->scale_buffer offset:o_weight->scale_offset atIndex:2u];
        [enc setBuffer:residual.buffer offset:residual.offset atIndex:3u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:4u];
        [enc setBytes:&params length:sizeof(params) atIndex:5u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)output_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size);
    }
}

static int metal_run_decode_attention_output_one_f16(uocr_metal_context *ctx,
