        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_ATTENTION_HEADS * (UOCR_HEAD_DIM / 2u), &pair_threads) ||
        pair_threads > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "invalid integrated RoPE request");
    }
