                                                          uocr_metal_buffer_slice dst,
                                                          char *error,
                                                          size_t error_size) {
    if (ctx == NULL || o_weight == NULL || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid integrated attention output request");
    }
    if (o_weight->qtype == UOCR_TENSOR_Q8_0) {
        return metal_run_attention_output_residual_q8_0(ctx,
                                                       context,
                                                       o_weight,
                                                       residual,
                                                       n_tokens,
                                                       dst,
                                                       "integrated attention output Q8",
                                                       error,
                                                       error_size);
    }
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t output_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (!metal_slice_valid(context, hidden_bytes) ||
        !metal_slice_valid(residual, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes) ||
        !metal_buffer_range_valid(o_weight->buffer, o_weight->offset, weight_bytes) || output_values > UINT32_MAX) {
        return metal_fail(error, error_size, "invalid integrated attention output request");
    }
    uocr_metal_buffer_slice weight_slice = { o_weight->buffer, o_weight->offset };
    return metal_run_mps_matmul_nt_f16(ctx,
                                       context,
                                       weight_slice,
                                       dst,
                                       n_tokens,
                                       UOCR_HIDDEN_SIZE,
                                       UOCR_HIDDEN_SIZE,
                                       "integrated attention output MPS matmul",
                                       error,
                                       error_size) &&
           metal_run_residual_add_f16(ctx,
                                      dst,
                                      residual,
                                      dst,
                                      (uint32_t)output_values,
                                      "integrated attention output MPS residual add",
                                      error,
                                      error_size);
}

static int metal_run_dense_swiglu_buffer_q8_0(uocr_metal_context *ctx,
                                             uocr_metal_buffer_slice input,
                                             const uocr_metal_decoder_binding *gate_weight,
                                             const uocr_metal_decoder_binding *up_weight,
                                             const uocr_metal_decoder_binding *down_weight,
                                             uocr_metal_buffer_slice residual,
                                             int has_residual,
                                             uint32_t n_tokens,
                                             uint32_t intermediate_size,
                                             uocr_metal_buffer_slice mid,
                                             uocr_metal_buffer_slice dst,
                                             const char *op_name,
                                             char *error,
                                             size_t error_size);

static int metal_run_dense_swiglu_buffer_q8_0(uocr_metal_context *ctx,
                                             uocr_metal_buffer_slice input,
                                             const uocr_metal_decoder_binding *gate_weight,
                                             const uocr_metal_decoder_binding *up_weight,
                                             const uocr_metal_decoder_binding *down_weight,
                                             uocr_metal_buffer_slice residual,
                                             int has_residual,
                                             uint32_t n_tokens,
                                             uint32_t intermediate_size,
                                             uocr_metal_buffer_slice mid,
                                             uocr_metal_buffer_slice dst,
                                             const char *op_name,
                                             char *error,
                                             size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal Q8 SwiGLU";
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t gate_qweight_bytes = uocr_q8_0_qweight_bytes(intermediate_size, UOCR_HIDDEN_SIZE);
    const uint64_t gate_qscale_bytes = uocr_q8_0_qscale_bytes(intermediate_size, UOCR_HIDDEN_SIZE, UOCR_Q8_GROUP_SIZE_DEFAULT);
    const uint64_t down_qweight_bytes = uocr_q8_0_qweight_bytes(UOCR_HIDDEN_SIZE, intermediate_size);
    const uint64_t down_qscale_bytes = uocr_q8_0_qscale_bytes(UOCR_HIDDEN_SIZE, intermediate_size, UOCR_Q8_GROUP_SIZE_DEFAULT);
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)intermediate_size * 2u;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)intermediate_size;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;

    if (ctx == NULL || gate_weight == NULL || up_weight == NULL || down_weight == NULL || n_tokens == 0u ||
        intermediate_size == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        gate_weight->qtype != UOCR_TENSOR_Q8_0 || up_weight->qtype != UOCR_TENSOR_Q8_0 ||
        down_weight->qtype != UOCR_TENSOR_Q8_0 ||
        gate_weight->payload_size != gate_qweight_bytes || gate_weight->scale_size != gate_qscale_bytes ||
        up_weight->payload_size != gate_qweight_bytes || up_weight->scale_size != gate_qscale_bytes ||
        down_weight->payload_size != down_qweight_bytes || down_weight->scale_size != down_qscale_bytes ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(mid, mid_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) || (has_residual && !metal_slice_valid(residual, hidden_bytes)) ||
        !metal_buffer_range_valid(gate_weight->buffer, gate_weight->offset, gate_qweight_bytes) ||
        !metal_buffer_range_valid(gate_weight->scale_buffer, gate_weight->scale_offset, gate_qscale_bytes) ||
        !metal_buffer_range_valid(up_weight->buffer, up_weight->offset, gate_qweight_bytes) ||
        !metal_buffer_range_valid(up_weight->scale_buffer, up_weight->scale_offset, gate_qscale_bytes) ||
        !metal_buffer_range_valid(down_weight->buffer, down_weight->offset, down_qweight_bytes) ||
        !metal_buffer_range_valid(down_weight->scale_buffer, down_weight->scale_offset, down_qscale_bytes)) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    const uint32_t groups_per_row_hidden = UOCR_HIDDEN_SIZE / UOCR_Q8_GROUP_SIZE_DEFAULT;
    const uint32_t groups_per_row_inter = intermediate_size / UOCR_Q8_GROUP_SIZE_DEFAULT;

    if (n_tokens > 1u && (intermediate_size % UOCR_METAL_GEMM_Q8_BN) == 0u) {
        /* Prefill: fused gate/up tiled GEMM + down tiled GEMM with residual;
         * the per-output GEMV kernels below are decode-only. */
        @autoreleasepool {
            id<MTLComputePipelineState> gate_pipeline = metal_get_pipeline(ctx, "uocr_decoder_swiglu_gate_up_gemm_q8_0_to_f16", error, error_size);
            id<MTLComputePipelineState> down_pipeline = metal_get_pipeline(ctx, "uocr_decoder_gemm_residual_q8_0_to_f16", error, error_size);
            if (gate_pipeline == nil || down_pipeline == nil) {
                return 0;
            }
            int owned_command_buffer = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
            if (cb == nil) {
                return 0;
            }
            const NSUInteger row_tiles = ((NSUInteger)n_tokens + UOCR_METAL_GEMM_Q8_BM - 1u) / UOCR_METAL_GEMM_Q8_BM;

            uocr_metal_decoder_gemm_q8_params gate_params;
            memset(&gate_params, 0, sizeof(gate_params));
            gate_params.m = n_tokens;
            gate_params.k = UOCR_HIDDEN_SIZE;
            gate_params.n = intermediate_size;
            gate_params.groups_per_row = groups_per_row_hidden;

            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create %s gate/up GEMM encoder", op);
            }
            [enc setComputePipelineState:gate_pipeline];
            [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
            [enc setBuffer:gate_weight->buffer offset:gate_weight->offset atIndex:1u];
            [enc setBuffer:up_weight->buffer offset:up_weight->offset atIndex:2u];
            [enc setBuffer:gate_weight->scale_buffer offset:gate_weight->scale_offset atIndex:3u];
            [enc setBuffer:up_weight->scale_buffer offset:up_weight->scale_offset atIndex:4u];
            [enc setBuffer:mid.buffer offset:mid.offset atIndex:5u];
            [enc setBytes:&gate_params length:sizeof(gate_params) atIndex:6u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)(intermediate_size / UOCR_METAL_GEMM_Q8_BN), row_tiles, 1u)
                threadsPerThreadgroup:MTLSizeMake(UOCR_METAL_GEMM_Q8_THREADS, 1u, 1u)];
            [enc endEncoding];

            uocr_metal_decoder_gemm_q8_params down_params;
            memset(&down_params, 0, sizeof(down_params));
            down_params.m = n_tokens;
            down_params.k = intermediate_size;
            down_params.n = UOCR_HIDDEN_SIZE;
            down_params.groups_per_row = groups_per_row_inter;
            down_params.has_residual = has_residual ? 1u : 0u;

            enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create %s down GEMM encoder", op);
            }
            [enc setComputePipelineState:down_pipeline];
            [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
            [enc setBuffer:down_weight->buffer offset:down_weight->offset atIndex:1u];
            [enc setBuffer:down_weight->scale_buffer offset:down_weight->scale_offset atIndex:2u];
            [enc setBuffer:(has_residual ? residual.buffer : input.buffer)
                    offset:(has_residual ? residual.offset : input.offset)
                   atIndex:3u];
            [enc setBuffer:dst.buffer offset:dst.offset atIndex:4u];
            [enc setBytes:&down_params length:sizeof(down_params) atIndex:5u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)(UOCR_HIDDEN_SIZE / UOCR_METAL_GEMM_Q8_BN), row_tiles, 1u)
                threadsPerThreadgroup:MTLSizeMake(UOCR_METAL_GEMM_Q8_THREADS, 1u, 1u)];
            [enc endEncoding];
            return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size);
        }
    }

    @autoreleasepool {
        /* Decode path: per-output GEMV kernels (n_tokens == 1). */
        id<MTLComputePipelineState> gate_pipeline = metal_get_decoder_shape_pipeline(ctx,
                                                                                     "uocr_dense_swiglu_gate_up_q8_0_to_f16",
                                                                                     error,
                                                                                     error_size);
        if (gate_pipeline == nil) {
            return 0;
        }
        id<MTLComputePipelineState> down_pipeline = metal_get_decoder_shape_pipeline(ctx, "uocr_dense_swiglu_down_q8_0_to_f16", error, error_size);
        if (down_pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
        if (cb == nil) {
            return 0;
        }

        uocr_metal_dense_swiglu_q8_params gate_params;
        gate_params.n_tokens = n_tokens;
        gate_params.hidden_size = UOCR_HIDDEN_SIZE;
        gate_params.intermediate_size = intermediate_size;
        gate_params.has_residual = has_residual ? 1u : 0u;
        gate_params.group_size = UOCR_Q8_GROUP_SIZE_DEFAULT;
        gate_params.groups_per_row = groups_per_row_hidden;
        gate_params.reserved0 = 0u;
        gate_params.reserved1 = 0u;

        uocr_metal_dense_swiglu_q8_params down_params = gate_params;
        down_params.groups_per_row = groups_per_row_inter;

        /* gate + up → mid */
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s gate/up command encoder", op);
        }
        const NSUInteger gate_threads = metal_power2_threadgroup_width(64u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:gate_weight->buffer offset:gate_weight->offset atIndex:1u];
        [enc setBuffer:up_weight->buffer offset:up_weight->offset atIndex:2u];
        [enc setBuffer:gate_weight->scale_buffer offset:gate_weight->scale_offset atIndex:3u];
        [enc setBuffer:up_weight->scale_buffer offset:up_weight->scale_offset atIndex:4u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:5u];
        [enc setBytes:&gate_params length:sizeof(gate_params) atIndex:6u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)gate_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        /* down → dst (+ residual) */
        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s down command encoder", op);
        }
        const NSUInteger down_threads = metal_power2_threadgroup_width(256u, down_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:down_pipeline];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
        [enc setBuffer:down_weight->buffer offset:down_weight->offset atIndex:1u];
        [enc setBuffer:down_weight->scale_buffer offset:down_weight->scale_offset atIndex:2u];
        [enc setBuffer:(has_residual ? residual.buffer : input.buffer) offset:(has_residual ? residual.offset : input.offset) atIndex:3u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:4u];
        [enc setBytes:&down_params length:sizeof(down_params) atIndex:5u];
        [enc setThreadgroupMemoryLength:down_threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)down_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(down_threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size);
    }
}

static int metal_run_dense_swiglu_buffer_f16(uocr_metal_context *ctx,
                                             uocr_metal_buffer_slice input,
                                             const uocr_metal_decoder_binding *gate_weight,
                                             const uocr_metal_decoder_binding *up_weight,
                                             const uocr_metal_decoder_binding *down_weight,
                                             uocr_metal_buffer_slice residual,
                                             int has_residual,
                                             uint32_t n_tokens,
                                             uint32_t intermediate_size,
                                             uocr_metal_buffer_slice mid,
                                             uocr_metal_buffer_slice dst,
                                             const char *op_name,
                                             char *error,
                                             size_t error_size) {
    if (ctx == NULL || gate_weight == NULL || up_weight == NULL || down_weight == NULL || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s SwiGLU request", op_name);
    }
    if (gate_weight->qtype == UOCR_TENSOR_Q8_0 && up_weight->qtype == UOCR_TENSOR_Q8_0 &&
        down_weight->qtype == UOCR_TENSOR_Q8_0) {
        return metal_run_dense_swiglu_buffer_q8_0(ctx, input, gate_weight, up_weight, down_weight,
                                                 residual, has_residual, n_tokens, intermediate_size,
                                                 mid, dst, op_name, error, error_size);
    }
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t gate_weight_bytes = (uint64_t)intermediate_size * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t down_weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)intermediate_size * 2u;
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)intermediate_size * 2u;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)intermediate_size;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (intermediate_size == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(mid, mid_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) || (has_residual && !metal_slice_valid(residual, hidden_bytes)) ||
        !metal_buffer_range_valid(gate_weight->buffer, gate_weight->offset, gate_weight_bytes) ||
        !metal_buffer_range_valid(up_weight->buffer, up_weight->offset, gate_weight_bytes) ||
        !metal_buffer_range_valid(down_weight->buffer, down_weight->offset, down_weight_bytes)) {
        return metal_fail(error, error_size, "invalid %s SwiGLU request", op_name);
    }
    @autoreleasepool {
        const int use_tiled_shared_gate_up = n_tokens == 1u && intermediate_size == UOCR_MOE_SHARED_INTERMEDIATE;
        id<MTLComputePipelineState> gate_pipeline = metal_get_decoder_shape_pipeline(ctx,
                                                                                     use_tiled_shared_gate_up ?
                                                                                         "uocr_dense_swiglu_shared_gate_up_tile4_f16" :
                                                                                         "uocr_dense_swiglu_gate_up_f16",
                                                                                     error,
                                                                                     error_size);
        if (gate_pipeline == nil) {
            return 0;
        }
        if (use_tiled_shared_gate_up &&
            gate_pipeline.maxTotalThreadsPerThreadgroup < (NSUInteger)UOCR_METAL_MOE_SHARED_GATE_UP_TILED_THREADS) {
            return metal_fail(error, error_size, "%s tiled shared gate/up pipeline does not support 1024 threads", op_name);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        uocr_metal_dense_swiglu_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.intermediate_size = intermediate_size;
        params.has_residual = has_residual ? 1u : 0u;
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s gate/up command encoder", op_name);
        }
        const NSUInteger gate_threads = use_tiled_shared_gate_up ?
            metal_power2_threadgroup_width((NSUInteger)UOCR_METAL_MOE_SHARED_GATE_UP_TILED_THREADS,
                                           gate_pipeline.maxTotalThreadsPerThreadgroup) :
            metal_power2_threadgroup_width(64u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        const NSUInteger gate_threadgroups = use_tiled_shared_gate_up ?
            (NSUInteger)n_tokens * ((NSUInteger)intermediate_size + (NSUInteger)UOCR_METAL_MOE_SHARED_GATE_UP_TILE_COLUMNS - 1u) /
                (NSUInteger)UOCR_METAL_MOE_SHARED_GATE_UP_TILE_COLUMNS :
            (NSUInteger)gate_values;
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:gate_weight->buffer offset:gate_weight->offset atIndex:1u];
        [enc setBuffer:up_weight->buffer offset:up_weight->offset atIndex:2u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake(gate_threadgroups, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        uocr_metal_buffer_slice down_weight_slice = { down_weight->buffer, down_weight->offset };
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size) ||
            !metal_run_mps_matmul_nt_f16(ctx,
                                         mid,
                                         down_weight_slice,
                                         dst,
                                         n_tokens,
                                         intermediate_size,
                                         UOCR_HIDDEN_SIZE,
                                         op_name,
                                         error,
                                         error_size)) {
            return 0;
        }
        if (has_residual) {
            return metal_run_residual_add_f16(ctx,
                                              dst,
                                              residual,
                                              dst,
                                              (uint32_t)down_values,
                                              op_name,
                                              error,
                                              error_size);
        }
        return 1;
    }
}

static int metal_run_moe_router_buffer_f16(uocr_metal_context *ctx,
                                           uocr_metal_buffer_slice input,
                                           const uocr_metal_decoder_binding *router_weight,
                                           uint32_t slot,
                                           uint32_t n_tokens,
                                           uocr_metal_buffer_slice *top_ids_out,
                                           uocr_metal_buffer_slice *top_weights_out,
                                           char *error,
                                           size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_ROUTED_EXPERTS * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uocr_metal_buffer_slice logits;
    uocr_metal_buffer_slice top_ids;
    uocr_metal_buffer_slice top_weights;
    uint64_t logits_bytes = 0u;
    uint64_t top_ids_bytes = 0u;
    uint64_t top_weights_bytes = 0u;
    uint64_t router_values = (uint64_t)n_tokens * (uint64_t)UOCR_ROUTED_EXPERTS;
    if (ctx == NULL || router_weight == NULL || top_ids_out == NULL || top_weights_out == NULL || n_tokens == 0u ||
        router_values > UINT32_MAX || !metal_slice_valid(input, hidden_bytes) ||
        !metal_buffer_range_valid(router_weight->buffer, router_weight->offset, weight_bytes) ||
        !metal_router_arena_slices(ctx, slot, n_tokens, &logits, &top_ids, &top_weights,
                                   &logits_bytes, &top_ids_bytes, &top_weights_bytes)) {
        return metal_fail(error, error_size, "invalid integrated MoE router request");
    }
    (void)logits_bytes;
    (void)top_ids_bytes;
    (void)top_weights_bytes;
    @autoreleasepool {
        const int use_fused_decode_router = (n_tokens == 1u);
        id<MTLComputePipelineState> fused_pipeline = use_fused_decode_router ?
            metal_get_decoder_shape_pipeline(ctx, "uocr_moe_router_decode_fused_f16", error, error_size) : nil;
        id<MTLComputePipelineState> topk_pipeline = use_fused_decode_router ? nil :
            metal_get_decoder_shape_pipeline(ctx, "uocr_moe_router_softmax_topk_f32", error, error_size);
        if ((use_fused_decode_router && fused_pipeline == nil) ||
            (!use_fused_decode_router && topk_pipeline == nil)) {
            return 0;
        }
        if (use_fused_decode_router && fused_pipeline.maxTotalThreadsPerThreadgroup < 256u) {
            return metal_fail(error, error_size, "integrated MoE fused router pipeline does not support 256 threads");
        }
        if (!use_fused_decode_router && topk_pipeline.maxTotalThreadsPerThreadgroup < (NSUInteger)UOCR_ROUTED_EXPERTS) {
            return metal_fail(error, error_size, "integrated MoE router top-k pipeline does not support 64 threads");
        }
        uocr_metal_moe_router_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.experts = UOCR_ROUTED_EXPERTS;
        params.top_k = UOCR_MOE_TOP_K;

        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated MoE router", error, error_size);
        if (cb == nil) {
            return 0;
        }
        if (use_fused_decode_router) {
            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create integrated MoE fused router encoder");
            }
            const NSUInteger fused_threads = metal_power2_threadgroup_width((NSUInteger)UOCR_METAL_MOE_ROUTER_FUSED_THREADS,
                                                                            fused_pipeline.maxTotalThreadsPerThreadgroup);
            const NSUInteger hidden_tg_bytes = (NSUInteger)UOCR_HIDDEN_SIZE * sizeof(uint16_t);
            const NSUInteger scratch_tg_bytes = ((NSUInteger)UOCR_ROUTED_EXPERTS + fused_threads) * sizeof(float);
            [enc setComputePipelineState:fused_pipeline];
            [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
            [enc setBuffer:router_weight->buffer offset:router_weight->offset atIndex:1u];
            [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:2u];
            [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:3u];
            [enc setBytes:&params length:sizeof(params) atIndex:4u];
            [enc setThreadgroupMemoryLength:hidden_tg_bytes atIndex:0u];
            [enc setThreadgroupMemoryLength:scratch_tg_bytes atIndex:1u];
            [enc dispatchThreadgroups:MTLSizeMake(1u, 1u, 1u)
                 threadsPerThreadgroup:MTLSizeMake(fused_threads, 1u, 1u)];
            [enc endEncoding];
        } else {
            uocr_metal_buffer_slice router_weight_slice = { router_weight->buffer, router_weight->offset };
            const uint64_t router_mps_start_ns = uocr_profile_now_ns();
            if (!metal_run_mps_matmul_nt_f16_to_f32(ctx,
                                                    input,
                                                    router_weight_slice,
                                                    logits,
                                                    n_tokens,
                                                    UOCR_HIDDEN_SIZE,
                                                    UOCR_ROUTED_EXPERTS,
                                                    "integrated MoE router MPS logits",
                                                    error,
                                                    error_size)) {
                return 0;
            }
            metal_profile_add_event_now(ctx, "metal.prefill.moe_router_mps_logits", router_mps_start_ns);

            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create integrated MoE router top-k encoder");
            }
            const NSUInteger topk_threads = metal_power2_threadgroup_width((NSUInteger)UOCR_METAL_MOE_ROUTER_TOPK_THREADS,
                                                                           topk_pipeline.maxTotalThreadsPerThreadgroup);
            const NSUInteger topk_scratch_bytes = ((NSUInteger)UOCR_ROUTED_EXPERTS + topk_threads) * sizeof(float) +
                                                  (NSUInteger)UOCR_ROUTED_EXPERTS * sizeof(uint32_t);
            [enc setComputePipelineState:topk_pipeline];
            [enc setBuffer:logits.buffer offset:logits.offset atIndex:0u];
            [enc setBuffer:logits.buffer offset:logits.offset atIndex:1u];
            [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:2u];
            [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:3u];
            [enc setBytes:&params length:sizeof(params) atIndex:4u];
            [enc setThreadgroupMemoryLength:topk_scratch_bytes atIndex:0u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_tokens, 1u, 1u)
                 threadsPerThreadgroup:MTLSizeMake(topk_threads, 1u, 1u)];
            [enc endEncoding];
        }
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated MoE router", error, error_size)) {
            return 0;
        }
    }
    *top_ids_out = top_ids;
    *top_weights_out = top_weights;
    return 1;
}

static int metal_expert_interleaved_slab_for_layer(const uocr_metal_context *ctx,
                                                   uint32_t layer,
                                                   uocr_metal_buffer_slice *out_slab,
                                                   char *error,
                                                   size_t error_size) {
    if (ctx == NULL || out_slab == NULL || layer == 0u || layer >= UOCR_DECODER_LAYERS) {
        return metal_fail(error, error_size, "invalid integrated MoE expert slab request");
    }
    const uocr_metal_decoder_expert_slab_cache *slab = &ctx->decoder_bindings.layers[layer].expert_slab;
    if (!ctx->decoder_bindings.valid || !slab->valid || slab->buffer == nil) {
        return metal_fail(error,
                          error_size,
                          "missing cached integrated MoE expert slab for layer %u",
                          layer);
    }
    if (!metal_buffer_range_valid(slab->buffer, slab->offset, slab->byte_length)) {
        return metal_fail(error,
                          error_size,
                          "cached integrated MoE expert slab for layer %u is outside its Metal buffer",
                          layer);
    }
    out_slab->buffer = slab->buffer;
    out_slab->offset = slab->offset;
    return 1;
}



static int metal_run_moe_interleaved_decode_fused_combine_buffer_q8_0(
    uocr_metal_context *ctx,
    uocr_metal_buffer_slice input,
    uocr_metal_buffer_slice top_ids,
    uocr_metal_buffer_slice top_weights,
    uocr_metal_buffer_slice expert_qweight_slab,
    uocr_metal_buffer_slice expert_qscale_slab,
    uint32_t n_tokens,
    uocr_metal_buffer_slice mid,
    uocr_metal_buffer_slice shared,
    uocr_metal_buffer_slice residual,
    uocr_metal_buffer_slice dst,
    char *error,
    size_t error_size);

static int metal_run_moe_interleaved_decode_fused_combine_buffer_q8_0(
    uocr_metal_context *ctx,
    uocr_metal_buffer_slice input,
    uocr_metal_buffer_slice top_ids,
    uocr_metal_buffer_slice top_weights,
    uocr_metal_buffer_slice expert_qweight_slab,
    uocr_metal_buffer_slice expert_qscale_slab,
    uint32_t n_tokens,
    uocr_metal_buffer_slice mid,
    uocr_metal_buffer_slice shared,
    uocr_metal_buffer_slice residual,
    uocr_metal_buffer_slice dst,
    char *error,
    size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t top_ids_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(uint32_t);
    const uint64_t top_weights_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(float);
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
    const uint64_t projection_values = (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * (uint64_t)UOCR_HIDDEN_SIZE;
    const uint64_t projection_scale_values =
        (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * ((uint64_t)UOCR_HIDDEN_SIZE / UOCR_Q8_GROUP_SIZE_DEFAULT);
    const uint64_t slab_qweight_bytes = projection_values * 3u * (uint64_t)UOCR_ROUTED_EXPERTS;
    const uint64_t slab_qscale_bytes = projection_scale_values * 3u * (uint64_t)UOCR_ROUTED_EXPERTS;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || n_tokens == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(top_ids, top_ids_bytes) ||
        !metal_slice_valid(top_weights, top_weights_bytes) ||
        !metal_slice_valid(expert_qweight_slab, slab_qweight_bytes) ||
        !metal_slice_valid(expert_qscale_slab, slab_qscale_bytes) ||
        !metal_slice_valid(mid, mid_bytes) || !metal_slice_valid(shared, hidden_bytes) ||
        !metal_slice_valid(residual, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid integrated routed MoE Q8 fused-combine request");
    }
    @autoreleasepool {
        const int use_decode_kernels = (n_tokens == 1u);
        const int use_tiled_routed_gate_up = use_decode_kernels;
        const uint32_t routed_top_k =
            use_decode_kernels ? (uint32_t)UOCR_METAL_DECODE_MOE_TOP_K : (uint32_t)UOCR_MOE_TOP_K;

        id<MTLComputePipelineState> gate_pipeline = nil;
        id<MTLComputePipelineState> down_combine_pipeline = nil;
        if (use_decode_kernels) {
            gate_pipeline = metal_get_pipeline(ctx,
                                                use_tiled_routed_gate_up ?
                                                    "uocr_moe_decode_interleaved_gate_up_tile4_q8_0_to_f16" :
                                                    "uocr_moe_decode_interleaved_gate_up_one_q8_0_to_f16",
                                                error, error_size);
            down_combine_pipeline = metal_get_pipeline(ctx,
                                                        use_tiled_routed_gate_up ?
                                                            "uocr_moe_decode_interleaved_down_sum_combine_tile4_q8_0_to_f16" :
                                                            "uocr_moe_decode_interleaved_down_sum_combine_one_q8_0_to_f16",
                                                        error, error_size);
        } else {
            /* Prefill uses the non-tiled decode gate/up kernel with n_tokens > 1,
             * and the non-tiled decode down/combine kernel.  The decode kernel
             * params struct is used for both since it has the same layout. */
            gate_pipeline = metal_get_pipeline(ctx,
                                                "uocr_moe_decode_interleaved_gate_up_one_q8_0_to_f16",
                                                error, error_size);
            down_combine_pipeline = metal_get_pipeline(ctx,
                                                        "uocr_moe_decode_interleaved_down_sum_combine_one_q8_0_to_f16",
                                                        error, error_size);
        }
        if (gate_pipeline == nil || down_combine_pipeline == nil) {
            return 0;
        }
        if (use_tiled_routed_gate_up &&
            gate_pipeline.maxTotalThreadsPerThreadgroup < (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS) {
            return metal_fail(error, error_size,
                              "integrated routed MoE Q8 tiled gate/up pipeline supports only %llu threads; need %u",
                              (unsigned long long)gate_pipeline.maxTotalThreadsPerThreadgroup,
                              UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated routed MoE Q8 fused combine", error, error_size);
        if (cb == nil) {
            return 0;
        }
        uocr_metal_moe_decode_interleaved_q8_params params;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
        params.expert_count = UOCR_ROUTED_EXPERTS;
        params.top_k = routed_top_k;
        params.expert_stride_values = (uint32_t)(projection_values * 3u);
        params.up_offset_values = (uint32_t)projection_values;
        params.down_offset_values = (uint32_t)(projection_values * 2u);
        params.expert_scale_stride_values = (uint32_t)(projection_scale_values * 3u);
        params.up_scale_offset_values = (uint32_t)projection_scale_values;
        params.down_scale_offset_values = (uint32_t)(projection_scale_values * 2u);
        params.group_size = UOCR_Q8_GROUP_SIZE_DEFAULT;
        params.reserved = 0u;

        /* The decode Q8 kernel uses n_tokens from the params struct for the
         * prefill path, but the decode struct doesn't have n_tokens.  For
         * prefill, we use the prefill Q8 params.  For decode, the decode
         * struct.  Both share the same kernel which reads n_tokens from the
         * constant buffer.  The decode kernel struct has no n_tokens field,
         * so for prefill we need the prefill struct.  To keep it simple, we
         * always use the prefill struct (which has n_tokens) for the gate/up
         * kernel, and the appropriate struct for down/combine. */
        uocr_metal_moe_prefill_interleaved_q8_params prefill_params;
        prefill_params.n_tokens = n_tokens;
        prefill_params.hidden_size = UOCR_HIDDEN_SIZE;
        prefill_params.intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
        prefill_params.expert_count = UOCR_ROUTED_EXPERTS;
        prefill_params.top_k = routed_top_k;
        prefill_params.expert_stride_values = (uint32_t)(projection_values * 3u);
        prefill_params.up_offset_values = (uint32_t)projection_values;
        prefill_params.down_offset_values = (uint32_t)(projection_values * 2u);
        prefill_params.expert_scale_stride_values = (uint32_t)(projection_scale_values * 3u);
        prefill_params.up_scale_offset_values = (uint32_t)projection_scale_values;
        prefill_params.down_scale_offset_values = (uint32_t)(projection_scale_values * 2u);
        prefill_params.group_size = UOCR_Q8_GROUP_SIZE_DEFAULT;

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE Q8 gate/up encoder");
        }
        const NSUInteger gate_threads = use_tiled_routed_gate_up ?
            metal_power2_threadgroup_width((NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS,
                                           gate_pipeline.maxTotalThreadsPerThreadgroup) :
            metal_power2_threadgroup_width(n_tokens == 1u ? 256u : 64u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        const NSUInteger gate_threadgroups = use_tiled_routed_gate_up ?
            (NSUInteger)n_tokens * (NSUInteger)routed_top_k *
                (((NSUInteger)UOCR_MOE_EXPERT_INTERMEDIATE + (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILE_COLUMNS - 1u) /
                 (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILE_COLUMNS) :
            (NSUInteger)n_tokens * (NSUInteger)routed_top_k * (NSUInteger)UOCR_MOE_EXPERT_INTERMEDIATE;
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:expert_qweight_slab.buffer offset:expert_qweight_slab.offset atIndex:2u];
        [enc setBuffer:expert_qscale_slab.buffer offset:expert_qscale_slab.offset atIndex:3u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:4u];
        [enc setBytes:&prefill_params length:sizeof(prefill_params) atIndex:5u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake(gate_threadgroups, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE Q8 down/combine encoder");
        }
        const NSUInteger down_threads = metal_power2_threadgroup_width(n_tokens == 1u ? 256u : 64u,
                                                                       down_combine_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:down_combine_pipeline];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:2u];
        [enc setBuffer:expert_qweight_slab.buffer offset:expert_qweight_slab.offset atIndex:3u];
        [enc setBuffer:expert_qscale_slab.buffer offset:expert_qscale_slab.offset atIndex:4u];
        [enc setBuffer:shared.buffer offset:shared.offset atIndex:5u];
        [enc setBuffer:residual.buffer offset:residual.offset atIndex:6u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:7u];
        [enc setBytes:&prefill_params length:sizeof(prefill_params) atIndex:8u];
        [enc setThreadgroupMemoryLength:down_threads * sizeof(float) atIndex:0u];
        {
            const NSUInteger down_threadgroups = use_tiled_routed_gate_up ?
                (NSUInteger)n_tokens * (((NSUInteger)UOCR_HIDDEN_SIZE + 4u - 1u) / 4u) :
                (NSUInteger)down_values;
            [enc dispatchThreadgroups:MTLSizeMake(down_threadgroups, 1u, 1u)
                 threadsPerThreadgroup:MTLSizeMake(down_threads, 1u, 1u)];
        }
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated routed MoE Q8 fused combine", error, error_size);
    }
}

static int metal_run_moe_interleaved_decode_fused_combine_buffer_f16(uocr_metal_context *ctx,
                                                                     uocr_metal_buffer_slice input,
                                                                     uocr_metal_buffer_slice top_ids,
                                                                     uocr_metal_buffer_slice top_weights,
                                                                     uocr_metal_buffer_slice expert_slab,
                                                                     uocr_metal_buffer_slice expert_scale_slab,
                                                                     uint32_t expert_qtype,
                                                                     uint32_t n_tokens,
                                                                     uocr_metal_buffer_slice mid,
                                                                     uocr_metal_buffer_slice shared,
                                                                     uocr_metal_buffer_slice residual,
                                                                     uocr_metal_buffer_slice dst,
                                                                     char *error,
                                                                     size_t error_size) {
    if (expert_qtype == UOCR_TENSOR_Q8_0) {
        return metal_run_moe_interleaved_decode_fused_combine_buffer_q8_0(ctx,
                                                                          input,
                                                                          top_ids,
                                                                          top_weights,
                                                                          expert_slab,
                                                                          expert_scale_slab,
                                                                          n_tokens,
                                                                          mid,
                                                                          shared,
                                                                          residual,
                                                                          dst,
                                                                          error,
                                                                          error_size);
    }
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t top_ids_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(uint32_t);
    const uint64_t top_weights_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(float);
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
    const uint64_t projection_values = (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * (uint64_t)UOCR_HIDDEN_SIZE;
    const uint64_t slab_bytes = projection_values * 2u * 3u * (uint64_t)UOCR_ROUTED_EXPERTS;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || n_tokens == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(top_ids, top_ids_bytes) ||
        !metal_slice_valid(top_weights, top_weights_bytes) || !metal_slice_valid(expert_slab, slab_bytes) ||
        !metal_slice_valid(mid, mid_bytes) || !metal_slice_valid(shared, hidden_bytes) ||
        !metal_slice_valid(residual, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid integrated routed MoE fused-combine request");
    }
    @autoreleasepool {
        const int use_decode_kernels = (n_tokens == 1u);
        const int use_tiled_routed_gate_up = use_decode_kernels;
        /* Decode uses fewer routed experts (UOCR_METAL_DECODE_MOE_TOP_K) than
         * prefill (UOCR_MOE_TOP_K).  Buffers remain sized for the max top_k. */
        const uint32_t routed_top_k =
            use_decode_kernels ? (uint32_t)UOCR_METAL_DECODE_MOE_TOP_K : (uint32_t)UOCR_MOE_TOP_K;
        id<MTLComputePipelineState> gate_pipeline = nil;
        id<MTLComputePipelineState> down_combine_pipeline = nil;
        if (use_decode_kernels) {
            MTLFunctionConstantValues *constants = [MTLFunctionConstantValues new];
            if (constants == nil) {
                return metal_fail(error, error_size, "failed to allocate integrated routed MoE decode constants");
            }
            const uint32_t hidden_size = UOCR_HIDDEN_SIZE;
            const uint32_t intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
            const uint32_t expert_count = UOCR_ROUTED_EXPERTS;
            const uint32_t top_k = routed_top_k;
            [constants setConstantValue:&hidden_size type:MTLDataTypeUInt atIndex:UOCR_METAL_FC_HIDDEN_SIZE];
            [constants setConstantValue:&expert_count type:MTLDataTypeUInt atIndex:UOCR_METAL_FC_MOE_EXPERTS];
            [constants setConstantValue:&top_k type:MTLDataTypeUInt atIndex:UOCR_METAL_FC_MOE_TOP_K];
            [constants setConstantValue:&intermediate_size type:MTLDataTypeUInt atIndex:UOCR_METAL_FC_MOE_EXPERT_INTERMEDIATE];
            NSString *constant_key = [NSString stringWithFormat:@"#integrated-moe-decode:h%u:i%u:e%u:k%u",
                                      hidden_size,
                                      intermediate_size,
                                      expert_count,
                                      top_k];
            gate_pipeline = metal_get_pipeline(ctx,
                                               use_tiled_routed_gate_up ?
                                                   "uocr_moe_decode_interleaved_gate_up_tile4_f16" :
                                                   "uocr_moe_decode_interleaved_gate_up_one_f16",
                                               error,
                                               error_size);
            down_combine_pipeline = metal_get_pipeline_with_constants(ctx,
                                                                      use_tiled_routed_gate_up ?
                                                                          UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_KERNEL :
                                                                          "uocr_moe_decode_interleaved_down_sum_combine_one_f16_to_f16",
                                                                      constant_key,
                                                                      constants,
                                                                      error,
                                                                      error_size);
            [constants release];
        } else {
            gate_pipeline = metal_get_pipeline(ctx,
                                               "uocr_moe_prefill_interleaved_gate_up_f16",
                                               error,
                                               error_size);
            down_combine_pipeline = metal_get_pipeline(ctx,
                                                       "uocr_moe_decode_interleaved_down_sum_combine_f16_to_f16",
                                                       error,
                                                       error_size);
        }
        if (gate_pipeline == nil || down_combine_pipeline == nil) {
            return 0;
        }
        if (use_tiled_routed_gate_up &&
            gate_pipeline.maxTotalThreadsPerThreadgroup < (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS) {
            return metal_fail(error,
                              error_size,
                              "integrated routed MoE tiled gate/up pipeline supports only %llu threads; need %u",
                              (unsigned long long)gate_pipeline.maxTotalThreadsPerThreadgroup,
                              UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated routed MoE fused combine", error, error_size);
        if (cb == nil) {
            return 0;
        }
        uocr_metal_moe_prefill_interleaved_params prefill_params;
        prefill_params.n_tokens = n_tokens;
        prefill_params.hidden_size = UOCR_HIDDEN_SIZE;
        prefill_params.intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
        prefill_params.expert_count = UOCR_ROUTED_EXPERTS;
        prefill_params.top_k = routed_top_k;
        prefill_params.expert_stride_values = (uint32_t)(projection_values * 3u);
        prefill_params.up_offset_values = (uint32_t)projection_values;
        prefill_params.down_offset_values = (uint32_t)(projection_values * 2u);
        uocr_metal_moe_decode_interleaved_params decode_params;
        decode_params.hidden_size = UOCR_HIDDEN_SIZE;
        decode_params.intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
        decode_params.expert_count = UOCR_ROUTED_EXPERTS;
        decode_params.top_k = routed_top_k;
        decode_params.expert_stride_values = (uint32_t)(projection_values * 3u);
        decode_params.up_offset_values = (uint32_t)projection_values;
        decode_params.down_offset_values = (uint32_t)(projection_values * 2u);
        decode_params.reserved = 0u;
        const void *down_params_ptr = use_decode_kernels ? (const void *)&decode_params : (const void *)&prefill_params;
        const NSUInteger down_params_size = use_decode_kernels ? sizeof(decode_params) : sizeof(prefill_params);
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE fused gate/up encoder");
        }
        const NSUInteger gate_threads = use_tiled_routed_gate_up ?
            metal_power2_threadgroup_width((NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILED_THREADS,
                                           gate_pipeline.maxTotalThreadsPerThreadgroup) :
            metal_power2_threadgroup_width(n_tokens == 1u ? 256u : 64u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        const NSUInteger gate_threadgroups = use_tiled_routed_gate_up ?
            (NSUInteger)n_tokens * (NSUInteger)routed_top_k *
                (((NSUInteger)UOCR_MOE_EXPERT_INTERMEDIATE + (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILE_COLUMNS - 1u) /
                 (NSUInteger)UOCR_METAL_MOE_ROUTED_GATE_UP_TILE_COLUMNS) :
            (NSUInteger)n_tokens * (NSUInteger)routed_top_k * (NSUInteger)UOCR_MOE_EXPERT_INTERMEDIATE;
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:expert_slab.buffer offset:expert_slab.offset atIndex:2u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:3u];
        [enc setBytes:&prefill_params length:sizeof(prefill_params) atIndex:4u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake(gate_threadgroups, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE fused down/combine encoder");
        }
        const NSUInteger down_threads = metal_power2_threadgroup_width(n_tokens == 1u ? 256u : 64u,
                                                                       down_combine_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:down_combine_pipeline];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:2u];
        [enc setBuffer:expert_slab.buffer offset:expert_slab.offset atIndex:3u];
        [enc setBuffer:shared.buffer offset:shared.offset atIndex:4u];
        [enc setBuffer:residual.buffer offset:residual.offset atIndex:5u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:6u];
        [enc setBytes:down_params_ptr length:down_params_size atIndex:7u];
        [enc setThreadgroupMemoryLength:down_threads * sizeof(float) atIndex:0u];
        {
            const NSUInteger down_threadgroups = use_decode_kernels ?
                ((NSUInteger)UOCR_HIDDEN_SIZE + (NSUInteger)UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_TILE_COLUMNS - 1u) /
                    (NSUInteger)UOCR_METAL_MOE_ROUTED_DOWN_COMBINE_TILE_COLUMNS :
                (NSUInteger)down_values;
            [enc dispatchThreadgroups:MTLSizeMake(down_threadgroups, 1u, 1u)
                 threadsPerThreadgroup:MTLSizeMake(down_threads, 1u, 1u)];
        }
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated routed MoE fused combine", error, error_size);
    }
}



static int metal_run_decoder_decode_one_f16(uocr_metal_context *ctx,
                                            uint32_t slot,
                                            uint32_t prompt_length,
                                            uint32_t generated_count_after_write,
                                            uint32_t generated_token_index,
                                            char *error,
                                            size_t error_size) {
    if (ctx == NULL || !ctx->has_kv_cache_layout || slot >= ctx->kv_cache_layout.batch_slots ||
        prompt_length == 0u || prompt_length > ctx->kv_cache_layout.prompt_token_capacity ||
        generated_count_after_write == 0u || generated_count_after_write > UOCR_MAX_POSITIONS - prompt_length) {
        return metal_fail(error, error_size, "invalid integrated decoder decode-step request");
    }
    const uint32_t position = prompt_length + generated_count_after_write - 1u;
    const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    (void)generated_token_index;

    uocr_metal_buffer_slice scratch[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
    for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
        uint64_t bytes = 0u;
        if (!metal_hidden_arena_segment_slice(ctx, slot, i, 1u, &scratch[i], &bytes) || bytes != hidden_bytes) {
            return metal_fail(error, error_size, "integrated decode requires hidden scratch segment %u", i);
        }
    }

#if UOCR_ENABLE_PROFILING
    /* Per-token op-level profiling: only commits/wait when
     * UOCR_METAL_DECODER_PROFILE_DETAIL >= 3 AND the env var
     * UOCR_METAL_DECODER_PROFILE_TOKEN_INDEX matches this token.
     * When token-index profiling is requested, suppress per-op CPU encoding
     * aggregate events for all tokens so the report is not polluted with
     * 984*12 decode-call counters. */
    const int targeted_decode_token_profile = metal_decoder_profile_token_index_requested();
    const int profile_decode_token =
        metal_decoder_profile_detail_level() >= 3 &&
        metal_decoder_profile_token_index_enabled(generated_token_index);

#define RUN_DECODE_TIMED(bucket_name, call_expr)                     \
    do {                                                            \
        const uint64_t decode_bucket_start_ns__ = uocr_profile_now_ns(); \
        if (!(call_expr)) {                                         \
            return 0;                                               \
        }                                                           \
        if (!targeted_decode_token_profile) {                       \
            metal_profile_add_event_now(ctx, (bucket_name), decode_bucket_start_ns__); \
        }                                                           \
    } while (0)

#define DECODE_OP_CHECKPOINT(op_short_name)                         \
    do {                                                            \
        if (profile_decode_token) {                                 \
            char _cp_name[64];                                      \
            (void)snprintf(_cp_name, sizeof(_cp_name),              \
                          "d.l%02u.%s", layer, (op_short_name));   \
            _cp_name[sizeof(_cp_name) - 1u] = '\0';                 \
            if (!metal_decoder_profile_checkpoint(ctx, _cp_name, 1, \
                                                  error, error_size)) { \
                return 0;                                           \
            }                                                       \
        }                                                           \
    } while (0)
#else
#define targeted_decode_token_profile 0
#define profile_decode_token 0
#define RUN_DECODE_TIMED(bucket_name, call_expr)                     \
    do {                                                            \
        if (!(call_expr)) {                                         \
            return 0;                                               \
        }                                                           \
    } while (0)
#define DECODE_OP_CHECKPOINT(op_short_name) ((void)(op_short_name))
#endif

    uocr_metal_buffer_slice current = scratch[0];
    uint32_t current_segment = 0u;
    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
#if UOCR_ENABLE_PROFILING
        const uint64_t layer_start_ns = uocr_profile_now_ns();
#endif
        uint32_t available[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
        uint32_t available_count = 0u;
        for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
            if (i != current_segment) {
                available[available_count++] = i;
            }
        }
        if (available_count < 4u) {
            return metal_fail(error, error_size, "integrated decode scratch assignment failed at layer %u", layer);
        }
        const uint32_t norm_segment = available[0];
        const uint32_t q_segment = available[1];
        const uint32_t k_segment = available[2];
        const uint32_t v_segment = available[3];
        uocr_metal_buffer_slice norm = scratch[norm_segment];
        uocr_metal_buffer_slice q = scratch[q_segment];
        uocr_metal_buffer_slice k = scratch[k_segment];
        uocr_metal_buffer_slice v = scratch[v_segment];
        uocr_metal_buffer_slice output = k;
        const uint32_t output_segment = k_segment;

        const uocr_metal_decoder_layer_fast_bindings *fast =
            &ctx->decoder_fast_bindings[layer];
        const uocr_metal_decoder_binding *input_norm = fast->input_norm;
        const uocr_metal_decoder_binding *post_norm = fast->post_attn_norm;
        const uocr_metal_decoder_binding *q_weight = fast->q_proj;
        const uocr_metal_decoder_binding *k_weight = fast->k_proj;
        const uocr_metal_decoder_binding *v_weight = fast->v_proj;
        const uocr_metal_decoder_binding *o_weight = fast->o_proj;
        if (input_norm == NULL || post_norm == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL || o_weight == NULL) {
            return 0;
        }

        RUN_DECODE_TIMED("metal.decode.attention_norm",
                         metal_run_rmsnorm_buffer_f16(ctx,
                                                      current,
                                                      input_norm,
                                                      1u,
                                                      norm,
                                                      "integrated decode input RMSNorm",
                                                      error,
                                                      error_size));
        DECODE_OP_CHECKPOINT("attn_norm");
        RUN_DECODE_TIMED("metal.decode.attention_projections",
                         metal_run_decode_attention_qkv_one_f16(ctx,
                                                                norm,
                                                                q_weight,
                                                                k_weight,
                                                                v_weight,
                                                                q,
                                                                k,
                                                                v,
                                                                error,
                                                                error_size));
        DECODE_OP_CHECKPOINT("attn_qkv");
        RUN_DECODE_TIMED("metal.decode.rope",
                         metal_run_rope_qk_buffer_f16(ctx, q, k, 1u, position, error, error_size));
        DECODE_OP_CHECKPOINT("rope");
        RUN_DECODE_TIMED("metal.decode.kv_write",
                         metal_run_kv_write_buffer_f16(ctx,
                                                       k,
                                                       v,
                                                       1u,
                                                       layer,
                                                       slot,
                                                       prompt_length,
                                                       position,
                                                       error,
                                                       error_size));
        DECODE_OP_CHECKPOINT("kv_write");
        RUN_DECODE_TIMED("metal.decode.attention",
                         metal_run_decode_attention_buffer_f16(ctx,
                                                               q,
                                                               layer,
                                                               slot,
                                                               prompt_length,
                                                               generated_count_after_write,
                                                               norm,
                                                               error,
                                                               error_size));
        DECODE_OP_CHECKPOINT("attn");
        RUN_DECODE_TIMED("metal.decode.attention_projections",
                         metal_run_decode_attention_output_one_f16(ctx,
                                                                   norm,
                                                                   o_weight,
                                                                   current,
                                                                   q,
                                                                   error,
                                                                   error_size));
        DECODE_OP_CHECKPOINT("attn_out");
        RUN_DECODE_TIMED("metal.decode.post_attention_norm",
                         metal_run_rmsnorm_buffer_f16(ctx,
                                                      q,
                                                      post_norm,
                                                      1u,
                                                      norm,
                                                      "integrated decode post-attention RMSNorm",
                                                      error,
                                                      error_size));
        DECODE_OP_CHECKPOINT("post_norm");

        if (layer == 0u) {
            const uocr_metal_decoder_binding *gate = fast->dense_gate;
            const uocr_metal_decoder_binding *up = fast->dense_up;
            const uocr_metal_decoder_binding *down = fast->dense_down;
            const uint64_t mid_bytes = (uint64_t)UOCR_DENSE_LAYER0_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (gate == NULL || up == NULL || down == NULL) {
                return 0;
            }
            if (!metal_moe_intermediate_slice(ctx, slot, mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode layer0 dense MLP intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.dense_mlp",
                             metal_run_decode_dense_swiglu_one_f16(ctx,
                                                                   norm,
                                                                   gate,
                                                                   up,
                                                                   down,
                                                                   q,
                                                                   1,
                                                                   UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                                   mid,
                                                                   output,
                                                                   "integrated decode layer0 dense SwiGLU",
                                                                   error,
                                                                   error_size));
            DECODE_OP_CHECKPOINT("dense");
        } else {
            const uocr_metal_decoder_binding *router = fast->moe_router;
            const uocr_metal_decoder_binding *shared_gate = fast->moe_shared_gate;
            const uocr_metal_decoder_binding *shared_up = fast->moe_shared_up;
            const uocr_metal_decoder_binding *shared_down = fast->moe_shared_down;
            uocr_metal_buffer_slice top_ids;
            uocr_metal_buffer_slice top_weights;
            uocr_metal_buffer_slice expert_slab;
            const uint64_t shared_mid_bytes = (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE * 2u;
            const uint64_t routed_mid_bytes = (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (router == NULL || shared_gate == NULL || shared_up == NULL || shared_down == NULL) {
                return 0;
            }
            RUN_DECODE_TIMED("metal.decode.moe_router",
                             metal_run_decode_moe_router_one_f16(ctx,
                                                                 norm,
                                                                 router,
                                                                 slot,
                                                                 &top_ids,
                                                                 &top_weights,
                                                                 error,
                                                                 error_size));
            DECODE_OP_CHECKPOINT("moe_router");
            if (!metal_moe_intermediate_slice(ctx, slot, shared_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode MoE shared intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.moe_shared_experts",
                             metal_run_decode_dense_swiglu_one_f16(ctx,
                                                                   norm,
                                                                   shared_gate,
                                                                   shared_up,
                                                                   shared_down,
                                                                   q,
                                                                   0,
                                                                   UOCR_MOE_SHARED_INTERMEDIATE,
                                                                   mid,
                                                                   v,
                                                                   "integrated decode MoE shared experts",
                                                                   error,
                                                                   error_size));
            DECODE_OP_CHECKPOINT("moe_shared");
            expert_slab = ctx->decoder_fast_expert_slabs[layer];
            const uocr_metal_buffer_slice expert_scale_slab = ctx->decoder_fast_expert_scale_slabs[layer];
            const uint32_t expert_qtype = ctx->decoder_fast_expert_qtype;
            if (!metal_moe_intermediate_slice(ctx, slot, routed_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode MoE routed intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.moe_routed_experts",
                             metal_run_moe_interleaved_decode_fused_combine_buffer_f16(ctx,
                                                                                       norm,
                                                                                       top_ids,
                                                                                       top_weights,
                                                                                       expert_slab,
                                                                                       expert_scale_slab,
                                                                                       expert_qtype,
                                                                                       1u,
                                                                                       mid,
                                                                                       v,
                                                                                       q,
                                                                                       output,
                                                                                       error,
                                                                                       error_size));
            DECODE_OP_CHECKPOINT("moe_routed");
        }

        current = output;
        current_segment = output_segment;
#if UOCR_ENABLE_PROFILING
        if (!targeted_decode_token_profile) {
            metal_profile_add_event_now(ctx, "metal.decode.layer", layer_start_ns);
            metal_profile_add_event_now(ctx, "metal.decode.layer_kernels", layer_start_ns);
            metal_profile_add_event_now_f(ctx, layer_start_ns, "metal.decode.layer.%02u", layer);
        }
        if (metal_decoder_profile_detail_level() == 2) {
#else
        {
#endif
            char checkpoint_name[64];
            (void)snprintf(checkpoint_name, sizeof(checkpoint_name), "decode.layer.%02u", layer);
            checkpoint_name[sizeof(checkpoint_name) - 1u] = '\0';
            if (!metal_decoder_profile_checkpoint(ctx, checkpoint_name, 1, error, error_size)) {
                return 0;
            }
        }
    }

    if (current_segment != 0u) {
        RUN_DECODE_TIMED("metal.decode.final_hidden_copy",
                         metal_copy_slice(ctx,
                                          current,
                                          scratch[0],
                                          hidden_bytes,
                                          "integrated decode final-hidden copy",
                                          error,
                                          error_size));
#if UOCR_ENABLE_PROFILING
        if (profile_decode_token) {
            char _cp_name[64];
            (void)snprintf(_cp_name, sizeof(_cp_name),
                          "d.l99.final_copy");
            _cp_name[sizeof(_cp_name) - 1u] = '\0';
            if (!metal_decoder_profile_checkpoint(ctx, _cp_name, 1,
                                                  error, error_size)) {
                return 0;
            }
        }
        if (metal_decoder_profile_detail_level() == 2 &&
            !metal_decoder_profile_checkpoint(ctx, "decode.final_hidden_copy", 1, error, error_size)) {
            return 0;
        }
#endif
    }
#undef RUN_DECODE_TIMED
    return 1;
}

static int metal_run_decoder_prefill_text_f16(uocr_metal_context *ctx,
                                              uint32_t slot,
                                              uint32_t n_tokens,
                                              char *error,
                                              size_t error_size) {
    uocr_metal_buffer_slice prompt;
    uint64_t hidden_bytes = 0u;
    if (!metal_prompt_arena_slice(ctx, slot, n_tokens, &prompt, &hidden_bytes)) {
        return metal_fail(error, error_size, "integrated prefill requires a valid prompt arena slice");
    }

    uocr_metal_buffer_slice scratch[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
    for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
        uint64_t bytes = 0u;
        if (!metal_hidden_arena_segment_slice(ctx, slot, i, n_tokens, &scratch[i], &bytes) || bytes != hidden_bytes) {
            return metal_fail(error, error_size, "integrated prefill requires hidden scratch segment %u", i);
        }
    }

#if UOCR_ENABLE_PROFILING
    const uint64_t prefill_command_encoding_start_ns = uocr_profile_now_ns();
#endif
    if (!metal_command_batch_begin(ctx, error, error_size)) {
        return 0;
    }

    uocr_metal_buffer_slice current = prompt;
    uint32_t current_segment = UINT32_MAX;
#if UOCR_ENABLE_PROFILING
#define RUN_PREFILL_OP(checkpoint_suffix__, event_name__, expr__)                         \
    do {                                                                                  \
        const uint64_t op_start_ns__ = uocr_profile_now_ns();                             \
        if (!(expr__)) {                                                                  \
            return 0;                                                                     \
        }                                                                                 \
        metal_profile_add_event_now(ctx, (event_name__), op_start_ns__);                  \
        if (metal_decoder_profile_detail_level() >= 3 &&                                  \
            getenv(UOCR_METAL_DECODER_PROFILE_TOKEN_INDEX_ENV) == NULL) {                  \
            char checkpoint_name__[96];                                                   \
            char checkpoint_alias__[96];                                                  \
            (void)snprintf(checkpoint_name__,                                             \
                           sizeof(checkpoint_name__),                                     \
                           "prefill.layer.%02u.%s",                                      \
                           layer,                                                         \
                           (checkpoint_suffix__));                                        \
            checkpoint_name__[sizeof(checkpoint_name__) - 1u] = '\0';                     \
            (void)snprintf(checkpoint_alias__,                                            \
                           sizeof(checkpoint_alias__),                                    \
                           "prefill.%s",                                                 \
                           (checkpoint_suffix__));                                        \
            checkpoint_alias__[sizeof(checkpoint_alias__) - 1u] = '\0';                   \
            if (!metal_decoder_profile_checkpoint_alias(ctx,                               \
                                                        checkpoint_name__,                \
                                                        checkpoint_alias__,               \
                                                        1,                                \
                                                        error,                            \
                                                        error_size)) {                    \
                return 0;                                                                 \
            }                                                                             \
        }                                                                                 \
    } while (0)
#else
#define RUN_PREFILL_OP(checkpoint_suffix__, event_name__, expr__)                         \
    do {                                                                                  \
        if (!(expr__)) {                                                                  \
            return 0;                                                                     \
        }                                                                                 \
    } while (0)
#endif

    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
#if UOCR_ENABLE_PROFILING
        const uint64_t layer_start_ns = uocr_profile_now_ns();
#endif
        uint32_t available[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
        uint32_t available_count = 0u;
        for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
            if (i != current_segment) {
                available[available_count++] = i;
            }
        }
        if (available_count < 4u) {
            return metal_fail(error, error_size, "integrated prefill scratch assignment failed at layer %u", layer);
        }
        const uint32_t norm_segment = available[0];
        const uint32_t q_segment = available[1];
        const uint32_t k_segment = available[2];
        const uint32_t v_segment = available[3];
        uocr_metal_buffer_slice norm = scratch[norm_segment];
        uocr_metal_buffer_slice q = scratch[q_segment];
        uocr_metal_buffer_slice k = scratch[k_segment];
        uocr_metal_buffer_slice v = scratch[v_segment];
        uocr_metal_buffer_slice output = k;
        const uint32_t output_segment = k_segment;

        char label[64];
        snprintf(label, sizeof(label), "layer%u input RMSNorm", layer);
        const uocr_metal_decoder_layer_binding_cache *layer_bindings = &ctx->decoder_bindings.layers[layer];
        const uocr_metal_decoder_binding *input_norm = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->input_norm,
                                                                                           label,
                                                                                           error,
                                                                                           error_size);
        const uocr_metal_decoder_binding *post_norm = metal_require_decoder_binding_index(ctx,
                                                                                          layer_bindings->post_attn_norm,
                                                                                          "post-attention norm",
                                                                                          error,
                                                                                          error_size);
        const uocr_metal_decoder_binding *q_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->q_proj,
                                                                                         "attention q_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *k_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->k_proj,
                                                                                         "attention k_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *v_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->v_proj,
                                                                                         "attention v_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *o_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->o_proj,
                                                                                         "attention o_proj",
                                                                                         error,
                                                                                         error_size);
        if (input_norm == NULL || post_norm == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL || o_weight == NULL) {
            return 0;
        }

        RUN_PREFILL_OP("attention_norm",
                       "metal.prefill.attention_norm",
                       metal_run_rmsnorm_buffer_f16(ctx,
                                                    current,
                                                    input_norm,
                                                    n_tokens,
                                                    norm,
                                                    "integrated input RMSNorm",
                                                    error,
                                                    error_size));
        RUN_PREFILL_OP("attention_qkv",
                       "metal.prefill.attention_qkv",
                       metal_run_attention_qkv_buffer_f16(ctx,
                                                          norm,
                                                          q_weight,
                                                          k_weight,
                                                          v_weight,
                                                          n_tokens,
                                                          q,
                                                          k,
                                                          v,
                                                          error,
                                                          error_size));
        RUN_PREFILL_OP("rope",
                       "metal.prefill.rope",
                       metal_run_rope_qk_buffer_f16(ctx, q, k, n_tokens, 0u, error, error_size));
        RUN_PREFILL_OP("kv_write",
                       "metal.prefill.kv_write",
                       metal_run_kv_write_buffer_f16(ctx, k, v, n_tokens, layer, slot, n_tokens, 0u, error, error_size));
        RUN_PREFILL_OP("attention",
                       "metal.prefill.attention",
                       metal_run_prefill_attention_buffer_f16(ctx, q, k, v, n_tokens, norm, error, error_size));
        RUN_PREFILL_OP("attention_output",
                       "metal.prefill.attention_output",
                       metal_run_attention_output_residual_buffer_f16(ctx,
                                                                      norm,
                                                                      o_weight,
                                                                      current,
                                                                      n_tokens,
                                                                      q,
                                                                      error,
                                                                      error_size));
        RUN_PREFILL_OP("post_attention_norm",
                       "metal.prefill.post_attention_norm",
                       metal_run_rmsnorm_buffer_f16(ctx,
                                                    q,
                                                    post_norm,
                                                    n_tokens,
                                                    norm,
                                                    "integrated post-attention RMSNorm",
                                                    error,
                                                    error_size));

        if (layer == 0u) {
            const uocr_metal_decoder_binding *gate = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_gate,
                                                                                         "layer0 dense gate",
                                                                                         error,
                                                                                         error_size);
            const uocr_metal_decoder_binding *up = metal_require_decoder_binding_index(ctx,
                                                                                       layer_bindings->dense_up,
                                                                                       "layer0 dense up",
                                                                                       error,
                                                                                       error_size);
            const uocr_metal_decoder_binding *down = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_down,
                                                                                         "layer0 dense down",
                                                                                         error,
                                                                                         error_size);
            const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_DENSE_LAYER0_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (gate == NULL || up == NULL || down == NULL ||
                !metal_moe_intermediate_slice(ctx, slot, mid_bytes, &mid)) {
                return 0;
            }
            RUN_PREFILL_OP("dense_mlp",
                           "metal.prefill.dense_mlp",
                           metal_run_dense_swiglu_buffer_f16(ctx,
                                                              norm,
                                                              gate,
                                                              up,
                                                              down,
                                                              q,
                                                              1,
                                                              n_tokens,
                                                              UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                              mid,
                                                              output,
                                                              "integrated layer0 dense SwiGLU",
                                                              error,
                                                              error_size));
        } else {
            const uocr_metal_decoder_binding *router = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->moe_router,
                                                                                           "MoE router",
                                                                                           error,
                                                                                           error_size);
            const uocr_metal_decoder_binding *shared_gate = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_gate,
                                                                                                "MoE shared gate",
                                                                                                error,
                                                                                                error_size);
            const uocr_metal_decoder_binding *shared_up = metal_require_decoder_binding_index(ctx,
                                                                                              layer_bindings->moe_shared_up,
                                                                                              "MoE shared up",
                                                                                              error,
                                                                                              error_size);
            const uocr_metal_decoder_binding *shared_down = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_down,
                                                                                                "MoE shared down",
                                                                                                error,
                                                                                                error_size);
            uocr_metal_buffer_slice top_ids;
            uocr_metal_buffer_slice top_weights;
            uocr_metal_buffer_slice expert_slab;
            const uint64_t shared_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE * 2u;
            const uint64_t routed_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K *
                                              (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (router == NULL || shared_gate == NULL || shared_up == NULL || shared_down == NULL) {
                return 0;
            }
            RUN_PREFILL_OP("moe_router",
                           "metal.prefill.moe_router",
                           metal_run_moe_router_buffer_f16(ctx,
                                                           norm,
                                                           router,
                                                           slot,
                                                           n_tokens,
                                                           &top_ids,
                                                           &top_weights,
                                                           error,
                                                           error_size));
            if (!metal_moe_intermediate_slice(ctx, slot, shared_mid_bytes, &mid)) {
                return 0;
            }
            RUN_PREFILL_OP("moe_shared_experts",
                           "metal.prefill.moe_shared_experts",
                           metal_run_dense_swiglu_buffer_f16(ctx,
                                                              norm,
                                                              shared_gate,
                                                              shared_up,
                                                              shared_down,
                                                              q,
                                                              0,
                                                              n_tokens,
                                                              UOCR_MOE_SHARED_INTERMEDIATE,
                                                              mid,
                                                              v,
                                                              "integrated MoE shared experts",
                                                              error,
                                                              error_size));
            expert_slab = ctx->decoder_fast_expert_slabs[layer];
            const uocr_metal_buffer_slice expert_scale_slab = ctx->decoder_fast_expert_scale_slabs[layer];
            const uint32_t expert_qtype = ctx->decoder_fast_expert_qtype;
            if (!metal_moe_intermediate_slice(ctx, slot, routed_mid_bytes, &mid)) {
                return 0;
            }
            RUN_PREFILL_OP("moe_routed_fused",
                           "metal.prefill.moe_routed_fused",
                           metal_run_moe_interleaved_decode_fused_combine_buffer_f16(ctx,
                                                                                     norm,
                                                                                     top_ids,
                                                                                     top_weights,
                                                                                     expert_slab,
                                                                                     expert_scale_slab,
                                                                                     expert_qtype,
                                                                                     n_tokens,
                                                                                     mid,
                                                                                     v,
                                                                                     q,
                                                                                     output,
                                                                                     error,
                                                                                     error_size));
        }

        current = output;
        current_segment = output_segment;
#if UOCR_ENABLE_PROFILING
        metal_profile_add_event_now(ctx, "metal.prefill.layer", layer_start_ns);
        metal_profile_add_event_now_f(ctx, layer_start_ns, "metal.prefill.layer.%02u", layer);
        if (metal_decoder_profile_detail_level() == 2) {
            char checkpoint_name[64];
            (void)snprintf(checkpoint_name, sizeof(checkpoint_name), "prefill.layer.%02u", layer);
            checkpoint_name[sizeof(checkpoint_name) - 1u] = '\0';
            if (!metal_decoder_profile_checkpoint(ctx, checkpoint_name, 1, error, error_size)) {
                return 0;
            }
        }
#endif
    }
#undef RUN_PREFILL_OP

    if (current_segment != 0u) {
        if (!metal_copy_slice(ctx, current, scratch[0], hidden_bytes, "integrated prefill final-hidden copy", error, error_size)) {
            return 0;
        }
        current_segment = 0u;
#if UOCR_ENABLE_PROFILING
        if (metal_decoder_profile_detail_level() >= 2 &&
            getenv(UOCR_METAL_DECODER_PROFILE_TOKEN_INDEX_ENV) == NULL &&
            !metal_decoder_profile_checkpoint(ctx, "prefill.final_hidden_copy", 1, error, error_size)) {
            return 0;
        }
#endif
    }
#if UOCR_ENABLE_PROFILING
    metal_profile_add_event_now(ctx, "metal.prefill.command_encoding", prefill_command_encoding_start_ns);
    const uint64_t prefill_command_wait_start_ns = uocr_profile_now_ns();
    if (!metal_command_batch_commit_and_wait(ctx, "integrated decoder prefill batch", error, error_size)) {
        ctx->has_integrated_prefill = 0;
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.prefill.command_wait", prefill_command_wait_start_ns);
#else
    if (!metal_command_batch_commit_and_wait(ctx, "integrated decoder prefill batch", error, error_size)) {
        ctx->has_integrated_prefill = 0;
        return 0;
    }
#endif
    ctx->has_integrated_prefill = 1;
    ctx->integrated_prefill_slot = slot;
    ctx->integrated_prefill_tokens = n_tokens;
    ctx->integrated_prefill_final_segment = current_segment;
    return 1;
}

static int metal_context_generate_f16_impl(uocr_metal_context *ctx,
                                           const uocr_metal_decoder_request_f16 *request,
                                           id<MTLBuffer> image_features_buffer,
                                           NSUInteger image_features_offset,
                                           uocr_metal_decoder_result_f16 *result,
                                           char *error,
                                           size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || request == NULL || result == NULL) {
        return metal_fail(error, error_size, "invalid Metal integrated decoder request");
    }
    metal_decoder_result_reset(result);

    if (!metal_decoder_runtime_arenas_ready(ctx)) {
        return metal_fail(error, error_size, "Metal integrated decoder requires allocated runtime arenas");
    }
    if (!uocr_metal_context_decoder_bindings_ready(ctx) ||
        ctx->decoder_bindings.token_embedding == UOCR_METAL_DECODER_BINDING_INDEX_INVALID ||
        ctx->decoder_bindings.final_norm == UOCR_METAL_DECODER_BINDING_INDEX_INVALID ||
        ctx->decoder_bindings.lm_head == UOCR_METAL_DECODER_BINDING_INDEX_INVALID) {
        const char *binding_error = ctx->decoder_binding_error[0] != '\0' ?
                                        ctx->decoder_binding_error :
                                        "decoder tensor bindings are not validated";
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder requires validated fp16 decoder tensor bindings: %s",
                          binding_error);
    }
    if (request->input_ids == NULL || request->image_mask == NULL || request->n_tokens == 0u) {
        return metal_fail(error, error_size, "Metal integrated decoder requires input ids, image mask, and prompt tokens");
    }
    if (request->slot >= ctx->kv_cache_layout.batch_slots) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder slot %u exceeds allocated batch slots %u",
                          request->slot,
                          ctx->kv_cache_layout.batch_slots);
    }
    metal_integrated_decoder_state_reset(ctx, request->slot);

    if (request->n_tokens > ctx->kv_cache_layout.prompt_token_capacity) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder prompt length %u exceeds prompt arena capacity %u",
                          request->n_tokens,
                          ctx->kv_cache_layout.prompt_token_capacity);
    }
    if (request->n_tokens > UOCR_MAX_POSITIONS || request->max_new_tokens > UOCR_MAX_POSITIONS - request->n_tokens) {
        return metal_fail(error, error_size, "Metal integrated decoder sequence length exceeds max positions");
    }
    if (request->max_new_tokens > 0u &&
        (result->generated_ids == NULL || result->generated_capacity < request->max_new_tokens)) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder generated-token output capacity %u is smaller than requested %u",
                          result->generated_capacity,
                          request->max_new_tokens);
    }

    uint32_t image_mask_count = 0u;
    for (uint32_t i = 0u; i < request->n_tokens; ++i) {
        if (request->input_ids[i] < 0 || (uint32_t)request->input_ids[i] >= UOCR_VOCAB_SIZE) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder token id %d at position %u is outside vocab %u",
                              request->input_ids[i],
                              i,
                              UOCR_VOCAB_SIZE);
        }
        if (request->image_mask[i] > 1u) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder image mask value %u at position %u is not 0/1",
                              (unsigned)request->image_mask[i],
                              i);
        }
        image_mask_count += request->image_mask[i] != 0u ? 1u : 0u;
    }

    if (request->image_span_length == 0u) {
        if (request->image_span_start != UINT32_MAX || request->image_features_f16 != NULL || image_mask_count != 0u) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder text-only requests must use UINT32_MAX image span, no image features, and an empty image mask");
        }
    } else {
        if ((request->image_features_f16 == NULL && image_features_buffer == nil) ||
            request->image_span_start == UINT32_MAX ||
            request->image_span_start > request->n_tokens ||
            request->image_span_length > request->n_tokens - request->image_span_start) {
            return metal_fail(error, error_size, "Metal integrated decoder image span/features are invalid");
        }
        if (image_mask_count != request->image_span_length) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder image mask count %u does not match image span length %u",
                              image_mask_count,
                              request->image_span_length);
        }
        for (uint32_t i = 0u; i < request->image_span_length; ++i) {
            const uint32_t pos = request->image_span_start + i;
            if (request->image_mask[pos] == 0u) {
                return metal_fail(error,
                                  error_size,
                                  "Metal integrated decoder image span position %u is not marked in image mask",
                                  pos);
            }
        }
    }

    if (!metal_prebuild_mps_runtime_workspace_ndarrays(ctx, request->n_tokens, error, error_size)) {
        return 0;
    }

    if (!metal_command_batch_begin(ctx, error, error_size)) {
        return 0;
    }

    const uint64_t prompt_assembly_start_ns = uocr_profile_now_ns();
    if (!metal_context_assemble_prompt_from_model_to_arena_f16(ctx,
                                                               request->input_ids,
                                                               request->n_tokens,
                                                               request->image_span_length != 0u ? request->image_span_start : UINT32_MAX,
                                                               request->image_span_length,
                                                               request->image_features_f16,
                                                               image_features_buffer,
                                                               image_features_offset,
                                                               request->slot,
                                                               error,
                                                               error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        metal_command_batch_abort(ctx);
        return metal_fail(error, error_size, "failed to assemble integrated prompt into Metal prefill graph: %s", detail);
    }
    metal_profile_add_event_now(ctx, "metal.prompt_assembly", prompt_assembly_start_ns);
    metal_profile_add_event_now(ctx, "metal.prefill.prompt_assembly", prompt_assembly_start_ns);
    if (metal_decoder_profile_detail_level() >= 1 &&
        !metal_decoder_profile_checkpoint(ctx, "prompt_assembly", 1, error, error_size)) {
        metal_command_batch_abort(ctx);
        return 0;
    }

    const uocr_metal_hot_path_alloc_guard prefill_guard =
        metal_hot_path_alloc_guard_begin(ctx);
    char prefill_error[512];
    prefill_error[0] = '\0';
    const uint64_t prefill_start_ns = uocr_profile_now_ns();
    const int prefill_ok = metal_run_decoder_prefill_text_f16(ctx,
                                                             request->slot,
                                                             request->n_tokens,
                                                             prefill_error,
                                                             sizeof(prefill_error));
    if (!metal_hot_path_alloc_guard_end(ctx,
                                        &prefill_guard,
                                        "integrated Metal fp16 prompt prefill",
                                        error,
                                        error_size)) {
        metal_command_batch_abort(ctx);
        ctx->has_integrated_prefill = 0;
        return 0;
    }
    if (!prefill_ok) {
        metal_command_batch_abort(ctx);
        ctx->has_integrated_prefill = 0;
        return metal_fail(error,
                          error_size,
                          "integrated Metal fp16 prompt prefill failed: %s",
                          prefill_error[0] != '\0' ? prefill_error : "unknown error");
    }
    metal_profile_add_event_now(ctx, "metal.prefill", prefill_start_ns);

    if (image_features_buffer != nil && ctx->scratch[UOCR_METAL_SCRATCH_VISION_FINAL].buffer == image_features_buffer) {
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
        image_features_buffer = nil;
        metal_profile_add_event_ms(ctx, "metal.prefill.final_visual_release", 0.0);
    }

    if (request->max_new_tokens == 0u) {
        metal_clear_error(error, error_size);
        return 1;
    }

    uocr_prepared_request sequence_request;
    memset(&sequence_request, 0, sizeof(sequence_request));
    sequence_request.input_ids = request->input_ids;
    sequence_request.image_mask = request->image_mask;
    sequence_request.n_tokens = request->n_tokens;
    sequence_request.max_new_tokens = request->max_new_tokens;

    uocr_sequence_state sequence_state;
    char sequence_error[256];
    memset(&sequence_state, 0, sizeof(sequence_state));
    memset(sequence_error, 0, sizeof(sequence_error));
    int sequence_status = uocr_build_sequence_state(&sequence_request,
                                                    &sequence_state,
                                                    sequence_error,
                                                    sizeof(sequence_error));
    if (sequence_status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "failed to build integrated Metal fp16 sequence state: %s",
                          sequence_error[0] != '\0' ? sequence_error : uocr_status_string(sequence_status));
    }

    uint64_t sequence_len_u64 = 0u;
    uint64_t sequence_bytes = 0u;
    if (!checked_add_u64((uint64_t)request->n_tokens, (uint64_t)request->max_new_tokens, &sequence_len_u64) ||
        sequence_len_u64 > (uint64_t)UINT32_MAX ||
        !checked_mul_u64(sequence_len_u64, (uint64_t)sizeof(int32_t), &sequence_bytes) ||
        sequence_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "integrated Metal fp16 decode sequence buffer size overflow");
    }
    int32_t *sequence = (int32_t *)uocr_malloc((size_t)sequence_bytes);
    if (sequence == NULL) {
        return metal_fail(error, error_size, "failed to allocate integrated Metal fp16 decode sequence buffer");
    }
    sequence_status = uocr_sequence_attach_generation_buffers(&sequence_state,
                                                             result->generated_ids,
                                                             result->generated_capacity,
                                                             sequence,
                                                             (uint32_t)sequence_len_u64);
    if (sequence_status != UOCR_OK) {
        uocr_free(sequence);
        return metal_fail(error,
                          error_size,
                          "failed to attach integrated Metal fp16 generation buffers: %s",
                          uocr_status_string(sequence_status));
    }

    uint64_t selection_scratch_bytes = 0u;
    if (!checked_mul_u64(metal_decode_selection_scratch_bytes_per_slot(),
                         (uint64_t)ctx->kv_cache_layout.batch_slots,
                         &selection_scratch_bytes) ||
        !uocr_metal_context_ensure_scratch(ctx,
                                           UOCR_METAL_SCRATCH_LOGITS,
                                           selection_scratch_bytes,
                                           0,
                                           error,
                                           error_size)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 decode selection scratch allocation failed");
    }

    /* LM head logits buffer (MPS path): f32 [VOCAB_SIZE] per slot */
    {
        uint64_t lm_head_logits_slot = 0u;
        uint64_t lm_head_logits_total = 0u;
        if (!checked_mul_u64((uint64_t)UOCR_VOCAB_SIZE, (uint64_t)sizeof(float), &lm_head_logits_slot) ||
            !checked_mul_u64(lm_head_logits_slot,
                             (uint64_t)ctx->kv_cache_layout.batch_slots,
                             &lm_head_logits_total) ||
            !uocr_metal_context_ensure_scratch(ctx,
                                               UOCR_METAL_SCRATCH_LM_HEAD_LOGITS,
                                               lm_head_logits_total,
                                               0,
                                               error,
                                               error_size)) {
            uocr_free(sequence);
            return metal_fail(error, error_size, "integrated Metal fp16 LM head logits scratch allocation failed");
        }
    }

    uocr_metal_buffer_slice selection_scratch;
    uocr_metal_buffer_slice token_slot;
    uocr_metal_buffer_slice score_slot;
    uocr_metal_buffer_slice norm_scratch;
    uint64_t one_hidden_bytes = 0u;
    if (!metal_decode_selection_scratch_slice(ctx, request->slot, &selection_scratch) ||
        !metal_token_readback_arena_slices(ctx, request->slot, &token_slot, &score_slot) ||
        !metal_hidden_arena_segment_slice(ctx, request->slot, 1u, 1u, &norm_scratch, &one_hidden_bytes) ||
        one_hidden_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 decode arena slices are invalid");
    }

    uocr_metal_buffer_slice prompt_token_ids;
    uint64_t prompt_token_ids_bytes = 0u;
    if (!metal_prompt_token_ids_slice(ctx, request->slot, request->n_tokens, &prompt_token_ids, &prompt_token_ids_bytes) ||
        prompt_token_ids_bytes != (uint64_t)request->n_tokens * (uint64_t)sizeof(int32_t)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 prompt token-id slice is invalid");
    }

    uocr_metal_buffer_slice hidden_for_selection;
    if (!metal_hidden_arena_token_slice(ctx,
                                        request->slot,
                                        ctx->integrated_prefill_final_segment,
                                        request->n_tokens - 1u,
                                        &hidden_for_selection)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 prefill final-token hidden slice is invalid");
    }

    const uocr_metal_hot_path_alloc_guard decode_loop_guard =
        metal_hot_path_alloc_guard_begin(ctx);
    const uint64_t decode_loop_start_ns = uocr_profile_now_ns();
    int decode_loop_ok = 1;
    char decode_loop_error[512];
    decode_loop_error[0] = '\0';

#define UOCR_METAL_DECODE_LOOP_FAIL(...)                    \
    do {                                                    \
        (void)snprintf(decode_loop_error,                   \
                       sizeof(decode_loop_error),           \
                       __VA_ARGS__);                        \
        decode_loop_ok = 0;                                 \
        goto decode_loop_done;                              \
    } while (0)

    /* ── Chunked decode: GPU-resident batch ───────────────────────── */
    /* Allocate CPU-visible shared buffer for chunk token/score results.
     * Worst case: one chunk of UOCR_METAL_DECODE_CHUNK_SIZE tokens. */
    const uint32_t chunk_capacity = UOCR_METAL_DECODE_CHUNK_SIZE;
    uint64_t chunk_buf_bytes = 0u;
    if (!checked_mul_u64((uint64_t)chunk_capacity, (uint64_t)sizeof(int32_t), &chunk_buf_bytes) ||
        !checked_add_u64(chunk_buf_bytes, (uint64_t)chunk_capacity * (uint64_t)sizeof(float), &chunk_buf_bytes) ||
        chunk_buf_bytes > (uint64_t)SIZE_MAX || chunk_buf_bytes > (uint64_t)NSUIntegerMax) {
        UOCR_METAL_DECODE_LOOP_FAIL("chunk buffer byte-size overflow");
    }
    id<MTLBuffer> chunk_buffer = metal_new_buffer_with_length(ctx,
                                                              (NSUInteger)chunk_buf_bytes,
                                                              MTLResourceStorageModeShared);
    if (chunk_buffer == nil) {
        UOCR_METAL_DECODE_LOOP_FAIL("failed to allocate chunk decode buffer");
    }
    chunk_buffer.label = @"uocr_decode_chunk_results";
    uocr_metal_buffer_slice chunk_tokens;
    chunk_tokens.buffer = chunk_buffer;
    chunk_tokens.offset = 0u;
    uocr_metal_buffer_slice chunk_scores;
    chunk_scores.buffer = chunk_buffer;
    chunk_scores.offset = (NSUInteger)((uint64_t)chunk_capacity * sizeof(int32_t));

    int chunk_loop_eos = 0;

    while (!chunk_loop_eos && !uocr_sequence_generation_done(&sequence_state)) {
        const uint64_t chunk_start_ns = uocr_profile_now_ns();
        const uint32_t generated_before_chunk = sequence_state.generated_count;
        const uint32_t total_remaining = request->max_new_tokens - generated_before_chunk;
        uint32_t this_chunk_size = total_remaining < chunk_capacity ? total_remaining : chunk_capacity;

        /* If targeted decode-op profiling is requested and the target token
         * falls in the middle of this chunk, end this chunk immediately before
         * it.  The next loop iteration then starts at the target token, so the
         * first per-op checkpoint does not include earlier autoregressive steps
         * from the same chunk. */
        uint32_t target_token_index = 0u;
        if (metal_decoder_profile_detail_level() >= 3 &&
            metal_decoder_profile_token_index_parse(&target_token_index) &&
            target_token_index > generated_before_chunk &&
            target_token_index < generated_before_chunk + this_chunk_size) {
            this_chunk_size = target_token_index - generated_before_chunk;
        }

        /* Open a single command batch for the whole chunk */
        if (!metal_command_batch_begin(ctx, error, error_size)) {
            [chunk_buffer release];
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("chunk decode command batch begin failed: %s", detail);
        }

        /* Encode this_chunk_size decode steps GPU-resident */
        if (!metal_run_decoder_decode_chunk_f16(ctx,
                                                request->slot,
                                                request->n_tokens,
                                                generated_before_chunk,
                                                this_chunk_size,
                                                hidden_for_selection,
                                                norm_scratch,
                                                selection_scratch,
                                                chunk_tokens,
                                                chunk_scores,
                                                error, error_size)) {
            [chunk_buffer release];
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("chunk decode steps failed: %s", detail);
        }

        /* Commit and wait for the chunk to complete */
        const uint64_t chunk_wait_start_ns = uocr_profile_now_ns();
        if (!metal_command_batch_commit_and_wait(ctx, "chunk decode batch", error, error_size)) {
            [chunk_buffer release];
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("chunk decode commit/wait failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.chunk.wait", chunk_wait_start_ns);
        metal_profile_add_event_now(ctx, "metal.chunk", chunk_start_ns);

        /* Read back tokens and scores from CPU-visible buffer */
        volatile int32_t *tokens_ptr = (volatile int32_t *)[chunk_buffer contents];
        volatile float *scores_ptr = (volatile float *)((uint8_t *)[chunk_buffer contents] +
                                                         (NSUInteger)((uint64_t)chunk_capacity * sizeof(int32_t)));

        for (uint32_t i = 0u; i < this_chunk_size; ++i) {
            const int32_t token_id = (int32_t)tokens_ptr[i];
            const float score = (float)scores_ptr[i];

            if (token_id < 0 || (uint32_t)token_id >= UOCR_VOCAB_SIZE) {
                [chunk_buffer release];
                UOCR_METAL_DECODE_LOOP_FAIL("chunk decode selected invalid token id %d at step %u",
                                            (int)token_id, i);
            }
            if (generated_before_chunk + i >= result->generated_capacity) {
                [chunk_buffer release];
                UOCR_METAL_DECODE_LOOP_FAIL("chunk decode generated count exceeds capacity");
            }

            const uint32_t gen_index = sequence_state.generated_count;
            const int accept_status = uocr_sequence_accept_generated_token(
                &sequence_state, token_id, NULL, 0u);
            if (accept_status != UOCR_OK) {
                [chunk_buffer release];
                UOCR_METAL_DECODE_LOOP_FAIL("chunk decode accept generated token failed: %s",
                                            uocr_status_string(accept_status));
            }
            if (result->generated_scores_f32_or_null != NULL) {
                result->generated_scores_f32_or_null[gen_index] = score;
            }
            result->generated_count = sequence_state.generated_count;
            result->last_token_id = (uint32_t)token_id;
            result->last_score_f32 = score;

            if (sequence_state.eos) {
                result->stopped_on_eos = 1u;
                chunk_loop_eos = 1;
                /* Trim at EOS: the remaining tokens in this chunk beyond EOS
                 * are junk; the caller sees generated_count as stopped. */
                metal_profile_add_event_ms(ctx, "metal.chunk.eos_trim", 0.0);
                break;
            }
        }

        /* Update hidden_for_selection for the next chunk.
         * After decode_one, the output is in segment 0. */
        if (!chunk_loop_eos && !uocr_sequence_generation_done(&sequence_state)) {
            if (!metal_hidden_arena_segment_slice(ctx, request->slot, 0u, 1u,
                                                  &hidden_for_selection, &one_hidden_bytes) ||
                one_hidden_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
                [chunk_buffer release];
                UOCR_METAL_DECODE_LOOP_FAIL("chunk decode hidden slice refresh failed");
            }
        }
    }

    [chunk_buffer release];
    metal_profile_add_event_now(ctx, "metal.decode_loop", decode_loop_start_ns);

decode_loop_done:
#undef UOCR_METAL_DECODE_LOOP_FAIL

    if (!metal_hot_path_alloc_guard_end(ctx,
                                        &decode_loop_guard,
                                        "integrated Metal fp16 decode token loop",
                                        error,
                                        error_size)) {
        metal_command_batch_abort(ctx);
        uocr_free(sequence);
        return 0;
    }
    uocr_free(sequence);
    if (!decode_loop_ok) {
        metal_command_batch_abort(ctx);
        return metal_fail(error, error_size, "%s", decode_loop_error);
    }
    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_generate_f16(uocr_metal_context *ctx,
                                    const uocr_metal_decoder_request_f16 *request,
                                    uocr_metal_decoder_result_f16 *result,
                                    char *error,
                                    size_t error_size) {
    const int ok = metal_context_generate_f16_impl(ctx,
                                                  request,
                                                  nil,
                                                  0u,
                                                  result,
                                                  error,
                                                  error_size);
    return ok;
}

static int metal_context_generate_image_f16_impl(uocr_metal_context *ctx,
                                          const uocr_prepared_request *request,
                                          uint32_t max_views_per_chunk,
                                          uint32_t slot,
                                          uocr_metal_decoder_result_f16 *result,
                                          uocr_metal_runtime_arena_prepare_fn prepare_runtime,
                                          void *prepare_user,
                                          char *error,
                                          size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || request == NULL || result == NULL) {
        return metal_fail(error, error_size, "invalid Metal image generation request");
    }
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }

    char detail[512];
    detail[0] = '\0';
    uocr_sequence_state sequence_state;
    memset(&sequence_state, 0, sizeof(sequence_state));
    int status = uocr_build_sequence_state(request, &sequence_state, detail, sizeof(detail));
    if (status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation sequence validation failed: %s",
                          detail[0] != '\0' ? detail : uocr_status_string(status));
    }
    if (sequence_state.image_span_start == UOCR_SEQUENCE_NO_IMAGE_SPAN || sequence_state.image_span_length == 0u) {
        return metal_fail(error, error_size, "Metal image generation requires one image span");
    }

    uocr_vision_schedule schedule;
    memset(&schedule, 0, sizeof(schedule));
    detail[0] = '\0';
    status = uocr_plan_vision_schedule(request, max_views_per_chunk, NULL, 0u, &schedule, detail, sizeof(detail));
    if (status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation vision schedule failed: %s",
                          detail[0] != '\0' ? detail : uocr_status_string(status));
    }
    if (schedule.final_visual_tokens == 0u || schedule.final_visual_tokens != sequence_state.image_span_length) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation visual rows %u do not match image span length %u",
                          schedule.final_visual_tokens,
                          sequence_state.image_span_length);
    }

    uocr_metal_vision_workspace scratch;
    memset(&scratch, 0, sizeof(scratch));
    const uocr_metal_runtime_arena_guard vision_arena_guard = metal_runtime_arena_guard_begin(ctx);
    const uint64_t vision_start_ns = uocr_profile_now_ns();
    const int vision_ok = metal_context_encode_visual_features_to_workspace_f16(ctx,
                                                                                request,
                                                                                max_views_per_chunk,
                                                                                &schedule,
                                                                                &scratch,
                                                                                0,
                                                                                error,
                                                                                error_size);
    if (!metal_runtime_arena_guard_end(ctx,
                                       &vision_arena_guard,
                                       "Metal image vision hot path",
                                       error,
                                       error_size)) {
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
        metal_vision_workspace_reset(&scratch);
        return 0;
    }
    if (!vision_ok) {
        char vision_detail[512];
        metal_copy_error_detail(vision_detail, sizeof(vision_detail), error);
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
        metal_vision_workspace_reset(&scratch);
        return metal_fail(error, error_size, "Metal image vision encoding failed: %s", vision_detail);
    }
    metal_profile_add_event_now(ctx, "metal.vision", vision_start_ns);

    id<MTLBuffer> final_visual_rows_buffer = scratch.final_visual_rows.buffer;
    const NSUInteger final_visual_rows_offset = scratch.final_visual_rows.offset;
    if (final_visual_rows_buffer == nil) {
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
        uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
        metal_vision_workspace_reset(&scratch);
        return metal_fail(error, error_size, "Metal image generation final visual rows buffer is not allocated");
    }
    uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
    metal_vision_workspace_reset(&scratch);
    metal_profile_add_event_ms(ctx, "metal.vision.chunk_scratch_release", 0.0);

    if (prepare_runtime != NULL) {
        const uint64_t runtime_prepare_start_ns = uocr_profile_now_ns();
        char runtime_error[512];
        runtime_error[0] = '\0';
        if (!prepare_runtime(prepare_user, 1u, request->n_tokens, runtime_error, sizeof(runtime_error))) {
            uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
            return metal_fail(error,
                              error_size,
                              "Metal image generation deferred runtime arena preparation failed: %s",
                              runtime_error[0] != '\0' ? runtime_error : "unknown error");
        }
        metal_profile_add_event_now(ctx, "metal.runtime_arena_prepare_deferred", runtime_prepare_start_ns);
    }

    uocr_metal_decoder_request_f16 decoder_request;
    memset(&decoder_request, 0, sizeof(decoder_request));
    decoder_request.input_ids = request->input_ids;
    decoder_request.image_mask = request->image_mask;
    decoder_request.image_features_f16 = NULL;
    decoder_request.n_tokens = request->n_tokens;
    decoder_request.max_new_tokens = request->max_new_tokens;
    decoder_request.slot = slot;
    decoder_request.image_span_start = sequence_state.image_span_start;
    decoder_request.image_span_length = sequence_state.image_span_length;

    const uint64_t generate_start_ns = uocr_profile_now_ns();
    const int ok = metal_context_generate_f16_impl(ctx,
                                                   &decoder_request,
                                                   final_visual_rows_buffer,
                                                   final_visual_rows_offset,
                                                   result,
                                                   error,
                                                   error_size);
    if (ok) {
        metal_profile_add_event_now(ctx, "metal.image_generate", generate_start_ns);
    }
    uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION);
    uocr_metal_context_release_scratch(ctx, UOCR_METAL_SCRATCH_VISION_FINAL);
    return ok;
}

int uocr_metal_context_generate_image_f16(uocr_metal_context *ctx,
                                          const uocr_prepared_request *request,
                                          uint32_t max_views_per_chunk,
                                          uint32_t slot,
                                          uocr_metal_decoder_result_f16 *result,
                                          char *error,
                                          size_t error_size) {
    const int ok = metal_context_generate_image_f16_impl(ctx,
                                                        request,
                                                        max_views_per_chunk,
                                                        slot,
                                                        result,
                                                        NULL,
                                                        NULL,
                                                        error,
                                                        error_size);
    return ok;
}

int uocr_metal_context_generate_image_f16_deferred_runtime(uocr_metal_context *ctx,
                                                           const uocr_prepared_request *request,
                                                           uint32_t max_views_per_chunk,
                                                           uint32_t slot,
                                                           uocr_metal_decoder_result_f16 *result,
                                                           uocr_metal_runtime_arena_prepare_fn prepare_runtime,
                                                           void *prepare_user,
                                                           char *error,
                                                           size_t error_size) {
    if (prepare_runtime == NULL) {
        return metal_fail(error, error_size, "Metal deferred image generation requires a runtime preparation callback");
    }
    const int ok = metal_context_generate_image_f16_impl(ctx,
                                                        request,
                                                        max_views_per_chunk,
                                                        slot,
                                                        result,
                                                        prepare_runtime,
                                                        prepare_user,
                                                        error,
                                                        error_size);
    return ok;
}
static int validate_prompt_text_token_ids(const int32_t *input_ids,
                                          uint32_t n_tokens,
                                          uint32_t table_rows,
                                          uint32_t image_span_start,
                                          uint32_t image_span_length,
                                          char *error,
                                          size_t error_size) {
    const int has_image_span = image_span_length != 0u;
    const uint64_t image_span_end = has_image_span ? (uint64_t)image_span_start + (uint64_t)image_span_length : 0u;
    for (uint32_t i = 0u; i < n_tokens; ++i) {
        if (has_image_span && i >= image_span_start && (uint64_t)i < image_span_end) {
            continue;
        }
        if (input_ids[i] < 0 || (uint32_t)input_ids[i] >= table_rows) {
            return metal_fail(error,
                              error_size,
                              "Metal prompt token id %d at position %u is outside embedding rows %u",
                              input_ids[i],
                              i,
                              table_rows);
        }
    }
    return 1;
}

static int metal_context_assemble_prompt_f16_with_table_buffer_to_buffer(uocr_metal_context *ctx,
                                                                          id<MTLBuffer> table_buffer,
                                                                          NSUInteger table_offset,
                                                                          uint32_t table_rows,
                                                                          uint32_t hidden_size,
                                                                          const int32_t *input_ids,
                                                                          uint32_t n_tokens,
                                                                          id<MTLBuffer> input_ids_buffer,
                                                                          NSUInteger input_ids_offset,
                                                                          uint32_t image_span_start,
                                                                          uint32_t image_span_length,
                                                                          const uint16_t *image_features_f16,
                                                                          id<MTLBuffer> image_features_buffer,
                                                                          NSUInteger image_features_offset,
                                                                          id<MTLBuffer> dst_buffer,
                                                                          NSUInteger dst_offset,
                                                                          const char *op_name,
                                                                          char *error,
                                                                          size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal prompt assembly";
    if (ctx == NULL || table_buffer == nil || input_ids == NULL || dst_buffer == nil ||
        table_rows == 0u || hidden_size == 0u || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    const int has_image_span = image_span_length != 0u;
    if (has_image_span) {
        uint64_t image_end = 0u;
        if (image_span_start == UINT32_MAX ||
            !checked_add_u64((uint64_t)image_span_start, (uint64_t)image_span_length, &image_end) ||
            image_span_start >= n_tokens || image_end > (uint64_t)n_tokens) {
            return metal_fail(error,
                              error_size,
                              "%s image span [%u,%llu) is outside %u tokens",
                              op,
                              image_span_start,
                              (unsigned long long)image_end,
                              n_tokens);
        }
        if (image_features_f16 == NULL && image_features_buffer == nil) {
            return metal_fail(error, error_size, "%s image span requires image features", op);
        }
    } else if (image_span_start != UINT32_MAX) {
        return metal_fail(error, error_size, "%s text-only path should use UINT32_MAX image span start", op);
    }

    if (!validate_prompt_text_token_ids(input_ids,
                                        n_tokens,
                                        table_rows,
                                        image_span_start,
                                        image_span_length,
                                        error,
                                        error_size)) {
        return 0;
    }

    uint64_t table_values = 0u;
    uint64_t table_bytes = 0u;
    uint64_t token_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t image_values = 0u;
    uint64_t image_bytes = 0u;
    if (!checked_mul_u64((uint64_t)table_rows, (uint64_t)hidden_size, &table_values) ||
        !checked_mul_u64(table_values, 2u, &table_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)sizeof(int32_t), &token_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)hidden_size, &output_values) ||
        !checked_mul_u64(output_values, 2u, &output_bytes) ||
        !checked_mul_u64((uint64_t)image_span_length, (uint64_t)hidden_size, &image_values) ||
        !checked_mul_u64(image_values, 2u, &image_bytes)) {
        return metal_fail(error, error_size, "%s byte-size overflow", op);
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (token_bytes > max_buffer_length || image_bytes > max_buffer_length ||
        token_bytes > (uint64_t)SIZE_MAX || image_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "%s transient buffers exceed maxBufferLength %llu",
                          op,
                          (unsigned long long)max_buffer_length);
    }
    const uint64_t table_offset_u64 = (uint64_t)table_offset;
    const uint64_t table_length = (uint64_t)[table_buffer length];
    uint64_t table_end = 0u;
    if (!checked_add_u64(table_offset_u64, table_bytes, &table_end) || table_end > table_length) {
        return metal_fail(error,
                          error_size,
                          "%s embedding table range [%llu,%llu) exceeds Metal buffer length %llu",
                          op,
                          (unsigned long long)table_offset_u64,
                          (unsigned long long)table_end,
                          (unsigned long long)table_length);
    }
    if (has_image_span && image_features_buffer != nil) {
        const uint64_t image_offset_u64 = (uint64_t)image_features_offset;
        const uint64_t image_length = (uint64_t)[image_features_buffer length];
        uint64_t image_end = 0u;
        if (!checked_add_u64(image_offset_u64, image_bytes, &image_end) || image_end > image_length) {
            return metal_fail(error,
                              error_size,
                              "%s image-feature range [%llu,%llu) exceeds Metal buffer length %llu",
                              op,
                              (unsigned long long)image_offset_u64,
                              (unsigned long long)image_end,
                              (unsigned long long)image_length);
        }
    }

    const uint64_t dst_offset_u64 = (uint64_t)dst_offset;
    const uint64_t dst_length = (uint64_t)[dst_buffer length];
    uint64_t dst_end = 0u;
    if (!checked_add_u64(dst_offset_u64, output_bytes, &dst_end) || dst_end > dst_length) {
        return metal_fail(error,
                          error_size,
                          "%s output range [%llu,%llu) exceeds Metal buffer length %llu",
                          op,
                          (unsigned long long)dst_offset_u64,
                          (unsigned long long)dst_end,
                          (unsigned long long)dst_length);
    }

    uint64_t image_dst_offset = 0u;
    if (has_image_span) {
        uint64_t image_dst_values = 0u;
        uint64_t image_dst_delta = 0u;
        if (!checked_mul_u64((uint64_t)image_span_start, (uint64_t)hidden_size, &image_dst_values) ||
            !checked_mul_u64(image_dst_values, 2u, &image_dst_delta) ||
            !checked_add_u64(dst_offset_u64, image_dst_delta, &image_dst_offset) ||
            image_dst_offset > (uint64_t)NSUIntegerMax || image_bytes > (uint64_t)NSUIntegerMax) {
            return metal_fail(error, error_size, "%s image-span output offset overflow", op);
        }
    }

    @autoreleasepool {
        const char *function_name = has_image_span ? "uocr_assemble_prompt_text_skip_image_f16" : "uocr_assemble_prompt_text_f16";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> tokens = input_ids_buffer;
        NSUInteger tokens_bind_offset = input_ids_offset;
        int owns_tokens = 0;
        if (tokens != nil) {
            const uint64_t token_offset_u64 = (uint64_t)input_ids_offset;
            const uint64_t token_length = (uint64_t)[tokens length];
            uint64_t token_end = 0u;
            if (!checked_add_u64(token_offset_u64, token_bytes, &token_end) || token_end > token_length) {
                return metal_fail(error,
                                  error_size,
                                  "%s persistent token-id range [%llu,%llu) exceeds Metal buffer length %llu",
                                  op,
                                  (unsigned long long)token_offset_u64,
                                  (unsigned long long)token_end,
                                  (unsigned long long)token_length);
            }
        } else {
            tokens = metal_new_buffer_with_bytes(ctx, input_ids, (NSUInteger)token_bytes, MTLResourceStorageModeShared);
            if (tokens == nil) {
                return metal_fail(error, error_size, "failed to allocate %s token-id buffer", op);
            }
            tokens.label = @"uocr_prompt_input_ids";
            tokens_bind_offset = 0u;
            owns_tokens = 1;
        }

        id<MTLBuffer> image_features = nil;
        NSUInteger image_features_bind_offset = 0u;
        int owns_image_features = 0;
        if (has_image_span) {
            if (image_features_buffer != nil) {
                image_features = image_features_buffer;
                image_features_bind_offset = image_features_offset;
            } else {
                image_features = metal_new_buffer_with_bytes(ctx, image_features_f16, (NSUInteger)image_bytes, MTLResourceStorageModeShared);
                if (image_features == nil) {
                    if (owns_tokens) {
                        [tokens release];
                    }
                    return metal_fail(error, error_size, "failed to allocate %s image-feature buffer", op);
                }
                image_features.label = @"uocr_prompt_image_features_f16";
                owns_image_features = 1;
            }
        }

        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
        if (cb == nil) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_prompt_assembly_command_buffer";
        }

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return metal_fail(error, error_size, "failed to create %s command encoder", op);
        }

        uocr_metal_prompt_assembly_params params;
        params.table_rows = table_rows;
        params.hidden_size = hidden_size;
        params.n_tokens = n_tokens;
        params.image_span_start = has_image_span ? image_span_start : UINT32_MAX;
        params.image_span_length = image_span_length;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const uint64_t token_gather_start_ns = uocr_profile_now_ns();
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:table_buffer offset:table_offset atIndex:0u];
        [enc setBuffer:tokens offset:tokens_bind_offset atIndex:1u];
        [enc setBuffer:dst_buffer offset:dst_offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];

        const NSUInteger dispatch_width = (NSUInteger)(((uint64_t)hidden_size + UOCR_METAL_HALF4_WIDTH - 1u) /
                                                       UOCR_METAL_HALF4_WIDTH);
        NSUInteger threads_per_group = pipeline.threadExecutionWidth;
        if (threads_per_group == 0u) {
            threads_per_group = 1u;
        }
        if (threads_per_group > dispatch_width) {
            threads_per_group = dispatch_width;
        }
        [enc dispatchThreads:MTLSizeMake(dispatch_width, (NSUInteger)n_tokens, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        metal_profile_add_event_now(ctx, "metal.prompt.token_gather", token_gather_start_ns);
        metal_profile_add_event_now(ctx, "metal.prefill.token_gather", token_gather_start_ns);

        if (has_image_span) {
            const uint64_t image_blit_start_ns = uocr_profile_now_ns();
            id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
            if (blit == nil) {
                if (owns_image_features) {
                    [image_features release];
                }
                if (owns_tokens) {
                    [tokens release];
                }
                return metal_fail(error, error_size, "failed to create %s image-span blit encoder", op);
            }
            [blit copyFromBuffer:image_features
                    sourceOffset:image_features_bind_offset
                        toBuffer:dst_buffer
               destinationOffset:(NSUInteger)image_dst_offset
                            size:(NSUInteger)image_bytes];
            [blit endEncoding];
            metal_profile_add_event_now(ctx, "metal.prompt.image_span_blit", image_blit_start_ns);
            metal_profile_add_event_now(ctx, "metal.prefill.image_span_blit", image_blit_start_ns);
        }

        if (!owned_command_buffer) {
            if (owns_tokens && !metal_retain_transient_until_completed(ctx, cb, tokens, error, error_size)) {
                if (owns_image_features) {
                    [image_features release];
                }
                [tokens release];
                return 0;
            }
            if (owns_image_features && !metal_retain_transient_until_completed(ctx, cb, image_features, error, error_size)) {
                [image_features release];
                if (owns_tokens) {
                    [tokens release];
                }
                return 0;
            }
        }
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size)) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return 0;
        }

        if (owns_image_features) {
            [image_features release];
        }
        if (owns_tokens) {
            [tokens release];
        }
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int metal_context_assemble_prompt_q8_0_with_table_buffer_to_buffer(uocr_metal_context *ctx,
                                                                            id<MTLBuffer> qweight_buffer,
                                                                            NSUInteger qweight_offset,
                                                                            id<MTLBuffer> qscale_buffer,
                                                                            NSUInteger qscale_offset,
                                                                            uint32_t table_rows,
                                                                            uint32_t hidden_size,
                                                                            const int32_t *input_ids,
                                                                            uint32_t n_tokens,
                                                                            id<MTLBuffer> input_ids_buffer,
                                                                            NSUInteger input_ids_offset,
                                                                            uint32_t image_span_start,
                                                                            uint32_t image_span_length,
                                                                            const uint16_t *image_features_f16,
                                                                            id<MTLBuffer> image_features_buffer,
                                                                            NSUInteger image_features_offset,
                                                                            id<MTLBuffer> dst_buffer,
                                                                            NSUInteger dst_offset,
                                                                            const char *op_name,
                                                                            char *error,
                                                                            size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal Q8 prompt assembly";
    if (ctx == NULL || qweight_buffer == nil || qscale_buffer == nil || input_ids == NULL || dst_buffer == nil ||
        table_rows == 0u || hidden_size != UOCR_HIDDEN_SIZE || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    const int has_image_span = image_span_length != 0u;
    if (has_image_span) {
        uint64_t image_end = 0u;
        if (image_span_start == UINT32_MAX ||
            !checked_add_u64((uint64_t)image_span_start, (uint64_t)image_span_length, &image_end) ||
            image_span_start >= n_tokens || image_end > (uint64_t)n_tokens) {
            return metal_fail(error,
                              error_size,
                              "%s image span [%u,%llu) is outside %u tokens",
                              op,
                              image_span_start,
                              (unsigned long long)image_end,
                              n_tokens);
        }
        if (image_features_f16 == NULL && image_features_buffer == nil) {
            return metal_fail(error, error_size, "%s image span requires image features", op);
        }
    } else if (image_span_start != UINT32_MAX) {
        return metal_fail(error, error_size, "%s text-only path should use UINT32_MAX image span start", op);
    }

    if (!validate_prompt_text_token_ids(input_ids,
                                        n_tokens,
                                        table_rows,
                                        image_span_start,
                                        image_span_length,
                                        error,
                                        error_size)) {
        return 0;
    }

    const uint64_t qweight_bytes = uocr_q8_0_qweight_bytes(table_rows, hidden_size);
    const uint64_t qscale_bytes = uocr_q8_0_qscale_bytes(table_rows, hidden_size, UOCR_Q8_GROUP_SIZE_DEFAULT);
    uint64_t token_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t image_values = 0u;
    uint64_t image_bytes = 0u;
    if (qscale_bytes == 0u ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)sizeof(int32_t), &token_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)hidden_size, &output_values) ||
        !checked_mul_u64(output_values, 2u, &output_bytes) ||
        !checked_mul_u64((uint64_t)image_span_length, (uint64_t)hidden_size, &image_values) ||
        !checked_mul_u64(image_values, 2u, &image_bytes)) {
        return metal_fail(error, error_size, "%s byte-size overflow", op);
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (token_bytes > max_buffer_length || image_bytes > max_buffer_length ||
        token_bytes > (uint64_t)SIZE_MAX || image_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "%s transient buffers exceed maxBufferLength %llu",
                          op,
                          (unsigned long long)max_buffer_length);
    }
    if (!metal_buffer_range_valid(qweight_buffer, qweight_offset, qweight_bytes) ||
        !metal_buffer_range_valid(qscale_buffer, qscale_offset, qscale_bytes) ||
        !metal_buffer_range_valid(dst_buffer, dst_offset, output_bytes)) {
        return metal_fail(error, error_size, "%s buffer range validation failed", op);
    }
    if (has_image_span && image_features_buffer != nil &&
        !metal_buffer_range_valid(image_features_buffer, image_features_offset, image_bytes)) {
        return metal_fail(error, error_size, "%s image-feature buffer range validation failed", op);
    }

    uint64_t image_dst_offset = 0u;
    if (has_image_span) {
        uint64_t image_dst_values = 0u;
        uint64_t image_dst_delta = 0u;
        if (!checked_mul_u64((uint64_t)image_span_start, (uint64_t)hidden_size, &image_dst_values) ||
            !checked_mul_u64(image_dst_values, 2u, &image_dst_delta) ||
            !checked_add_u64((uint64_t)dst_offset, image_dst_delta, &image_dst_offset) ||
            image_dst_offset > (uint64_t)NSUIntegerMax || image_bytes > (uint64_t)NSUIntegerMax) {
            return metal_fail(error, error_size, "%s image-span output offset overflow", op);
        }
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx,
                                                                  "uocr_get_rows_q8_0_to_f16_h1280_g64",
                                                                  error,
                                                                  error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> tokens = input_ids_buffer;
        NSUInteger tokens_bind_offset = input_ids_offset;
        int owns_tokens = 0;
        if (tokens != nil) {
            if (!metal_buffer_range_valid(tokens, tokens_bind_offset, token_bytes)) {
                return metal_fail(error, error_size, "%s persistent token-id range validation failed", op);
            }
        } else {
            tokens = metal_new_buffer_with_bytes(ctx, input_ids, (NSUInteger)token_bytes, MTLResourceStorageModeShared);
            if (tokens == nil) {
                return metal_fail(error, error_size, "failed to allocate %s token-id buffer", op);
            }
            tokens.label = @"uocr_prompt_input_ids_q8";
            tokens_bind_offset = 0u;
            owns_tokens = 1;
        }

        id<MTLBuffer> image_features = nil;
        NSUInteger image_features_bind_offset = 0u;
        int owns_image_features = 0;
        if (has_image_span) {
            if (image_features_buffer != nil) {
                image_features = image_features_buffer;
                image_features_bind_offset = image_features_offset;
            } else {
                image_features = metal_new_buffer_with_bytes(ctx, image_features_f16, (NSUInteger)image_bytes, MTLResourceStorageModeShared);
                if (image_features == nil) {
                    if (owns_tokens) [tokens release];
                    return metal_fail(error, error_size, "failed to allocate %s image-feature buffer", op);
                }
                image_features.label = @"uocr_prompt_image_features_f16";
                owns_image_features = 1;
            }
        }

        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
        if (cb == nil) {
            if (owns_image_features) [image_features release];
            if (owns_tokens) [tokens release];
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_prompt_assembly_q8_command_buffer";
        }

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            if (owns_image_features) [image_features release];
            if (owns_tokens) [tokens release];
            return metal_fail(error, error_size, "failed to create %s command encoder", op);
        }

        uocr_metal_get_rows_q8_params params;
        memset(&params, 0, sizeof(params));
        params.table_rows = table_rows;
        params.logical_width = hidden_size;
        params.physical_width = hidden_size;
        params.n_row_ids = n_tokens;
        params.row_size = hidden_size;

        const uint64_t token_gather_start_ns = uocr_profile_now_ns();
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:qweight_buffer offset:qweight_offset atIndex:0u];
        [enc setBuffer:qscale_buffer offset:qscale_offset atIndex:1u];
        [enc setBuffer:tokens offset:tokens_bind_offset atIndex:2u];
        [enc setBuffer:dst_buffer offset:dst_offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        const NSUInteger dispatch_width = (NSUInteger)((hidden_size + UOCR_METAL_HALF4_WIDTH - 1u) /
                                                       UOCR_METAL_HALF4_WIDTH);
        NSUInteger threads_per_group = pipeline.threadExecutionWidth;
        if (threads_per_group == 0u) threads_per_group = 1u;
        if (threads_per_group > dispatch_width) threads_per_group = dispatch_width;
        [enc dispatchThreads:MTLSizeMake(dispatch_width, (NSUInteger)n_tokens, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        metal_profile_add_event_now(ctx, "metal.prompt.token_gather_q8", token_gather_start_ns);
        metal_profile_add_event_now(ctx, "metal.prefill.token_gather_q8", token_gather_start_ns);

        if (has_image_span) {
            const uint64_t image_blit_start_ns = uocr_profile_now_ns();
            id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
            if (blit == nil) {
                if (owns_image_features) [image_features release];
                if (owns_tokens) [tokens release];
                return metal_fail(error, error_size, "failed to create %s image-span blit encoder", op);
            }
            [blit copyFromBuffer:image_features
                    sourceOffset:image_features_bind_offset
                        toBuffer:dst_buffer
               destinationOffset:(NSUInteger)image_dst_offset
                            size:(NSUInteger)image_bytes];
            [blit endEncoding];
            metal_profile_add_event_now(ctx, "metal.prompt.image_span_blit", image_blit_start_ns);
            metal_profile_add_event_now(ctx, "metal.prefill.image_span_blit", image_blit_start_ns);
        }

        if (!owned_command_buffer) {
            if (owns_tokens && !metal_retain_transient_until_completed(ctx, cb, tokens, error, error_size)) {
                if (owns_image_features) [image_features release];
                [tokens release];
                return 0;
            }
            if (owns_image_features && !metal_retain_transient_until_completed(ctx, cb, image_features, error, error_size)) {
                [image_features release];
                if (owns_tokens) [tokens release];
                return 0;
            }
        }
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size)) {
            if (owns_image_features) [image_features release];
            if (owns_tokens) [tokens release];
            return 0;
        }

        if (owns_image_features) [image_features release];
        if (owns_tokens) [tokens release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int metal_context_assemble_prompt_q8_0_with_table_buffer(uocr_metal_context *ctx,
                                                                 id<MTLBuffer> qweight_buffer,
                                                                 NSUInteger qweight_offset,
                                                                 id<MTLBuffer> qscale_buffer,
                                                                 NSUInteger qscale_offset,
                                                                 uint32_t table_rows,
                                                                 uint32_t hidden_size,
                                                                 const int32_t *input_ids,
                                                                 uint32_t n_tokens,
                                                                 uint32_t image_span_start,
                                                                 uint32_t image_span_length,
                                                                 const uint16_t *image_features_f16,
                                                                 uint16_t *out_prompt_f16,
                                                                 const char *op_name,
                                                                 char *error,
                                                                 size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal Q8 prompt assembly";
    if (ctx == NULL || qweight_buffer == nil || qscale_buffer == nil || input_ids == NULL || out_prompt_f16 == NULL ||
        table_rows == 0u || hidden_size == 0u || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    if (!checked_mul_u64((uint64_t)n_tokens, (uint64_t)hidden_size, &output_values) ||
        !checked_mul_u64(output_values, 2u, &output_bytes) || output_bytes > (uint64_t)SIZE_MAX ||
        output_bytes > metal_device_max_buffer_length(ctx->device)) {
        return metal_fail(error, error_size, "%s output byte-size overflow", op);
    }

    @autoreleasepool {
        id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, (NSUInteger)output_bytes, MTLResourceStorageModeShared);
        if (dst == nil) {
            return metal_fail(error, error_size, "failed to allocate %s output buffer", op);
        }
        dst.label = @"uocr_prompt_embeddings_q8_to_f16";

        const int status = metal_context_assemble_prompt_q8_0_with_table_buffer_to_buffer(ctx,
                                                                                           qweight_buffer,
                                                                                           qweight_offset,
                                                                                           qscale_buffer,
                                                                                           qscale_offset,
                                                                                           table_rows,
                                                                                           hidden_size,
                                                                                           input_ids,
                                                                                           n_tokens,
                                                                                           nil,
                                                                                           0u,
                                                                                           image_span_start,
                                                                                           image_span_length,
                                                                                           image_features_f16,
                                                                                           nil,
                                                                                           0u,
                                                                                           dst,
                                                                                           0u,
                                                                                           op,
                                                                                           error,
                                                                                           error_size);
        if (status == 1) {
            memcpy(out_prompt_f16, [dst contents], (size_t)output_bytes);
        }
        [dst release];
        return status;
    }
}

