        !checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &window_tokens_per_view) ||
        !checked_mul_u64(window_tokens_per_view, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &window_values_per_view) ||
        !checked_mul_u64(window_values_per_view, (uint64_t)view_count, &window_values) ||
        !metal_vision_f16_bytes(window_values, &window_bytes) || output_values > (uint64_t)UINT32_MAX ||
        !metal_vision_require_workspace_slice(windows, window_bytes, "SAM window unpartition batch input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_bhwc, output_bytes, "SAM window unpartition batch output", error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_window_unpartition_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal SAM window unpartition batch", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM window unpartition batch command encoder");
        }

        uocr_metal_sam_window_partition_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.padded_width = padded_w;
        params.padded_height = padded_h;
        params.windows_per_row = windows_per_row;
        params.windows_per_col = windows_per_col;
        params.window_size = UOCR_SAM_WINDOW_SIZE;
        params.hidden_size = UOCR_SAM_HIDDEN_SIZE;
        params.batch_size = view_count;

        const NSUInteger threads_per_group = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:windows.buffer offset:windows.offset atIndex:0u];
        [enc setBuffer:out_bhwc.buffer offset:out_bhwc.offset atIndex:1u];
        [enc setBytes:&params length:sizeof(params) atIndex:2u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)output_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal SAM window unpartition batch", error, error_size);
    }
}

static int metal_context_sam_global_attention_mps_f16_to_slice(uocr_metal_context *ctx,
                                                               uocr_metal_vision_workspace_slice q,
                                                               uocr_metal_vision_workspace_slice k,
                                                               uocr_metal_vision_workspace_slice v,
                                                               uocr_metal_vision_tensor_f16 rel_pos_h,
                                                               uocr_metal_vision_tensor_f16 rel_pos_w,
                                                               uint32_t grid_w,
                                                               uint32_t grid_h,
                                                               uint32_t view_count,
                                                               uint32_t rel_pos_h_length,
                                                               uint32_t rel_pos_w_length,
                                                               uocr_metal_vision_workspace_slice out,
                                                               uocr_metal_vision_workspace *scratch,
                                                               const uocr_metal_sam_rel_pos_attention_params *params,
                                                               char *error,
                                                               size_t error_size) {
    const uint32_t tokens = grid_w * grid_h;
    const uint32_t logical_heads = view_count * UOCR_SAM_ATTENTION_HEADS;
    const uint64_t pack_values = (uint64_t)logical_heads * (uint64_t)tokens * (uint64_t)UOCR_SAM_HEAD_DIM;
    const uint64_t pack_bytes = pack_values * 2u;
    const uint64_t logits_values = (uint64_t)logical_heads * (uint64_t)tokens * (uint64_t)tokens;
    const uint64_t logits_f32_bytes = logits_values * (uint64_t)sizeof(float);
    const uint64_t probs_bytes = logits_values * 2u;
    const uint64_t rel_h_bytes = (uint64_t)logical_heads * (uint64_t)tokens * (uint64_t)grid_h * (uint64_t)sizeof(float);
    const uint64_t rel_w_bytes = (uint64_t)logical_heads * (uint64_t)tokens * (uint64_t)grid_w * (uint64_t)sizeof(float);
    const uint64_t io_bytes = (uint64_t)view_count * (uint64_t)tokens * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    if (ctx == NULL || scratch == NULL || params == NULL || grid_w == 0u || grid_h == 0u || view_count == 0u ||
        rel_pos_h_length != 2u * grid_h - 1u || rel_pos_w_length != 2u * grid_w - 1u ||
        !metal_vision_require_workspace_slice(q, io_bytes, "SAM global attention Q", error, error_size) ||
        !metal_vision_require_workspace_slice(k, io_bytes, "SAM global attention K", error, error_size) ||
        !metal_vision_require_workspace_slice(v, io_bytes, "SAM global attention V", error, error_size) ||
        !metal_vision_require_workspace_slice(out, io_bytes, "SAM global attention output", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_global_q_pack, pack_bytes, "SAM global attention Q pack", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_global_k_pack, pack_bytes, "SAM global attention K pack", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_global_vt_pack, pack_bytes, "SAM global attention VT pack", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_global_probs, probs_bytes, "SAM global attention probabilities", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_global_out_pack, pack_bytes, "SAM global attention output pack", error, error_size) ||
        scratch->sam_global_logits_f32.bytes < logits_f32_bytes ||
        scratch->sam_global_rel_h_f32.bytes < rel_h_bytes ||
        scratch->sam_global_rel_w_f32.bytes < rel_w_bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){scratch->sam_global_logits_f32.buffer, scratch->sam_global_logits_f32.offset}, logits_f32_bytes) ||
        !metal_slice_valid((uocr_metal_buffer_slice){scratch->sam_global_rel_h_f32.buffer, scratch->sam_global_rel_h_f32.offset}, rel_h_bytes) ||
        !metal_slice_valid((uocr_metal_buffer_slice){scratch->sam_global_rel_w_f32.buffer, scratch->sam_global_rel_w_f32.offset}, rel_w_bytes)) {
        return metal_fail(error, error_size, "invalid Metal SAM global MPS attention request");
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pack_pipeline = metal_get_pipeline(ctx, "uocr_sam_global_attention_pack_qkv_f16", error, error_size);
        id<MTLComputePipelineState> rel_pipeline = metal_get_pipeline(ctx, "uocr_sam_rel_pos_logits_f16_to_f32", error, error_size);
        if (pack_pipeline == nil || rel_pipeline == nil) {
            return 0;
        }
        NSUInteger rel_threads = 0u;
        if (!metal_flash_attention_threads_per_threadgroup(rel_pipeline,
                                                           1u,
                                                           UOCR_SAM_HEAD_DIM,
                                                           "Metal SAM global rel-pos logits",
                                                           &rel_threads,
                                                           error,
                                                           error_size)) {
            return 0;
        }
        int owned = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned, "Metal SAM global attention pack", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM global attention pack encoder");
        }
        const NSUInteger pack_threads = metal_power2_threadgroup_width(256u, pack_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:pack_pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
        [enc setBuffer:scratch->sam_global_q_pack.buffer offset:scratch->sam_global_q_pack.offset atIndex:3u];
        [enc setBuffer:scratch->sam_global_k_pack.buffer offset:scratch->sam_global_k_pack.offset atIndex:4u];
        [enc setBuffer:scratch->sam_global_vt_pack.buffer offset:scratch->sam_global_vt_pack.offset atIndex:5u];
        [enc setBytes:params length:sizeof(*params) atIndex:6u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)pack_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(pack_threads, 1u, 1u)];

        [enc setComputePipelineState:rel_pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:rel_pos_h.slice.buffer offset:rel_pos_h.slice.offset atIndex:1u];
        [enc setBuffer:rel_pos_w.slice.buffer offset:rel_pos_w.slice.offset atIndex:2u];
        [enc setBuffer:scratch->sam_global_rel_h_f32.buffer offset:scratch->sam_global_rel_h_f32.offset atIndex:3u];
        [enc setBuffer:scratch->sam_global_rel_w_f32.buffer offset:scratch->sam_global_rel_w_f32.offset atIndex:4u];
        [enc setBytes:params length:sizeof(*params) atIndex:5u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, (NSUInteger)tokens, (NSUInteger)view_count)
             threadsPerThreadgroup:MTLSizeMake(rel_threads, 1u, 1u)];
        [enc endEncoding];
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned, "Metal SAM global attention pack", error, error_size)) {
            return 0;
        }

        uocr_metal_buffer_slice q_base = { scratch->sam_global_q_pack.buffer, scratch->sam_global_q_pack.offset };
        uocr_metal_buffer_slice k_base = { scratch->sam_global_k_pack.buffer, scratch->sam_global_k_pack.offset };
        uocr_metal_buffer_slice logits_base = { scratch->sam_global_logits_f32.buffer, scratch->sam_global_logits_f32.offset };
        for (uint32_t logical_head = 0u; logical_head < logical_heads; ++logical_head) {
            uocr_metal_buffer_slice q_head;
            uocr_metal_buffer_slice k_head;
            uocr_metal_buffer_slice logits_head;
            uint64_t unused = 0u;
            if (!metal_matrix_subslice(q_base, pack_bytes, logical_head * tokens, tokens, UOCR_SAM_HEAD_DIM, 2u, &q_head, &unused) ||
                !metal_matrix_subslice(k_base, pack_bytes, logical_head * tokens, tokens, UOCR_SAM_HEAD_DIM, 2u, &k_head, &unused) ||
                !metal_matrix_subslice(logits_base, logits_f32_bytes, logical_head * tokens, tokens, tokens, sizeof(float), &logits_head, &unused) ||
                !metal_run_mps_matmul_nt_f16_to_f32(ctx,
                                                     q_head,
                                                     k_head,
                                                     logits_head,
                                                     tokens,
                                                     UOCR_SAM_HEAD_DIM,
                                                     tokens,
                                                     "Metal SAM global attention QK MPS",
                                                     error,
                                                     error_size)) {
                return 0;
            }
        }

        id<MTLComputePipelineState> softmax_pipeline = metal_get_pipeline(ctx, "uocr_sam_global_attention_softmax_f32_to_f16", error, error_size);
        if (softmax_pipeline == nil) {
            return 0;
        }
        owned = 0;
        cb = metal_command_buffer_for_op(ctx, &owned, "Metal SAM global attention softmax", error, error_size);
        if (cb == nil) {
            return 0;
        }
        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM global attention softmax encoder");
        }
        const NSUInteger softmax_threads = metal_power2_threadgroup_width(256u, softmax_pipeline.maxTotalThreadsPerThreadgroup);
        const uint64_t softmax_tg_bytes = (uint64_t)softmax_threads * (uint64_t)sizeof(float);
        if (softmax_tg_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "Metal SAM global attention softmax threadgroup memory exceeds device limit");
        }
        [enc setComputePipelineState:softmax_pipeline];
        [enc setBuffer:scratch->sam_global_logits_f32.buffer offset:scratch->sam_global_logits_f32.offset atIndex:0u];
        [enc setBuffer:scratch->sam_global_rel_h_f32.buffer offset:scratch->sam_global_rel_h_f32.offset atIndex:1u];
        [enc setBuffer:scratch->sam_global_rel_w_f32.buffer offset:scratch->sam_global_rel_w_f32.offset atIndex:2u];
        [enc setBuffer:scratch->sam_global_probs.buffer offset:scratch->sam_global_probs.offset atIndex:3u];
        [enc setBytes:params length:sizeof(*params) atIndex:4u];
        [enc setThreadgroupMemoryLength:(NSUInteger)softmax_tg_bytes atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)tokens, (NSUInteger)logical_heads, 1u)
             threadsPerThreadgroup:MTLSizeMake(softmax_threads, 1u, 1u)];
        [enc endEncoding];
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned, "Metal SAM global attention softmax", error, error_size)) {
            return 0;
        }

        uocr_metal_buffer_slice probs_base = { scratch->sam_global_probs.buffer, scratch->sam_global_probs.offset };
        uocr_metal_buffer_slice vt_base = { scratch->sam_global_vt_pack.buffer, scratch->sam_global_vt_pack.offset };
        uocr_metal_buffer_slice out_pack_base = { scratch->sam_global_out_pack.buffer, scratch->sam_global_out_pack.offset };
        for (uint32_t logical_head = 0u; logical_head < logical_heads; ++logical_head) {
            uocr_metal_buffer_slice probs_head;
            uocr_metal_buffer_slice vt_head;
            uocr_metal_buffer_slice out_head;
            uint64_t unused = 0u;
            if (!metal_matrix_subslice(probs_base, probs_bytes, logical_head * tokens, tokens, tokens, 2u, &probs_head, &unused) ||
                !metal_matrix_subslice(vt_base, pack_bytes, logical_head * UOCR_SAM_HEAD_DIM, UOCR_SAM_HEAD_DIM, tokens, 2u, &vt_head, &unused) ||
                !metal_matrix_subslice(out_pack_base, pack_bytes, logical_head * tokens, tokens, UOCR_SAM_HEAD_DIM, 2u, &out_head, &unused) ||
                !metal_run_mps_matmul_nt_f16(ctx,
                                             probs_head,
                                             vt_head,
                                             out_head,
                                             tokens,
                                             tokens,
                                             UOCR_SAM_HEAD_DIM,
                                             "Metal SAM global attention AV MPS",
                                             error,
                                             error_size)) {
                return 0;
            }
        }

        id<MTLComputePipelineState> unpack_pipeline = metal_get_pipeline(ctx, "uocr_sam_global_attention_unpack_f16", error, error_size);
        if (unpack_pipeline == nil) {
            return 0;
        }
        owned = 0;
        cb = metal_command_buffer_for_op(ctx, &owned, "Metal SAM global attention unpack", error, error_size);
        if (cb == nil) {
            return 0;
        }
        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM global attention unpack encoder");
        }
        const NSUInteger unpack_threads = metal_power2_threadgroup_width(256u, unpack_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:unpack_pipeline];
        [enc setBuffer:scratch->sam_global_out_pack.buffer offset:scratch->sam_global_out_pack.offset atIndex:0u];
        [enc setBuffer:out.buffer offset:out.offset atIndex:1u];
        [enc setBytes:params length:sizeof(*params) atIndex:2u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)pack_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(unpack_threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned, "Metal SAM global attention unpack", error, error_size);
    }
}

static int metal_context_sam_rel_pos_attention_batch_f16_to_slice(uocr_metal_context *ctx,
                                                                  uocr_metal_vision_workspace_slice q,
                                                                  uocr_metal_vision_workspace_slice k,
                                                                  uocr_metal_vision_workspace_slice v,
                                                                  uocr_metal_vision_tensor_f16 rel_pos_h,
                                                                  uocr_metal_vision_tensor_f16 rel_pos_w,
                                                                  uint32_t n_windows,
                                                                  uint32_t grid_w,
                                                                  uint32_t grid_h,
                                                                  uint32_t view_count,
                                                                  uint32_t rel_pos_h_length,
                                                                  uint32_t rel_pos_w_length,
                                                                  uocr_metal_vision_workspace_slice out,
                                                                  uocr_metal_vision_workspace *scratch,
                                                                  char *error,
                                                                  size_t error_size) {
    uint64_t tokens = 0u;
    uint64_t values_per_view = 0u;
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    uint64_t rel_h_values = 0u;
    uint64_t rel_w_values = 0u;
    uint64_t rel_h_bytes = 0u;
    uint64_t rel_w_bytes = 0u;
    if (ctx == NULL || n_windows == 0u || view_count == 0u || grid_w == 0u || grid_h == 0u ||
        rel_pos_h_length == 0u || rel_pos_w_length == 0u ||
        !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &tokens) || tokens == 0u ||
        tokens > (uint64_t)UINT32_MAX || tokens > (uint64_t)UOCR_SAM_MAX_GRID_TOKENS ||
        !checked_mul_u64((uint64_t)n_windows, tokens, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)view_count, &values) ||
        !metal_vision_f16_bytes(values, &bytes) ||
        !checked_mul_u64((uint64_t)rel_pos_h_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_h_values) ||
        !checked_mul_u64((uint64_t)rel_pos_w_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_w_values) ||
        !metal_vision_f16_bytes(rel_h_values, &rel_h_bytes) ||
        !metal_vision_f16_bytes(rel_w_values, &rel_w_bytes) ||
        !metal_vision_require_workspace_slice(q, bytes, "SAM rel-pos batch Q", error, error_size) ||
        !metal_vision_require_workspace_slice(k, bytes, "SAM rel-pos batch K", error, error_size) ||
        !metal_vision_require_workspace_slice(v, bytes, "SAM rel-pos batch V", error, error_size) ||
        !metal_vision_require_workspace_slice(out, bytes, "SAM rel-pos batch output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(rel_pos_h, rel_h_bytes, "SAM relative position H", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(rel_pos_w, rel_w_bytes, "SAM relative position W", error, error_size)) {
        return 0;
    }
    if (grid_w > UOCR_SAM_MAX_GRID_SIZE || grid_h > UOCR_SAM_MAX_GRID_SIZE ||
        rel_pos_h_length > UOCR_SAM_MAX_REL_POS_SIZE || rel_pos_w_length > UOCR_SAM_MAX_REL_POS_SIZE) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch dimensions exceed limits");
    }
    if (UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch constants are inconsistent");
    }
    const uint64_t logical_windows = (uint64_t)n_windows * (uint64_t)view_count;
    if (logical_windows > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch window-count overflow");
    }
    const uint32_t target_h_length = 2u * grid_h - 1u;
    const uint32_t target_w_length = 2u * grid_w - 1u;
    const int rel_pos_tables_match_target = rel_pos_h_length == target_h_length && rel_pos_w_length == target_w_length;

    uocr_metal_sam_rel_pos_attention_params params;
    params.windows = n_windows;
    params.grid_width = grid_w;
    params.grid_height = grid_h;
    params.tokens_per_window = (uint32_t)tokens;
    params.heads = UOCR_SAM_ATTENTION_HEADS;
    params.head_dim = UOCR_SAM_HEAD_DIM;
    params.rel_pos_h_length = rel_pos_h_length;
    params.rel_pos_w_length = rel_pos_w_length;
    params.scale = 1.0f / sqrtf((float)UOCR_SAM_HEAD_DIM);
    params.batch_size = view_count;
    params.reserved1 = 0u;
    params.reserved2 = 0u;

    if (n_windows == 1u) {
        if (!rel_pos_tables_match_target) {
            return metal_fail(error,
                              error_size,
                              "Metal SAM global attention requires matching rel-pos path, got grid %ux%u rel %ux%u",
                              grid_w,
                              grid_h,
                              rel_pos_h_length,
                              rel_pos_w_length);
        }
        return metal_context_sam_global_attention_mps_f16_to_slice(ctx,
                                                                   q,
                                                                   k,
                                                                   v,
                                                                   rel_pos_h,
                                                                   rel_pos_w,
                                                                   grid_w,
                                                                   grid_h,
                                                                   view_count,
                                                                   rel_pos_h_length,
                                                                   rel_pos_w_length,
                                                                   out,
                                                                   scratch,
                                                                   &params,
                                                                   error,
                                                                   error_size);
    }

    if (rel_pos_tables_match_target) {
        const char *op_name = n_windows == 1u ?
                                  "Metal SAM global precomputed rel-pos attention" :
                                  "Metal SAM window precomputed rel-pos attention";
        uint64_t rel_h_logit_count = 0u;
        uint64_t rel_w_logit_count = 0u;
        uint64_t rel_h_logit_bytes = 0u;
        uint64_t rel_w_logit_bytes = 0u;
        if (!checked_mul_u64(logical_windows, (uint64_t)UOCR_SAM_ATTENTION_HEADS, &rel_h_logit_count) ||
            !checked_mul_u64(rel_h_logit_count, tokens, &rel_h_logit_count) ||
            !checked_mul_u64(rel_h_logit_count, (uint64_t)grid_h, &rel_h_logit_count) ||
            !checked_mul_u64(logical_windows, (uint64_t)UOCR_SAM_ATTENTION_HEADS, &rel_w_logit_count) ||
            !checked_mul_u64(rel_w_logit_count, tokens, &rel_w_logit_count) ||
            !checked_mul_u64(rel_w_logit_count, (uint64_t)grid_w, &rel_w_logit_count) ||
            !checked_mul_u64(rel_h_logit_count, (uint64_t)sizeof(float), &rel_h_logit_bytes) ||
            !checked_mul_u64(rel_w_logit_count, (uint64_t)sizeof(float), &rel_w_logit_bytes) ||
            rel_h_logit_bytes > (uint64_t)NSUIntegerMax || rel_w_logit_bytes > (uint64_t)NSUIntegerMax ||
            rel_h_logit_bytes > ctx->device.maxBufferLength || rel_w_logit_bytes > ctx->device.maxBufferLength) {
            return metal_fail(error, error_size, "Metal SAM precomputed rel-pos logit buffer size overflow");
        }

        @autoreleasepool {
            id<MTLComputePipelineState> logits_pipeline = metal_get_pipeline(ctx, "uocr_sam_rel_pos_logits_f16_to_f32", error, error_size);
            id<MTLComputePipelineState> attention_pipeline = metal_get_pipeline(ctx,
                                                                                "uocr_sam_rel_pos_attention_tiled_precomputed_f16_to_f16",
                                                                                error,
                                                                                error_size);
            if (logits_pipeline == nil || attention_pipeline == nil) {
                return 0;
            }
            NSUInteger logits_threads_per_group = 0u;
            NSUInteger attention_threads_per_group = 0u;
            if (!metal_flash_attention_threads_per_threadgroup(logits_pipeline,
                                                               1u,
                                                               UOCR_SAM_HEAD_DIM,
                                                               "Metal SAM rel-pos logits",
                                                               &logits_threads_per_group,
                                                               error,
                                                               error_size) ||
                !metal_flash_attention_threads_per_threadgroup(attention_pipeline,
                                                               UOCR_METAL_FLASH_Q_PER_TG,
                                                               UOCR_SAM_HEAD_DIM,
                                                               op_name,
                                                               &attention_threads_per_group,
                                                               error,
                                                               error_size)) {
                return 0;
            }

            id<MTLBuffer> rel_h_logits = metal_new_buffer_with_length(ctx,
                                                                      (NSUInteger)rel_h_logit_bytes,
                                                                      MTLResourceStorageModePrivate);
            id<MTLBuffer> rel_w_logits = metal_new_buffer_with_length(ctx,
                                                                      (NSUInteger)rel_w_logit_bytes,
                                                                      MTLResourceStorageModePrivate);
            if (rel_h_logits == nil || rel_w_logits == nil) {
                [rel_w_logits release];
                [rel_h_logits release];
                return metal_fail(error, error_size, "failed to allocate Metal SAM precomputed rel-pos logits");
            }
            rel_h_logits.label = @"uocr_sam_rel_h_logits_f32";
            rel_w_logits.label = @"uocr_sam_rel_w_logits_f32";

            int owned_command_buffer = 0;
            id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
            if (cb == nil) {
                [rel_w_logits release];
                [rel_h_logits release];
                return 0;
            }
            if (!owned_command_buffer) {
                if (!metal_retain_transient_until_completed(ctx, cb, rel_h_logits, error, error_size) ||
                    !metal_retain_transient_until_completed(ctx, cb, rel_w_logits, error, error_size)) {
                    [rel_w_logits release];
                    [rel_h_logits release];
                    return 0;
                }
            }

            id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                [rel_w_logits release];
                [rel_h_logits release];
                return metal_fail(error, error_size, "failed to create Metal SAM precomputed rel-pos attention command encoder");
            }

            [enc setComputePipelineState:logits_pipeline];
            [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
            [enc setBuffer:rel_pos_h.slice.buffer offset:rel_pos_h.slice.offset atIndex:1u];
            [enc setBuffer:rel_pos_w.slice.buffer offset:rel_pos_w.slice.offset atIndex:2u];
            [enc setBuffer:rel_h_logits offset:0u atIndex:3u];
            [enc setBuffer:rel_w_logits offset:0u atIndex:4u];
            [enc setBytes:&params length:sizeof(params) atIndex:5u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS,
                                                  (NSUInteger)tokens,
                                                  (NSUInteger)logical_windows)
                 threadsPerThreadgroup:MTLSizeMake(logits_threads_per_group, 1u, 1u)];

            const NSUInteger query_blocks = (NSUInteger)(((uint32_t)tokens + UOCR_METAL_FLASH_Q_PER_TG - 1u) / UOCR_METAL_FLASH_Q_PER_TG);
            const NSUInteger tile_keys = 16u;
            const NSUInteger tile_bytes = tile_keys * (NSUInteger)UOCR_SAM_HEAD_DIM * sizeof(uint16_t);
            [enc setComputePipelineState:attention_pipeline];
            [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
            [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
            [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
            [enc setBuffer:rel_h_logits offset:0u atIndex:3u];
            [enc setBuffer:rel_w_logits offset:0u atIndex:4u];
            [enc setBuffer:out.buffer offset:out.offset atIndex:5u];
            [enc setBytes:&params length:sizeof(params) atIndex:6u];
            [enc setThreadgroupMemoryLength:tile_bytes atIndex:0u];
            [enc setThreadgroupMemoryLength:tile_bytes atIndex:1u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, query_blocks, (NSUInteger)logical_windows)
                 threadsPerThreadgroup:MTLSizeMake(attention_threads_per_group, 1u, 1u)];
            [enc endEncoding];

            const int result = metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
            [rel_w_logits release];
            [rel_h_logits release];
            return result;
        }
    }

    const char *kernel_name = "uocr_sam_rel_pos_attention_flash_f16_to_f16";
    const char *op_name = "Metal SAM rel-pos batch attention";

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, kernel_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads_per_group = 0u;
        if (!metal_flash_attention_threads_per_threadgroup(pipeline,
                                                           UOCR_METAL_FLASH_Q_PER_TG,
                                                           UOCR_SAM_HEAD_DIM,
                                                           op_name,
                                                           &threads_per_group,
                                                           error,
                                                           error_size)) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM rel-pos batch attention command encoder");
        }

        const NSUInteger query_blocks = (NSUInteger)(((uint32_t)tokens + UOCR_METAL_FLASH_Q_PER_TG - 1u) / UOCR_METAL_FLASH_Q_PER_TG);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
        [enc setBuffer:rel_pos_h.slice.buffer offset:rel_pos_h.slice.offset atIndex:3u];
        [enc setBuffer:rel_pos_w.slice.buffer offset:rel_pos_w.slice.offset atIndex:4u];
        [enc setBuffer:out.buffer offset:out.offset atIndex:5u];
        [enc setBytes:&params length:sizeof(params) atIndex:6u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, query_blocks, (NSUInteger)logical_windows)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_context_sam_mlp_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                             uocr_metal_vision_workspace_slice input,
                                                             const uocr_metal_sam_transformer_block_slices_f16 *block,
                                                             uint32_t rows,
                                                             uocr_metal_vision_workspace_slice intermediate,
                                                             uocr_metal_vision_workspace_slice out,
                                                             char *error,
                                                             size_t error_size) {
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    uint64_t intermediate_values = 0u;
    uint64_t intermediate_bytes = 0u;
    const uint64_t lin1_weight_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t lin1_bias_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin2_weight_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin2_bias_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const int lin1_is_q8 = block != NULL && block->mlp_lin1_weight.qtype == UOCR_TENSOR_Q8_0;
    const int lin2_is_q8 = block != NULL && block->mlp_lin2_weight.qtype == UOCR_TENSOR_Q8_0;
    if (ctx == NULL || !metal_sam_transformer_block_slices_have_weights(block) || rows == 0u ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_MLP_INTERMEDIATE, &intermediate_values) ||
        intermediate_values > (uint64_t)UINT32_MAX ||
        !metal_vision_f16_bytes(intermediate_values, &intermediate_bytes) ||
        !metal_vision_require_workspace_slice(input, hidden_bytes, "SAM batch MLP input", error, error_size) ||
        !metal_vision_require_workspace_slice(intermediate, intermediate_bytes, "SAM batch MLP intermediate", error, error_size) ||
        !metal_vision_require_workspace_slice(out, hidden_bytes, "SAM batch MLP output", error, error_size) ||
        (!lin1_is_q8 &&
         !metal_vision_require_tensor_slice_f16(block->mlp_lin1_weight, lin1_weight_bytes, "SAM MLP lin1 weight", error, error_size)) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin1_bias, lin1_bias_bytes, "SAM MLP lin1 bias", error, error_size) ||
        (!lin2_is_q8 &&
         !metal_vision_require_tensor_slice_f16(block->mlp_lin2_weight, lin2_weight_bytes, "SAM MLP lin2 weight", error, error_size)) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin2_bias, lin2_bias_bytes, "SAM MLP lin2 bias", error, error_size)) {
        return 0;
    }

    uocr_metal_buffer_slice input_slice = { input.buffer, input.offset };
    uocr_metal_buffer_slice intermediate_slice = { intermediate.buffer, intermediate.offset };
    uocr_metal_buffer_slice out_slice = { out.buffer, out.offset };

    int ok;
    const uint64_t lin1_start_ns = uocr_profile_now_ns();
    if (lin1_is_q8) {
        ok = metal_run_vision_linear_q8_0(ctx,
                                          input_slice,
                                          block->mlp_lin1_weight,
                                          block->mlp_lin1_bias,
                                          rows,
                                          UOCR_SAM_HIDDEN_SIZE,
                                          UOCR_SAM_MLP_INTERMEDIATE,
                                          UOCR_METAL_VISION_Q8_ACT_GELU_ERF,
                                          intermediate_slice,
                                          "Metal SAM batch MLP lin1 Q8",
                                          error,
                                          error_size);
        if (ok) {
            metal_profile_add_event_now(ctx, "metal.vision.sam_mlp_q8.lin1", lin1_start_ns);
        }
    } else {
        ok = metal_run_mps_matmul_nt_f16(ctx,
                                         input_slice,
                                         block->mlp_lin1_weight.slice,
                                         intermediate_slice,
                                         rows,
                                         UOCR_SAM_HIDDEN_SIZE,
                                         UOCR_SAM_MLP_INTERMEDIATE,
                                         "Metal SAM batch MLP lin1 MPS matmul",
                                         error,
                                         error_size) &&
             metal_run_bias_gelu_f16_inplace(ctx,
                                             intermediate_slice,
                                             block->mlp_lin1_bias.slice,
                                             rows,
                                             UOCR_SAM_MLP_INTERMEDIATE,
                                             "Metal SAM batch MLP lin1 bias GELU",
                                             error,
                                             error_size);
    }
    if (ok) {
        const uint64_t lin2_start_ns = uocr_profile_now_ns();
        if (lin2_is_q8) {
            ok = metal_run_vision_linear_q8_0(ctx,
                                              intermediate_slice,
                                              block->mlp_lin2_weight,
                                              block->mlp_lin2_bias,
                                              rows,
                                              UOCR_SAM_MLP_INTERMEDIATE,
                                              UOCR_SAM_HIDDEN_SIZE,
                                              UOCR_METAL_VISION_Q8_ACT_NONE,
                                              out_slice,
                                              "Metal SAM batch MLP lin2 Q8",
                                              error,
                                              error_size);
            if (ok) {
                metal_profile_add_event_now(ctx, "metal.vision.sam_mlp_q8.lin2", lin2_start_ns);
            }
        } else {
            ok = metal_run_mps_matmul_nt_f16(ctx,
                                             intermediate_slice,
                                             block->mlp_lin2_weight.slice,
                                             out_slice,
                                             rows,
                                             UOCR_SAM_MLP_INTERMEDIATE,
                                             UOCR_SAM_HIDDEN_SIZE,
                                             "Metal SAM batch MLP lin2 MPS matmul",
                                             error,
                                             error_size) &&
                 metal_run_bias_add_f16_inplace(ctx,
                                                out_slice,
                                                block->mlp_lin2_bias.slice,
                                                rows,
                                                UOCR_SAM_HIDDEN_SIZE,
                                                "Metal SAM batch MLP lin2 bias add",
                                                error,
                                                error_size);
        }
    }
    if (!ok) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        return metal_fail(error, error_size, "failed to compute Metal SAM batch MLP: %s", detail);
    }
    return 1;
}

static int metal_context_sam_transformer_batch_block_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                           uocr_metal_vision_workspace_slice input_bhwc,
                                                                           const uocr_metal_sam_transformer_block_slices_f16 *block,
                                                                           uint32_t grid_w,
                                                                           uint32_t grid_h,
                                                                           uint32_t view_count,
                                                                           int use_global_attention,
                                                                           uocr_metal_vision_workspace_slice out_bhwc,
                                                                           uocr_metal_vision_workspace *scratch,
                                                                           char *error,
                                                                           size_t error_size) {
    if (ctx == NULL || !metal_sam_transformer_block_slices_have_weights(block) || view_count == 0u || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer block request");
    }
    if (UOCR_SAM_HIDDEN_SIZE != 768u || UOCR_SAM_QKV_SIZE != 2304u || UOCR_SAM_ATTENTION_HEADS != 12u ||
        UOCR_SAM_HEAD_DIM != 64u || UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_WINDOW_SIZE != 14u || UOCR_SAM_WINDOW_TOKENS != 196u || UOCR_SAM_MLP_INTERMEDIATE != 3072u) {
        return metal_fail(error, error_size, "Metal SAM batch transformer block constants are inconsistent");
    }

    uint64_t rows_per_view_u64 = 0u;
    uint64_t hidden_bytes_per_view = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &rows_per_view_u64, &hidden_bytes_per_view, error, error_size)) {
        return 0;
    }
    if (rows_per_view_u64 > (uint64_t)(UINT32_MAX / view_count)) {
        return metal_fail(error, error_size, "Metal SAM batch transformer row-count overflow");
    }
    const uint32_t rows_per_view = (uint32_t)rows_per_view_u64;
    const uint32_t rows = rows_per_view * view_count;

    uint32_t n_windows = 1u;
    uint32_t padded_w = grid_w;
    uint32_t padded_h = grid_h;
    uint64_t attention_rows_per_view_u64 = rows_per_view_u64;
    if (!use_global_attention) {
        uint32_t windows_per_row = 0u;
        uint32_t windows_per_col = 0u;
        if (!sam_window_partition_geometry(grid_w,
                                           grid_h,
                                           &padded_w,
                                           &padded_h,
                                           &windows_per_row,
                                           &windows_per_col,
                                           &n_windows)) {
            return metal_fail(error, error_size, "invalid Metal SAM batch transformer window grid %ux%u", grid_w, grid_h);
        }
        if (!checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &attention_rows_per_view_u64)) {
            return metal_fail(error, error_size, "Metal SAM batch transformer window row-count overflow");
        }
    }
    if (attention_rows_per_view_u64 > (uint64_t)(UINT32_MAX / view_count)) {
        return metal_fail(error, error_size, "Metal SAM batch transformer attention row-count overflow");
    }
    const uint32_t attention_rows = (uint32_t)attention_rows_per_view_u64 * view_count;

    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    uint64_t attention_values = 0u;
    uint64_t attention_bytes = 0u;
    uint64_t mlp_values = 0u;
    uint64_t mlp_bytes = 0u;
    const uint64_t parameter_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t qkv_weight_bytes = (uint64_t)UOCR_SAM_QKV_SIZE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t qkv_bias_bytes = (uint64_t)UOCR_SAM_QKV_SIZE * 2u;
    const uint64_t projection_weight_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t rel_h_bytes = (uint64_t)block->rel_pos_h_length * (uint64_t)UOCR_SAM_HEAD_DIM * 2u;
    const uint64_t rel_w_bytes = (uint64_t)block->rel_pos_w_length * (uint64_t)UOCR_SAM_HEAD_DIM * 2u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        hidden_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !checked_mul_u64((uint64_t)attention_rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        attention_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(attention_values, &attention_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_MLP_INTERMEDIATE, &mlp_values) ||
        mlp_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(mlp_values, &mlp_bytes) ||
        !metal_vision_require_workspace_slice(input_bhwc, hidden_bytes, "SAM batch block input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_bhwc, hidden_bytes, "SAM batch block output", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_norm1_bhwc, hidden_bytes, "SAM batch block norm1", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_window_tokens, attention_bytes, "SAM batch block window tokens", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_q, attention_bytes, "SAM batch block Q", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_k, attention_bytes, "SAM batch block K", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_v, attention_bytes, "SAM batch block V", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_attention, attention_bytes, "SAM batch block attention", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_projected_windows, attention_bytes, "SAM batch block projected windows", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_attention_bhwc, hidden_bytes, "SAM batch block attention BHWC", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_residual1_bhwc, hidden_bytes, "SAM batch block residual1", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_norm2_bhwc, hidden_bytes, "SAM batch block norm2", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_mlp_intermediate, mlp_bytes, "SAM batch block MLP intermediate", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_block_mlp_bhwc, hidden_bytes, "SAM batch block MLP", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm1_weight, parameter_bytes, "SAM block norm1 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm1_bias, parameter_bytes, "SAM block norm1 bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_weight, qkv_weight_bytes, "SAM block QKV weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_bias, qkv_bias_bytes, "SAM block QKV bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->proj_weight, projection_weight_bytes, "SAM block projection weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->proj_bias, parameter_bytes, "SAM block projection bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->rel_pos_h, rel_h_bytes, "SAM block relative position H", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->rel_pos_w, rel_w_bytes, "SAM block relative position W", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm2_weight, parameter_bytes, "SAM block norm2 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm2_bias, parameter_bytes, "SAM block norm2 bias", error, error_size)) {
        return 0;
    }

#define RUN_SAM_BATCH_BLOCK_STEP(step_name, call_expr)                                                \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            return metal_fail(error, error_size, "failed to compute Metal SAM batch block %s: %s", step_name, detail); \
        }                                                                                               \
        if (metal_vision_profile_detail_level() >= 3) {                                                 \
            char checkpoint_name[96];                                                                   \
            (void)snprintf(checkpoint_name, sizeof(checkpoint_name), "sam_batch_block.%s", step_name);  \
            checkpoint_name[sizeof(checkpoint_name) - 1u] = '\0';                                        \
            if (!metal_vision_profile_checkpoint(ctx, checkpoint_name, 1, error, error_size)) {          \
                return 0;                                                                               \
            }                                                                                           \
        }                                                                                               \
    } while (0)

    RUN_SAM_BATCH_BLOCK_STEP("LayerNorm1",
                             metal_context_layernorm_f16_slices_with_parameter_buffers(ctx,
                                                                                        (uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset},
                                                                                        block->norm1_weight.slice.buffer,
                                                                                        block->norm1_weight.slice.offset,
                                                                                        block->norm1_bias.slice.buffer,
                                                                                        block->norm1_bias.slice.offset,
                                                                                        rows,
                                                                                        UOCR_SAM_HIDDEN_SIZE,
                                                                                        1.0e-6f,
                                                                                        UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                        (uocr_metal_buffer_slice){scratch->sam_block_norm1_bhwc.buffer, scratch->sam_block_norm1_bhwc.offset},
                                                                                        "Metal SAM batch LayerNorm1",
                                                                                        error,
                                                                                        error_size));

    if (use_global_attention) {
        RUN_SAM_BATCH_BLOCK_STEP("QKV",
                                 metal_run_packed_qkv_mps_f16(ctx,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_norm1_bhwc.buffer, scratch->sam_block_norm1_bhwc.offset},
                                                               block->qkv_weight.slice,
                                                               block->qkv_bias.slice,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_q.buffer, scratch->sam_block_q.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_k.buffer, scratch->sam_block_k.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_v.buffer, scratch->sam_block_v.offset},
                                                               rows,
                                                               UOCR_SAM_HIDDEN_SIZE,
                                                               "Metal SAM batch global QKV MPS matmul",
                                                               error,
                                                               error_size));
        const uocr_metal_sam_rel_pos_table_pair_f16 rel_pos = metal_sam_rel_pos_table_for_grid(block, grid_w, grid_h);
        RUN_SAM_BATCH_BLOCK_STEP("relative-position attention",
                                 metal_context_sam_rel_pos_attention_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_q,
                                                                                       scratch->sam_block_k,
                                                                                       scratch->sam_block_v,
                                                                                       rel_pos.h,
                                                                                       rel_pos.w,
                                                                                       1u,
                                                                                       grid_w,
                                                                                       grid_h,
                                                                                       view_count,
                                                                                       rel_pos.h_length,
                                                                                       rel_pos.w_length,
                                                                                       scratch->sam_block_attention,
                                                                                       scratch,
                                                                                       error,
                                                                                       error_size));
        RUN_SAM_BATCH_BLOCK_STEP("output projection",
                                 metal_run_mps_matmul_nt_f16(ctx,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention.buffer, scratch->sam_block_attention.offset},
                                                             block->proj_weight.slice,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                             rows,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             "Metal SAM batch global output projection MPS matmul",
                                                             error,
                                                             error_size) &&
                                 metal_run_bias_add_f16_inplace(ctx,
                                                                (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                                block->proj_bias.slice,
                                                                rows,
                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                "Metal SAM batch global output projection bias",
                                                                error,
                                                                error_size));
        RUN_SAM_BATCH_BLOCK_STEP("attention residual",
                                 metal_run_residual_add_f16(ctx,
                                                            (uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                            (uint32_t)hidden_values,
                                                            "Metal SAM batch global attention residual",
                                                            error,
                                                            error_size));
    } else {
        uint32_t actual_windows = 0u;
        uint32_t actual_padded_w = 0u;
        uint32_t actual_padded_h = 0u;
        RUN_SAM_BATCH_BLOCK_STEP("window partition",
                                 metal_context_sam_window_partition_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_norm1_bhwc,
                                                                                       grid_w,
                                                                                       grid_h,
                                                                                       view_count,
                                                                                       scratch->sam_block_window_tokens,
                                                                                       &actual_windows,
                                                                                       &actual_padded_w,
                                                                                       &actual_padded_h,
                                                                                       error,
                                                                                       error_size));
        if (actual_windows != n_windows || actual_padded_w != padded_w || actual_padded_h != padded_h) {
            return metal_fail(error, error_size, "Metal SAM batch window geometry changed during partition");
        }
        RUN_SAM_BATCH_BLOCK_STEP("window QKV",
                                 metal_run_packed_qkv_mps_f16(ctx,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_window_tokens.buffer, scratch->sam_block_window_tokens.offset},
                                                               block->qkv_weight.slice,
                                                               block->qkv_bias.slice,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_q.buffer, scratch->sam_block_q.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_k.buffer, scratch->sam_block_k.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_v.buffer, scratch->sam_block_v.offset},
                                                               attention_rows,
                                                               UOCR_SAM_HIDDEN_SIZE,
                                                               "Metal SAM batch window QKV MPS matmul",
                                                               error,
                                                               error_size));
        const uocr_metal_sam_rel_pos_table_pair_f16 rel_pos = metal_sam_rel_pos_table_for_grid(block,
                                                                                                  UOCR_SAM_WINDOW_SIZE,
                                                                                                  UOCR_SAM_WINDOW_SIZE);
        RUN_SAM_BATCH_BLOCK_STEP("window relative-position attention",
                                 metal_context_sam_rel_pos_attention_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_q,
                                                                                       scratch->sam_block_k,
                                                                                       scratch->sam_block_v,
                                                                                       rel_pos.h,
                                                                                       rel_pos.w,
                                                                                       n_windows,
                                                                                       UOCR_SAM_WINDOW_SIZE,
                                                                                       UOCR_SAM_WINDOW_SIZE,
                                                                                       view_count,
                                                                                       rel_pos.h_length,
                                                                                       rel_pos.w_length,
                                                                                       scratch->sam_block_attention,
                                                                                       scratch,
                                                                                       error,
                                                                                       error_size));
        RUN_SAM_BATCH_BLOCK_STEP("window output projection",
                                 metal_run_mps_matmul_nt_f16(ctx,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention.buffer, scratch->sam_block_attention.offset},
                                                             block->proj_weight.slice,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_projected_windows.buffer, scratch->sam_block_projected_windows.offset},
                                                             attention_rows,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             "Metal SAM batch window output projection MPS matmul",
                                                             error,
                                                             error_size) &&
                                 metal_run_bias_add_f16_inplace(ctx,
                                                                (uocr_metal_buffer_slice){scratch->sam_block_projected_windows.buffer, scratch->sam_block_projected_windows.offset},
                                                                block->proj_bias.slice,
                                                                attention_rows,
                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                "Metal SAM batch window output projection bias",
                                                                error,
                                                                error_size));
        RUN_SAM_BATCH_BLOCK_STEP("window unpartition",
                                 metal_context_sam_window_unpartition_batch_f16_to_slice(ctx,
                                                                                         scratch->sam_block_projected_windows,
                                                                                         grid_w,
                                                                                         grid_h,
                                                                                         view_count,
                                                                                         scratch->sam_block_attention_bhwc,
                                                                                         error,
                                                                                         error_size));
        RUN_SAM_BATCH_BLOCK_STEP("attention residual",
                                 metal_run_residual_add_f16(ctx,
                                                            (uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                            (uint32_t)hidden_values,
                                                            "Metal SAM batch window attention residual",
                                                            error,
                                                            error_size));
    }

    RUN_SAM_BATCH_BLOCK_STEP("LayerNorm2",
                             metal_context_layernorm_f16_slices_with_parameter_buffers(ctx,
                                                                                        (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                                                        block->norm2_weight.slice.buffer,
                                                                                        block->norm2_weight.slice.offset,
                                                                                        block->norm2_bias.slice.buffer,
                                                                                        block->norm2_bias.slice.offset,
                                                                                        rows,
                                                                                        UOCR_SAM_HIDDEN_SIZE,
                                                                                        1.0e-6f,
                                                                                        UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                        (uocr_metal_buffer_slice){scratch->sam_block_norm2_bhwc.buffer, scratch->sam_block_norm2_bhwc.offset},
                                                                                        "Metal SAM batch LayerNorm2",
                                                                                        error,
                                                                                        error_size));
    RUN_SAM_BATCH_BLOCK_STEP("MLP",
                             metal_context_sam_mlp_batch_workspace_f16_to_slice(ctx,
                                                                                scratch->sam_block_norm2_bhwc,
                                                                                block,
                                                                                rows,
                                                                                scratch->sam_block_mlp_intermediate,
                                                                                scratch->sam_block_mlp_bhwc,
                                                                                error,
                                                                                error_size));
    RUN_SAM_BATCH_BLOCK_STEP("MLP residual",
                             metal_run_residual_add_f16(ctx,
                                                        (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                        (uocr_metal_buffer_slice){scratch->sam_block_mlp_bhwc.buffer, scratch->sam_block_mlp_bhwc.offset},
                                                        (uocr_metal_buffer_slice){out_bhwc.buffer, out_bhwc.offset},
                                                        (uint32_t)hidden_values,
                                                        "Metal SAM batch MLP residual",
                                                        error,
                                                        error_size));

#undef RUN_SAM_BATCH_BLOCK_STEP

    return 1;
}

static int metal_context_sam_transformer_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                      uocr_metal_vision_workspace_slice input_bhwc,
                                                                      const uocr_metal_sam_transformer_block_slices_f16 *blocks,
                                                                      uint32_t block_count,
                                                                      uint32_t grid_w,
                                                                      uint32_t grid_h,
                                                                      uint32_t view_count,
                                                                      uocr_metal_vision_workspace_slice out_bhwc,
                                                                      uocr_metal_vision_workspace *scratch,
                                                                      char *error,
                                                                      size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_bhwc.buffer == nil || input_bhwc.bytes == 0u || blocks == NULL || view_count == 0u ||
        out_bhwc.buffer == nil || out_bhwc.bytes == 0u || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer request");
    }
    if (block_count != UOCR_SAM_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer block count %u", block_count);
    }
    uint64_t rows_per_view = 0u;
    uint64_t hidden_bytes_per_view = 0u;
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &rows_per_view, &hidden_bytes_per_view, error, error_size) ||
        rows_per_view > (uint64_t)(UINT32_MAX / view_count) ||
        !checked_mul_u64(rows_per_view, (uint64_t)view_count, &hidden_values) ||
        !checked_mul_u64(hidden_values, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        hidden_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !metal_vision_require_workspace_slice(input_bhwc, hidden_bytes, "SAM batch transformer input", error, error_size) ||
        !metal_vision_require_workspace_slice(out_bhwc, hidden_bytes, "SAM batch transformer output", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_patch_bhwc, hidden_bytes, "SAM batch transformer state A", error, error_size) ||
        !metal_vision_require_workspace_slice(scratch->sam_transformer_batch_bhwc, hidden_bytes, "SAM batch transformer state B", error, error_size)) {
        return 0;
    }
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        if (!metal_sam_transformer_block_slices_have_weights(&blocks[block_index])) {
            return metal_fail(error, error_size, "invalid Metal SAM batch transformer block %u weights", block_index);
        }
    }

    uocr_metal_vision_workspace_slice current = input_bhwc;
    uocr_metal_vision_workspace_slice state_a = scratch->sam_patch_bhwc;
    uocr_metal_vision_workspace_slice state_b = scratch->sam_transformer_batch_bhwc;
    uocr_metal_vision_workspace_slice next = state_a;
    const uint64_t sam_blocks_start_ns = uocr_profile_now_ns();
    const int vision_profile_detail = metal_vision_profile_detail_level();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        uocr_metal_vision_workspace_slice block_out = is_last ? out_bhwc : next;
        if (block_out.buffer == current.buffer && block_out.offset == current.offset) {
            return metal_fail(error, error_size, "Metal SAM batch transformer attempted in-place block output");
        }
        if (!metal_context_sam_transformer_batch_block_workspace_f16_to_slice(ctx,
                                                                              current,
                                                                              &blocks[block_index],
                                                                              grid_w,
                                                                              grid_h,
                                                                              view_count,
                                                                              uocr_sam_block_uses_global_attention(block_index),
                                                                              block_out,
                                                                              scratch,
                                                                              error,
                                                                              error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            return metal_fail(error,
                              error_size,
                              "failed to compute Metal SAM batch transformer block %u: %s",
                              block_index,
                              detail);
        }
        if (!is_last) {
            current = block_out;
            next = (block_out.buffer == state_a.buffer && block_out.offset == state_a.offset) ? state_b : state_a;
        }
        metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.sam_block_batch" : "metal.vision.sam_block", block_start_ns);
        metal_profile_add_event_now_f(ctx,
                                      block_start_ns,
                                      view_count > 1u ? "metal.vision.sam_block_batch.%02u" : "metal.vision.sam_block.%02u",
                                      block_index);
        if (vision_profile_detail == 2) {
            char checkpoint_name[64];
            (void)snprintf(checkpoint_name,
                           sizeof(checkpoint_name),
                           view_count > 1u ? "sam_block_batch.%02u" : "sam_block.%02u",
                           block_index);
            checkpoint_name[sizeof(checkpoint_name) - 1u] = '\0';
            if (!metal_vision_profile_checkpoint(ctx, checkpoint_name, 1, error, error_size)) {
                return 0;
            }
        }
    }
    metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.sam_blocks_batch" : "metal.vision.sam_blocks", sam_blocks_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}
int uocr_metal_context_final_rmsnorm_f16(uocr_metal_context *ctx,
                                         const uint16_t *input_f16,
                                         uint32_t n_rows,
                                         uocr_metal_rmsnorm_output_type output_type,
                                         void *out,
                                         char *error,
                                         size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_f16 == NULL || out == NULL || n_rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal final RMSNorm request");
    }

    id<MTLBuffer> weight = nil;
    NSUInteger weight_offset = 0u;
    const uint64_t expected_payload_size = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_get_mapped_tensor_buffer(ctx,
                                        UOCR_TENSOR_ID_FINAL_NORM,
                                        expected_payload_size,
                                        &weight,
                                        &weight_offset,
                                        error,
                                        error_size)) {
        return 0;
    }

    return metal_context_rmsnorm_f16_with_weight_buffer(ctx,
                                                        input_f16,
                                                        weight,
                                                        weight_offset,
                                                        n_rows,
                                                        UOCR_HIDDEN_SIZE,
                                                        UOCR_RMS_NORM_EPS,
                                                        output_type,
                                                        out,
                                                        "Metal final RMSNorm",
                                                        error,
                                                        error_size);
}

int uocr_metal_context_lm_head_f16(uocr_metal_context *ctx,
                                   const uint16_t *input_f16,
                                   uint32_t n_rows,
                                   float *logits_out_f32,
                                   char *error,
                                   size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_f16 == NULL || logits_out_f32 == NULL || n_rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal LM-head request");
    }

    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t weight_values = 0u;
    uint64_t weight_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_HIDDEN_SIZE, &input_values) ||
        !checked_mul_u64(input_values, 2u, &input_bytes) ||
        !checked_mul_u64((uint64_t)UOCR_VOCAB_SIZE, (uint64_t)UOCR_HIDDEN_SIZE, &weight_values) ||
        !checked_mul_u64(weight_values, 2u, &weight_bytes) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_VOCAB_SIZE, &output_values) ||
        !checked_mul_u64(output_values, (uint64_t)sizeof(float), &output_bytes)) {
        return metal_fail(error, error_size, "Metal LM-head byte-size overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (input_bytes > max_buffer_length || output_bytes > max_buffer_length ||
        input_bytes > (uint64_t)SIZE_MAX || output_bytes > (uint64_t)SIZE_MAX ||
        output_values > (uint64_t)UINT32_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal LM-head buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    id<MTLBuffer> lm_head_weight = nil;
    NSUInteger lm_head_offset = 0u;
    if (!metal_get_mapped_tensor_buffer(ctx,
                                        UOCR_TENSOR_ID_LM_HEAD,
                                        weight_bytes,
                                        &lm_head_weight,
                                        &lm_head_offset,
                                        error,
                                        error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLBuffer> src = metal_new_buffer_with_bytes(ctx, input_f16, (NSUInteger)input_bytes, MTLResourceStorageModeShared);
        if (src == nil) {
            return metal_fail(error, error_size, "failed to allocate Metal LM-head input buffer");
        }
        src.label = @"uocr_lm_head_input_f16";

        id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, (NSUInteger)output_bytes, MTLResourceStorageModeShared);
        if (dst == nil) {
            [src release];
            return metal_fail(error, error_size, "failed to allocate Metal LM-head logits buffer");
        }
        dst.label = @"uocr_lm_head_logits_f32";

        {
            uocr_metal_buffer_slice src_slice = { src, 0u };
            uocr_metal_buffer_slice weight_slice = { lm_head_weight, lm_head_offset };
            uocr_metal_buffer_slice dst_slice = { dst, 0u };
            const uint64_t lm_mps_start_ns = uocr_profile_now_ns();
            if (!metal_run_mps_matmul_nt_f16_to_f32(ctx,
                                                    src_slice,
                                                    weight_slice,
                                                    dst_slice,
                                                    n_rows,
                                                    UOCR_HIDDEN_SIZE,
                                                    UOCR_VOCAB_SIZE,
                                                    "Metal LM-head MPS matmul",
                                                    error,
                                                    error_size)) {
                [dst release];
                [src release];
                return 0;
            }
            metal_profile_add_event_now(ctx, "metal.lm_head.mps_matmul", lm_mps_start_ns);
        }

        memcpy(logits_out_f32, [dst contents], (size_t)output_bytes);
        [dst release];
        [src release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_argmax_f32(uocr_metal_context *ctx,
                                  const float *logits_f32,
                                  uint32_t n_rows,
                                  uint32_t vocab_size,
                                  uint32_t *token_ids_out,
                                  float *scores_out_f32_or_null,
                                  char *error,
                                  size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || logits_f32 == NULL || token_ids_out == NULL || n_rows == 0u || vocab_size == 0u) {
        return metal_fail(error, error_size, "invalid Metal argmax request");
    }

    uint64_t logits_values = 0u;
    uint64_t logits_bytes = 0u;
    uint64_t ids_bytes = 0u;
    uint64_t scores_bytes = 0u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)vocab_size, &logits_values) ||
        !checked_mul_u64(logits_values, (uint64_t)sizeof(float), &logits_bytes) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)sizeof(uint32_t), &ids_bytes) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)sizeof(float), &scores_bytes)) {
        return metal_fail(error, error_size, "Metal argmax byte-size overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (logits_bytes > max_buffer_length || ids_bytes > max_buffer_length || scores_bytes > max_buffer_length ||
        logits_bytes > (uint64_t)SIZE_MAX || ids_bytes > (uint64_t)SIZE_MAX || scores_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal argmax buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_argmax_f32", error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> logits = metal_new_buffer_with_bytes(ctx, logits_f32, (NSUInteger)logits_bytes, MTLResourceStorageModeShared);
        if (logits == nil) {
            return metal_fail(error, error_size, "failed to allocate Metal argmax logits buffer");
        }
        logits.label = @"uocr_argmax_logits_f32";

        id<MTLBuffer> ids = metal_new_buffer_with_length(ctx, (NSUInteger)ids_bytes, MTLResourceStorageModeShared);
        id<MTLBuffer> scores = metal_new_buffer_with_length(ctx, (NSUInteger)scores_bytes, MTLResourceStorageModeShared);
        if (ids == nil || scores == nil) {
            [scores release];
            [ids release];
            [logits release];
            return metal_fail(error, error_size, "failed to allocate Metal argmax output buffers");
        }
        ids.label = @"uocr_argmax_token_ids";
        scores.label = @"uocr_argmax_scores";
        memset([ids contents], 0xff, (size_t)ids_bytes);
        memset([scores contents], 0, (size_t)scores_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [scores release];
            [ids release];
            [logits release];
            return metal_fail(error, error_size, "failed to create Metal argmax command buffer");
        }
        cb.label = @"uocr_argmax_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [scores release];
            [ids release];
            [logits release];
            return metal_fail(error, error_size, "failed to create Metal argmax command encoder");
        }

        uocr_metal_argmax_params params;
        params.rows = n_rows;
        params.vocab_size = vocab_size;
        params.reserved0 = 0u;
        params.reserved1 = 0u;

        const NSUInteger threads_per_group = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        const uint64_t threadgroup_bytes = (uint64_t)threads_per_group * (uint64_t)sizeof(float);
        uint64_t total_threadgroup_bytes = 0u;
        if (!checked_mul_u64(threadgroup_bytes, 2u, &total_threadgroup_bytes) ||
            total_threadgroup_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            [scores release];
            [ids release];
            [logits release];
            return metal_fail(error, error_size, "Metal argmax threadgroup memory exceeds device limit");
        }

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:logits offset:0u atIndex:0u];
        [enc setBuffer:ids offset:0u atIndex:1u];
        [enc setBuffer:scores offset:0u atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc setThreadgroupMemoryLength:threads_per_group * sizeof(float) atIndex:0u];
        [enc setThreadgroupMemoryLength:threads_per_group * sizeof(uint32_t) atIndex:1u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_rows, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            [scores release];
            [ids release];
            [logits release];
            return metal_fail(error, error_size, "Metal argmax command failed: %s", [description UTF8String]);
        }

        memcpy(token_ids_out, [ids contents], (size_t)ids_bytes);
        if (scores_out_f32_or_null != NULL) {
            memcpy(scores_out_f32_or_null, [scores contents], (size_t)scores_bytes);
        }
        [scores release];
        [ids release];
        [logits release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_select_greedy_f32(uocr_metal_context *ctx,
                                         float *logits_f32,
                                         uint32_t n_rows,
                                         uint32_t vocab_size,
                                         uint32_t *token_ids_out,
                                         float *scores_out_f32_or_null,
                                         char *error,
                                         size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || logits_f32 == NULL || token_ids_out == NULL || n_rows == 0u || vocab_size == 0u) {
        return metal_fail(error, error_size, "invalid Metal greedy selection request");
    }

    return uocr_metal_context_argmax_f32(ctx,
                                         logits_f32,
                                         n_rows,
                                         vocab_size,
                                         token_ids_out,
                                         scores_out_f32_or_null,
                                         error,
                                         error_size);
}

int uocr_metal_context_select_next_token_f16(uocr_metal_context *ctx,
                                             const uint16_t *hidden_f16,
                                             uint32_t n_rows,
                                             uint16_t *normed_scratch_f16,
                                             float *logits_scratch_f32,
                                             uint32_t *token_ids_out,
                                             float *scores_out_f32_or_null,
                                             char *error,
                                             size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || hidden_f16 == NULL || normed_scratch_f16 == NULL || logits_scratch_f32 == NULL ||
        token_ids_out == NULL || n_rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal next-token selection request");
    }

    uint64_t hidden_values = 0u;
    uint64_t logits_values = 0u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_HIDDEN_SIZE, &hidden_values) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_VOCAB_SIZE, &logits_values) ||
        hidden_values > (uint64_t)SIZE_MAX / sizeof(uint16_t) ||
        logits_values > (uint64_t)SIZE_MAX / sizeof(float)) {
        return metal_fail(error, error_size, "Metal next-token selection scratch byte-size overflow");
    }

    if (!uocr_metal_context_final_rmsnorm_f16(ctx,
                                             hidden_f16,
                                             n_rows,
                                             UOCR_METAL_RMSNORM_OUTPUT_F16,
                                             normed_scratch_f16,
                                             error,
                                             error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        return metal_fail(error, error_size, "failed to apply final RMSNorm before next-token selection: %s", detail);
    }

    if (!uocr_metal_context_lm_head_f16(ctx,
                                        normed_scratch_f16,
                                        n_rows,
                                        logits_scratch_f32,
                                        error,
                                        error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        return metal_fail(error, error_size, "failed to compute LM-head logits before next-token selection: %s", detail);
    }

    if (!uocr_metal_context_select_greedy_f32(ctx,
                                             logits_scratch_f32,
                                             n_rows,
                                             UOCR_VOCAB_SIZE,
                                             token_ids_out,
                                             scores_out_f32_or_null,
                                             error,
                                             error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        return metal_fail(error, error_size, "failed to greedily select next token: %s", detail);
    }

    metal_clear_error(error, error_size);
    return 1;
}
void uocr_metal_context_set_profile(uocr_metal_context *ctx, uocr_profile_state *profile) {
    if (ctx != NULL) {
        ctx->profile = profile;
    }
}

void uocr_metal_context_set_memory_tracker(uocr_metal_context *ctx, uocr_memory_tracker *memory_tracker) {
    if (ctx != NULL) {
        ctx->memory_tracker = memory_tracker;
    }
}

void uocr_metal_context_destroy(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    metal_command_batch_abort(ctx);
    uocr_metal_context_unmap_model(ctx);
    uocr_metal_context_release_runtime_arenas(ctx);
    release_all_scratch(ctx);
    @autoreleasepool {
        [ctx->transient_retains release];
        [ctx->mps_matmul_kernel release];
        [ctx->mps_workspace_ndarray_cache release];
        [ctx->mps_weight_ndarray_cache release];
        [ctx->mps_descriptor_cache release];
        [ctx->pipeline_cache release];
        [ctx->library release];
        [ctx->queue release];
        [ctx->device release];
        free(ctx);
    }
}

static int run_scratch_smoke(uocr_metal_context *ctx, char *error, size_t error_size) {
    if (!uocr_metal_context_ensure_scratch(ctx, UOCR_METAL_SCRATCH_TRANSIENT, 4096u, 1, error, error_size)) {
        return 0;
    }
    if (uocr_metal_context_scratch_capacity(ctx, UOCR_METAL_SCRATCH_TRANSIENT) < 4096u) {
        return metal_fail(error, error_size, "Metal scratch buffer capacity did not satisfy request");
    }
    return 1;
}

static size_t round_up_size(size_t value, size_t align) {
    if (align == 0u) {
        return value;
    }
    const size_t remainder = value % align;
    return remainder == 0u ? value : value + (align - remainder);
}

static int run_no_copy_kernel_smoke(uocr_metal_context *ctx, char *error, size_t error_size) {
    enum { N = 16 };
    const size_t bytes = (size_t)N * sizeof(uint32_t);
    long page_size_long = sysconf(_SC_PAGESIZE);
    if (page_size_long <= 0) {
        page_size_long = 4096;
    }
    const size_t page_size = (size_t)page_size_long;
    const size_t map_size = round_up_size(bytes, page_size);

    char path[] = "/tmp/uocr-metal-smoke-XXXXXX";
    int fd = mkstemp(path);
    if (fd < 0) {
        return metal_fail(error, error_size, "mkstemp failed: %s", strerror(errno));
    }
    (void)unlink(path);
    if (ftruncate(fd, (off_t)map_size) != 0) {
        int saved_errno = errno;
        (void)close(fd);
        return metal_fail(error, error_size, "ftruncate failed: %s", strerror(saved_errno));
    }

    void *mapping = mmap(NULL, map_size, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    if (mapping == MAP_FAILED) {
        int saved_errno = errno;
        (void)close(fd);
        return metal_fail(error, error_size, "mmap failed: %s", strerror(saved_errno));
    }

    uint32_t *src_words = (uint32_t *)mapping;
    for (uint32_t i = 0u; i < (uint32_t)N; ++i) {
        src_words[i] = 0x1000u + i;
    }

    id<MTLBuffer> src = metal_new_buffer_with_bytes_no_copy(ctx, mapping, map_size, MTLResourceStorageModeShared, nil);
    if (src == nil) {
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "newBufferWithBytesNoCopy failed for mmap range");
    }
    src.label = @"uocr_mmap_no_copy_smoke_src";

    id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, bytes, MTLResourceStorageModeShared);
    if (dst == nil) {
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "failed to allocate Metal readback buffer");
    }
    dst.label = @"uocr_smoke_dst";
    memset([dst contents], 0, bytes);

    id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_smoke_u32", error, error_size);
    if (pipeline == nil) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return 0;
    }

    id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
    if (cb == nil) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "failed to create Metal command buffer");
    }
    cb.label = @"uocr_smoke_command_buffer";

    id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
    if (enc == nil) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "failed to create Metal command encoder");
    }
    [enc setComputePipelineState:pipeline];
    [enc setBuffer:src offset:0u atIndex:0u];
    [enc setBuffer:dst offset:0u atIndex:1u];
    uint32_t n = (uint32_t)N;
    [enc setBytes:&n length:sizeof(n) atIndex:2u];

    NSUInteger threads_per_group = pipeline.threadExecutionWidth;
    if (threads_per_group == 0u) {
        threads_per_group = 1u;
    }
    if (threads_per_group > (NSUInteger)N) {
        threads_per_group = (NSUInteger)N;
    }
    [enc dispatchThreads:MTLSizeMake((NSUInteger)N, 1u, 1u)
   threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
    [enc endEncoding];

    const uint32_t transient_count_before = metal_inflight_transient_count(ctx);
    if (!metal_retain_transient_until_completed(ctx, cb, src, error, error_size)) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return 0;
    }
    if (metal_inflight_transient_count(ctx) != transient_count_before + 1u) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "Metal transient retain tracking count did not increase");
    }

    UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
    if (cb.status == MTLCommandBufferStatusError) {
        NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "Metal smoke command failed: %s", [description UTF8String]);
    }
    if (metal_inflight_transient_count(ctx) != transient_count_before) {
        [dst release];
        [src release];
        (void)munmap(mapping, map_size);
        (void)close(fd);
        return metal_fail(error, error_size, "Metal transient retain tracking count did not drain after command completion");
    }

    const uint32_t *dst_words = (const uint32_t *)[dst contents];
    int ok = 1;
    for (uint32_t i = 0u; i < (uint32_t)N; ++i) {
        const uint32_t expected = (0x1000u + i) ^ 0xa5a5a5a5u;
        if (dst_words[i] != expected) {
            ok = 0;
            (void)metal_fail(error,
                             error_size,
                             "Metal smoke mismatch at %u: got 0x%08x expected 0x%08x",
                             i,
                             dst_words[i],
                             expected);
            break;
        }
    }

    [dst release];
    [src release];
    (void)munmap(mapping, map_size);
    (void)close(fd);
    return ok;
}

int uocr_metal_smoke_test(const char *resource_path, char *error, size_t error_size) {
    metal_clear_error(error, error_size);
    @autoreleasepool {
        uocr_metal_context *ctx = uocr_metal_context_create(resource_path, error, error_size);
        if (ctx == NULL) {
            return 0;
        }

        int ok = run_scratch_smoke(ctx, error, error_size);
        if (ok) {
            ok = run_no_copy_kernel_smoke(ctx, error, error_size);
        }
        uocr_metal_context_destroy(ctx);
        if (ok) {
            metal_clear_error(error, error_size);
        }
        return ok;
    }
}
